import test from "node:test";
import assert from "node:assert/strict";
import { mkdtemp, rm } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { existsSync } from "node:fs";
import { runTask } from "../src/run.js";
import { EventLog } from "../src/events/event-log.js";

// Integration tests that call a real model API — skip when API credits are unavailable
const skipReason = { skip: "integration test: requires model API credits" };

test("runTask creates session and returns result", skipReason, async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-loop-"));
  try {
    const result = await runTask(dir, "say hello");
    assert.ok(result.sessionId);
    assert.ok(existsSync(join(dir, ".alix", "sessions", result.sessionId, "events.jsonl")));

    const log = new EventLog(join(dir, ".alix", "sessions", result.sessionId));
    await log.init();
    const events = await log.readAll();
    assert.ok(events.some((e) => e.type === "session.started"), "should have session.started");
    assert.ok(events.some((e) => e.type === "session.ended"), "should have session.ended");
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("runTask loops on tool calls", skipReason, async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-loop-tool-"));
  try {
    const result = await runTask(dir, "run the tests");
    assert.ok(result.sessionId);

    const log = new EventLog(join(dir, ".alix", "sessions", result.sessionId));
    await log.init();
    const events = await log.readAll();

    const userMsg = events.filter((e) => e.type === "user.message");
    assert.ok(userMsg.length >= 1, "should have user message");

    const agentMsgs = events.filter((e) => e.type === "agent.message");
    assert.ok(agentMsgs.length >= 1, "should have agent messages");

    const toolRequested = events.filter((e) => e.type === "tool.requested");
    const toolCompleted = events.filter((e) => e.type === "tool.completed" || e.type === "tool.failed");
    assert.ok(toolRequested.length > 0 || agentMsgs.length > 0, "should have agent activity");
    assert.ok(toolCompleted.length > 0 || toolRequested.length === 0, "if tools called, results logged");
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("runTask respects max iterations", skipReason, async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-loop-max-"));
  try {
    const result = await runTask(dir, "run the tests");
    const log = new EventLog(join(dir, ".alix", "sessions", result.sessionId));
    await log.init();
    const events = await log.readAll();

    const toolRequested = events.filter((e) => e.type === "tool.requested");
    assert.ok(toolRequested.length <= 10, "should not exceed max iterations");
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

import test from "node:test";
import assert from "node:assert/strict";
import { AnthropicProvider } from "../src/providers/anthropic-provider.js";

test("anthropic provider returns correct capabilities", () => {
  const provider = new AnthropicProvider({ apiKey: "test-key" });
  assert.equal(provider.id, "anthropic");
  assert.equal(provider.capabilities.provider, "anthropic");
  assert.equal(provider.capabilities.model, "claude-sonnet-4-6");
  assert.equal(provider.capabilities.supportsTools, true);
  assert.equal(provider.capabilities.supportsVision, true);
  assert.equal(provider.editFormatPreference, "search_replace");
  assert.equal(provider.longContextStrategy, "trimmed_context");
});

test("anthropic provider requires API key", async () => {
  const provider = new AnthropicProvider({ apiKey: "" });
  await assert.rejects(() => provider.complete({ systemPrompt: "", messages: [] }), /ANTHROPIC_API_KEY/);
});

test("anthropic provider accepts config overrides", () => {
  const provider = new AnthropicProvider({ apiKey: "my-key", model: "claude-3-5-sonnet", maxTokens: 2048 });
  assert.equal(provider.capabilities.model, "claude-3-5-sonnet");
  assert.equal(provider.capabilities.outputTokenLimit, 8192); // default, aligns with maxTokens default
});

import { describe, it } from "node:test";
import assert from "node:assert";
import { classifyTask } from "../src/task-classifier.js";

describe("autonomous loop exit conditions", () => {
  it("bugfix: uses classifyTask for task type", () => {
    const taskType = classifyTask("fix the null pointer exception");
    assert.strictEqual(taskType, "bugfix");
  });

  it("feature: uses classifyTask for task type", () => {
    const taskType = classifyTask("add OAuth login to the app");
    assert.strictEqual(taskType, "feature");
  });

  it("refactor: uses classifyTask for task type", () => {
    const taskType = classifyTask("extract the payment logic into a service");
    assert.strictEqual(taskType, "refactor");
  });

  it("unknown task defaults to checking tests", () => {
    const taskType = classifyTask("do something with the codebase");
    assert.strictEqual(taskType, "unknown");
  });

  it("docs task skips verification", () => {
    const taskType = classifyTask("update the README with new steps");
    assert.strictEqual(taskType, "docs");
  });
});

import test from "node:test";
import assert from "node:assert/strict";
import { buildErrorMessage } from "../src/run.js";

// --- Error results ---

test("buildErrorMessage includes Error prefix", () => {
  const msg = buildErrorMessage({ kind: "error", message: "something failed" });
  assert.ok(msg.includes("Error: something failed"));
});

test("buildErrorMessage includes Hint when hint is present", () => {
  const msg = buildErrorMessage({ kind: "error", message: "bad path", hint: "Check the path is inside the project" });
  assert.ok(msg.includes("Hint: Check the path is inside the project"));
});

test("buildErrorMessage does not include Hint when hint is absent", () => {
  const msg = buildErrorMessage({ kind: "error", message: "oops" });
  assert.ok(!msg.includes("Hint:"));
});

test("buildErrorMessage signals fatal for retryable: false", () => {
  const msg = buildErrorMessage({ kind: "error", message: "invalid api key", retryable: false });
  assert.ok(msg.includes("do not retry"));
  assert.ok(!msg.includes("may be transient"));
});

test("buildErrorMessage signals transient hint for retryable: true", () => {
  const msg = buildErrorMessage({ kind: "error", message: "timeout", retryable: true });
  assert.ok(msg.includes("may be transient"));
  assert.ok(!msg.includes("do not retry"));
});

test("buildErrorMessage omits retry signal when retryable is undefined", () => {
  const msg = buildErrorMessage({ kind: "error", message: "oops" });
  assert.ok(!msg.includes("do not retry"));
  assert.ok(!msg.includes("may be transient"));
});

test("buildErrorMessage formats full fatal error correctly", () => {
  const msg = buildErrorMessage({
    kind: "error",
    message: "invalid api key",
    hint: "Check ANTHROPIC_API_KEY is set",
    retryable: false
  });
  assert.ok(msg.startsWith("Error: invalid api key"));
  assert.ok(msg.includes("Hint: Check ANTHROPIC_API_KEY is set"));
  assert.ok(msg.includes("do not retry"));
});

test("buildErrorMessage formats full retryable error correctly", () => {
  const msg = buildErrorMessage({
    kind: "error",
    message: "connection refused",
    hint: "Check the server is running",
    retryable: true
  });
  assert.ok(msg.startsWith("Error: connection refused"));
  assert.ok(msg.includes("Hint: Check the server is running"));
  assert.ok(msg.includes("may be transient"));
});

import test from "node:test";
import assert from "node:assert/strict";
import { fileURLToPath } from "node:url";
import { McpManager } from "../src/mcp/manager.js";
import { loadConfig } from "../src/config/loader.js";

const __dirname = fileURLToPath(new URL(".", import.meta.url));

test("discoverServer returns correct info for mcp-server-fetch", { timeout: 120_000 }, async () => {
  const config = await loadConfig(__dirname);
  const mcpManager = new McpManager(config);
  await mcpManager.initialize();

  try {
    const info = await mcpManager.discoverServer("mcp-server-fetch");

    // Should return a valid info object
    assert.ok(typeof info.name === "string", "name should be a string");
    assert.ok(typeof info.version === "string", "version should be a string");
    assert.ok(typeof info.toolCount === "number", "toolCount should be a number");
    assert.ok(Array.isArray(info.toolNames), "toolNames should be an array");

    // Tool count should match the array length
    assert.equal(info.toolCount, info.toolNames.length, "toolCount should equal toolNames.length");

    // Should have discovered at least one tool
    assert.ok(info.toolCount > 0, "should discover at least one tool");

    // Tool names should be non-empty strings
    for (const t of info.toolNames) {
      assert.ok(typeof t === "string" && t.length > 0, `tool name should be a non-empty string, got: ${JSON.stringify(t)}`);
    }
  } finally {
    await mcpManager.closeAll().catch(() => {});
  }
});

test("discoverServer throws for unknown package", { timeout: 60_000 }, async () => {
  const config = await loadConfig(__dirname);
  const mcpManager = new McpManager(config);
  await mcpManager.initialize();

  try {
    await assert.rejects(
      mcpManager.discoverServer("this-package-definitely-does-not-exist-12345"),
      (err: Error) => {
        assert.ok(err.message.includes("Could not connect") || err.message.includes("not found"));
        return true;
      }
    );
  } finally {
    await mcpManager.closeAll().catch(() => {});
  }
});

import test from "node:test";
import assert from "node:assert/strict";
import { mkdtemp, mkdir, writeFile, rm } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { loadConfig, _setHomedirOverride, mergeConfig } from "../src/config/loader.js";
import { DEFAULT_CONFIG } from "../src/config/defaults.js";
import type { AlixConfig, McpServerConfig } from "../src/config/schema.js";

function withMockedHomedir(dir: string): () => void {
  _setHomedirOverride(dir);
  return () => _setHomedirOverride(undefined);
}

// --- Config merge order tests ---

test("loadConfig applies defaults when no config files exist", async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-config-"));
  try {
    _setHomedirOverride(dir);
    const config = await loadConfig(dir);
    assert.equal(config.model.provider, "ollama");
    assert.equal(config.ui.port, 4137);
    assert.ok(config.permissions.protectedPaths.includes(".git/**"));
  } finally {
    _setHomedirOverride(undefined);
    await rm(dir, { recursive: true, force: true });
  }
});

test("loadConfig merges global user config on top of defaults", async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-config-"));
  const restore = withMockedHomedir(dir);
  try {
    await mkdir(join(dir, ".alix"), { recursive: true });
    await writeFile(
      join(dir, ".alix", "config.json"),
      JSON.stringify({ model: { name: "claude-custom" } })
    );
    const config = await loadConfig(dir);
    assert.equal(config.model.name, "claude-custom");
    assert.equal(config.model.provider, "ollama"); // inherited from defaults
    assert.equal(config.ui.port, 4137); // inherited from defaults
  } finally {
    restore();
    await rm(dir, { recursive: true, force: true });
  }
});

test("loadConfig applies user config overrides on top of defaults", async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-config-"));
  const restore = withMockedHomedir(dir);
  try {
    // .alix/config.json (used as both global and project config) overrides defaults
    await mkdir(join(dir, ".alix"), { recursive: true });
    await writeFile(
      join(dir, ".alix", "config.json"),
      JSON.stringify({ model: { provider: "openai", name: "gpt-4o" }, ui: { port: 5000 } })
    );
    const config = await loadConfig(dir);
    assert.equal(config.model.provider, "openai");
    assert.equal(config.model.name, "gpt-4o");
    assert.equal(config.ui.port, 5000);
    assert.ok(config.permissions.protectedPaths.includes(".git/**")); // defaults preserved
  } finally {
    restore();
    await rm(dir, { recursive: true, force: true });
  }
});

test("loadConfig merges XDG config then global config then project config", async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-config-"));
  const restore = withMockedHomedir(dir);
  try {
    // XDG: sets model name
    await mkdir(join(dir, ".config", "alix"), { recursive: true });
    await writeFile(
      join(dir, ".config", "alix", "config.json"),
      JSON.stringify({ model: { name: "xdg-model" } })
    );
    // Global: sets provider
    await mkdir(join(dir, ".alix"), { recursive: true });
    await writeFile(
      join(dir, ".alix", "config.json"),
      JSON.stringify({ model: { provider: "openai" } })
    );
    // Project: overrides provider
    await writeFile(
      join(dir, ".alix", "config.json"),
      JSON.stringify({ model: { provider: "google" } })
    );
    const config = await loadConfig(dir);
    assert.equal(config.model.name, "xdg-model");   // XDG preserved
    assert.equal(config.model.provider, "google");   // project overrides
    assert.equal(config.ui.port, 4137);             // defaults preserved
  } finally {
    restore();
    await rm(dir, { recursive: true, force: true });
  }
});

// --- normalizeMcpServers tests ---

test("normalizeMcpServers converts Record map to array format", () => {
  const servers: Record<string, McpServerConfig> = {
    github: { type: "stdio", name: "github", command: "npx", args: ["-y", "@modelcontextprotocol/server-github"] }
  };
  const result = mergeConfig(DEFAULT_CONFIG, { mcpServers: servers as unknown as McpServerConfig[] });
  assert.equal(Array.isArray(result.mcpServers), true);
  assert.equal(result.mcpServers!.length, 1);
  assert.equal(result.mcpServers![0].name, "github");
  assert.equal(result.mcpServers![0].type, "stdio");
});

test("normalizeMcpServers keeps array format as-is", () => {
  const servers: McpServerConfig[] = [
    { name: "fetch", type: "stdio", command: "node", args: ["server.js"] }
  ];
  const result = mergeConfig(DEFAULT_CONFIG, { mcpServers: servers });
  assert.equal(result.mcpServers!.length, 1);
  assert.equal(result.mcpServers![0].name, "fetch");
});

test("normalizeMcpServers returns existing defaults when mcpServers is not overridden", () => {
  // DEFAULT_CONFIG.mcpServers has the "fetch" server; passing undefined preserves it
  const result = mergeConfig(DEFAULT_CONFIG, {});
  assert.equal(Array.isArray(result.mcpServers), true);
  assert.ok(result.mcpServers!.length >= 1, "should have default mcpServers");
  assert.equal(result.mcpServers![0].name, "fetch");
});

// --- API key injection tests ---

test("loadConfig injects API key from XDG user config as env var", async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-config-"));
  const restore = withMockedHomedir(dir);
  try {
    await mkdir(join(dir, ".config", "alix"), { recursive: true });
    await writeFile(
      join(dir, ".config", "alix", "config.json"),
      JSON.stringify({ apiKeys: { openai: "xdg-key-123" } })
    );
    delete process.env.OPENAI_API_KEY;
    await loadConfig(dir);
    assert.equal(process.env.OPENAI_API_KEY, "xdg-key-123");
  } finally {
    restore();
    delete process.env.OPENAI_API_KEY;
    await rm(dir, { recursive: true, force: true });
  }
});

