import test from "node:test";
import assert from "node:assert/strict";
import { mkdtemp, writeFile, mkdir, rm } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { readFile, searchDir } from "../src/tools/file-tools.js";

test("readFile returns content", async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-file-"));
  try {
    await mkdir(join(dir, "src"));
    await writeFile(join(dir, "src/a.ts"), "export const x = 1;\n");
    const result = await readFile({ root: dir, path: "src/a.ts" });
    assert.equal(result.kind, "success");
    assert.equal(result.content, "export const x = 1;\n");
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("readFile returns error for missing file", async () => {
  const result = await readFile({ root: "/tmp", path: "nonexistent-file-xyz.ts" });
  assert.equal(result.kind, "error");
  assert.ok(result.message?.includes("not found"));
});

test("readFile rejects paths outside workspace", async () => {
  const result = await readFile({ root: "/tmp/alix", path: "../etc/passwd" });
  assert.equal(result.kind, "error");
});

test("searchDir skips ignored directories", async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-ignore-"));
  try {
    // Create files in both ignored and non-ignored dirs
    await mkdir(join(dir, "src"));
    await mkdir(join(dir, "node_modules"));
    await mkdir(join(dir, ".git"));
    await writeFile(join(dir, "src/visible.ts"), "TARGET_LINE\n");
    await writeFile(join(dir, "node_modules/hidden.ts"), "TARGET_LINE\n");
    await writeFile(join(dir, ".git/hidden.ts"), "TARGET_LINE\n");
    const result = await searchDir({ root: dir, pattern: "TARGET_LINE", extensions: [".ts"] });
    assert.equal(result.kind, "success");
    assert.equal(result.matches?.length, 1);
    assert.ok(result.matches?.[0].path.includes("src/visible.ts"));
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("searchDir returns matching files", async () => {
  const dir = await mkdtemp(join(tmpdir(), "alix-search-"));
  try {
    await mkdir(join(dir, "src"));
    await writeFile(join(dir, "src/a.ts"), "function hello() {}\n");
    await writeFile(join(dir, "src/b.ts"), "const x = 1;\n");
    await writeFile(join(dir, "src/c.js"), "function hello() {}\n");
    const result = await searchDir({ root: dir, pattern: "hello", extensions: [".ts"] });
    assert.equal(result.kind, "success");
    assert.equal(result.matches?.length, 1);
    assert.ok(result.matches?.[0].path.includes("a.ts"));
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

import test from "node:test";
import assert from "node:assert/strict";
import type { AlixEvent } from "../src/events/types.js";
import { buildInspectorSnapshot, compareInspectorSnapshots } from "../src/inspector/projection.js";

function event(seq: number, type: string, payload: unknown, timestamp = `2026-01-01T00:00:${String(seq).padStart(2, "0")}Z`): AlixEvent {
  return {
    id: String(seq),
    seq,
    version: 1,
    sessionId: "s1",
    timestamp,
    type,
    actor: "system",
    payload
  };
}

test("buildInspectorSnapshot groups context, shell, diff, approval, verification, token, and ended-session data", () => {
  const snapshot = buildInspectorSnapshot("s1", [
    event(1, "session.started", {}),
    event(2, "context.bundle_compiled", {
      taskType: "feature",
      budget: { maxTokens: 1000, usedTokens: 250 },
      primaryFiles: [{ path: "src/app.ts", kind: "source", symbolName: "run" }],
      pinned: [{ path: "README.md", kind: "doc", reason: "user pinned" }]
    }),
    event(3, "session.started", {}),
    event(4, "tool.requested", { toolCallId: "shell-1", toolName: "shell.run", argsPreview: { command: "npm test" } }),
    event(5, "tool.completed", { toolCallId: "shell-1", toolName: "shell.run", status: "success", outputPreview: "ok" }),
    event(6, "patch.checkpoint_created", { toolCallId: "patch-1", files: ["src/app.ts"] }),
    event(7, "tool.completed", { toolCallId: "patch-1", toolName: "patch.apply", changedFiles: ["src/app.ts"], status: "success" }),
    event(8, "patch.rollback_completed", { toolCallId: "patch-1" }),
    event(9, "autonomy.scope_expansion", { toolCallId: "approval-1", toolName: "write", paths: ["src/app.ts"] }),
    event(10, "autonomy.scope_approved", { toolCallId: "approval-1", toolName: "write", paths: ["src/app.ts"] }),
    event(11, "verification.check_started", { command: "npm run build", reason: "compile" }),
    event(12, "verification.check_finished", { command: "npm run build", status: "passed", output: "clean" }),
    event(13, "model.usage", { provider: "openai", model: "gpt", inputTokens: 10, outputTokens: 5 }),
    event(14, "session.ended", { reason: "completed" })
  ]);

  assert.equal(snapshot.sessionId, "s1");
  assert.deepEqual(snapshot.summary, {
    eventCount: 14,
    status: "completed",
    reason: "completed",
    latestSeq: 14,
    startedAt: "2026-01-01T00:00:01Z",
    endedAt: "2026-01-01T00:00:14Z"
  });
  assert.equal(snapshot.timeline.length, 14);
  assert.deepEqual(snapshot.context, {
    taskType: "feature",
    budget: { maxTokens: 1000, usedTokens: 250 },
    primaryFiles: [{ path: "src/app.ts", kind: "source", symbolName: "run" }],
    tests: [],
    supportingFiles: [],
    pinned: [{ path: "README.md", kind: "doc", reason: "user pinned" }]
  });
  assert.deepEqual(snapshot.terminal, [{ toolCallId: "shell-1", command: "npm test", status: "success", outputPreview: "ok" }]);
  assert.deepEqual(snapshot.diffs, [
    {
      toolCallId: "patch-1",
      changedFiles: ["src/app.ts"],
      checkpointFiles: ["src/app.ts"],
      rolledBack: true,
      status: "rolled_back"
    }
  ]);
  assert.deepEqual(snapshot.approvals, [
    { toolCallId: "approval-1", toolName: "write", paths: ["src/app.ts"], status: "pending" },
    { toolCallId: "approval-1", toolName: "write", paths: ["src/app.ts"], status: "approved" }
  ]);
  assert.deepEqual(snapshot.verification, [{ command: "npm run build", reason: "compile", status: "passed", output: "clean" }]);
  assert.deepEqual(snapshot.tokens, {
    totalInputTokens: 10,
    totalOutputTokens: 5,
    entries: [{ provider: "openai", model: "gpt", inputTokens: 10, outputTokens: 5 }]
  });
});

test("compareInspectorSnapshots reports changed-file differences and verification status differences", () => {
  const left = buildInspectorSnapshot("left", [
    event(1, "tool.completed", { toolCallId: "left-patch", toolName: "patch.apply", changedFiles: ["left.ts", "both.ts"], status: "success" }),
    event(2, "verification.check_finished", { command: "npm test", status: "passed" }),
    event(3, "model.usage", { inputTokens: 100, outputTokens: 20 })
  ]);
  const right = buildInspectorSnapshot("right", [
    event(1, "tool.completed", { toolCallId: "right-patch", toolName: "patch.apply", changedFiles: ["right.ts", "both.ts"], status: "success" }),
    event(2, "verification.check_finished", { command: "npm test", status: "failed" }),
    event(3, "verification.check_finished", { command: "npm run build", status: "passed" }),
    event(4, "model.usage", { inputTokens: 130, outputTokens: 15 })
  ]);

  assert.deepEqual(compareInspectorSnapshots(left, right), {
    leftSessionId: "left",
    rightSessionId: "right",
    changedFilesOnlyLeft: ["left.ts"],
    changedFilesOnlyRight: ["right.ts"],
    changedFilesBoth: ["both.ts"],
    verificationStatus: { left: "passed", right: "mixed" },
    tokenDelta: { inputTokens: 30, outputTokens: -5 }
  });
});

test("buildInspectorSnapshot falls back to checkpoint files when patch apply omits changed files", () => {
  const snapshot = buildInspectorSnapshot("s1", [
    event(1, "patch.checkpoint_created", { toolCallId: "patch-1", files: ["src/app.ts", "tests/app.test.ts"] }),
    event(2, "tool.completed", { toolCallId: "patch-1", toolName: "patch.apply", status: "success" })
  ]);

  assert.deepEqual(snapshot.diffs[0], {
    toolCallId: "patch-1",
    changedFiles: ["src/app.ts", "tests/app.test.ts"],
    checkpointFiles: ["src/app.ts", "tests/app.test.ts"],
    rolledBack: false,
    status: "applied"
  });
});

test("buildInspectorSnapshot finishes the latest matching verification command", () => {
  const snapshot = buildInspectorSnapshot("s1", [
    event(1, "verification.check_started", { command: "npm test", reason: "first run" }),
    event(2, "verification.check_finished", { command: "npm test", status: "failed", output: "first failure" }),
    event(3, "verification.check_started", { command: "npm test", reason: "repair run" }),
    event(4, "verification.check_finished", { command: "npm test", status: "passed", output: "second pass" })
  ]);

  assert.deepEqual(snapshot.verification, [
    { command: "npm test", reason: "first run", status: "failed", output: "first failure" },
    { command: "npm test", reason: "repair run", status: "passed", output: "second pass" }
  ]);
});

import { describe, it } from "node:test";
import assert from "node:assert";
import { mkdtempSync, writeFileSync, mkdirSync, rmSync } from "node:fs";
import { join } from "node:path";
import { tmpdir as tmpDir } from "node:os";
import { startServer } from "../src/server/server.js";

describe("Inspector SSE event streaming", () => {
  it("sends existing events as SSE and keeps connection open for polling", async () => {
    const tmp = mkdtempSync(join(tmpDir(), "alix-test-"));
    const sessionDir = join(tmp, ".alix", "sessions", "test-session");
    mkdirSync(sessionDir, { recursive: true });
    const eventsPath = join(sessionDir, "events.jsonl");
    writeFileSync(eventsPath, '{"seq":1,"type":"test","actor":"agent","timestamp":"2026-01-01T00:00:00Z","payload":{}}\n');

    const { url, close } = await startServer(tmp, "127.0.0.1", 0);
    try {
      const res = await fetch(`${url}/api/sessions/test-session/events`);
      assert.strictEqual(res.headers.get("content-type"), "text/event-stream");

      // Read with a short timeout so we don't wait for the SSE connection to close
      const reader = res.body!.getReader();
      const decoder = new TextDecoder();
      let body = "";
      const startTime = Date.now();
      while (Date.now() - startTime < 1500) {
        const { done, value } = await reader.read();
        if (done) break;
        body += decoder.decode(value, { stream: true });
        if (body.length > 0) break; // Got at least one chunk — assertion below is sufficient
      }
      reader.cancel();

      assert.ok(body.includes("event: alix"), `should contain SSE event line, got: ${body}`);
      assert.ok(body.includes('"seq":1'), `should contain event data, got: ${body}`);
      assert.ok(body.includes("data: "), `should contain data field, got: ${body}`);
    } finally {
      await close();
      rmSync(tmp, { recursive: true, force: true });
    }
  });

  it("polls for and delivers new events written after connection", async () => {
    const tmp = mkdtempSync(join(tmpDir(), "alix-test-"));
    const sessionDir = join(tmp, ".alix", "sessions", "test-session");
    mkdirSync(sessionDir, { recursive: true });
    const eventsPath = join(sessionDir, "events.jsonl");

    // Write initial event
    writeFileSync(eventsPath, '{"seq":1,"type":"session.started","actor":"system","timestamp":"2026-01-01T00:00:00Z","payload":{}}\n');

    const { url, close } = await startServer(tmp, "127.0.0.1", 0);
    try {
      const res = await fetch(`${url}/api/sessions/test-session/events`);
      assert.strictEqual(res.headers.get("content-type"), "text/event-stream");

      // Wait for initial event
      const reader = res.body!.getReader();
      const decoder = new TextDecoder();
      let body = "";
      const startTime = Date.now();
      while (Date.now() - startTime < 1500) {
        const { done, value } = await reader.read();
        if (done) break;
        body += decoder.decode(value, { stream: true });
        if (body.includes('"seq":1')) break;
      }
      reader.cancel();

      assert.ok(body.includes('"seq":1'), "should receive initial event");

      // Write a second event while the connection is open
      writeFileSync(
        eventsPath,
        '{"seq":2,"type":"agent.plan_proposed","actor":"agent","timestamp":"2026-01-01T00:00:01Z","payload":{"text":"hello"}}\n',
        { flag: "a" }
      );

      // Verify the new event arrived via polling (wait up to 2 seconds)
      // We re-connect to pick up the new event
      const res2 = await fetch(`${url}/api/sessions/test-session/events`);
      const reader2 = res2.body!.getReader();
      let body2 = "";
      const startTime2 = Date.now();
      while (Date.now() - startTime2 < 2000) {
        const { done, value } = await reader2.read();
        if (done) break;
        body2 += decoder.decode(value, { stream: true });
        if (body2.includes('"seq":2')) break;
      }
      reader2.cancel();

      assert.ok(body2.includes('"seq":2'), `should receive new event seq=2, got: ${body2.slice(0, 200)}`);
    } finally {
      await close();
      rmSync(tmp, { recursive: true, force: true });
    }
  });

  it("resumes from Last-Event-ID cursor on reconnect", async () => {
    const tmp = mkdtempSync(join(tmpDir(), "alix-test-"));
    const sessionDir = join(tmp, ".alix", "sessions", "test-session");
    mkdirSync(sessionDir, { recursive: true });
    const eventsPath = join(sessionDir, "events.jsonl");

    // Write 3 events
    writeFileSync(
      eventsPath,
      [
        '{"seq":1,"type":"session.started","actor":"system","timestamp":"2026-01-01T00:00:00Z","payload":{}}\n',
        '{"seq":2,"type":"user.message","actor":"user","timestamp":"2026-01-01T00:00:01Z","payload":{}}\n',
        '{"seq":3,"type":"agent.plan_proposed","actor":"agent","timestamp":"2026-01-01T00:00:02Z","payload":{}}\n',
      ].join("")
    );

    const { url, close } = await startServer(tmp, "127.0.0.1", 0);
    try {
      // Resume from seq=1 — should only get seq=2 and seq=3
      const res = await fetch(`${url}/api/sessions/test-session/events`, {
        headers: { "Last-Event-ID": "1" },
      });
      const reader = res.body!.getReader();
      const decoder = new TextDecoder();
      let body = "";
      const startTime = Date.now();
      while (Date.now() - startTime < 1500) {
        const { done, value } = await reader.read();
        if (done) break;
        body += decoder.decode(value, { stream: true });
        if (body.includes('"seq":3')) break;
      }
      reader.cancel();

      assert.ok(body.includes('"seq":2'), `should contain seq=2, got: ${body.slice(0, 200)}`);
      assert.ok(body.includes('"seq":3'), `should contain seq=3, got: ${body.slice(0, 200)}`);
      assert.ok(!body.includes('"seq":1'), `should NOT contain seq=1 (already seen), got: ${body.slice(0, 200)}`);
    } finally {
      await close();
      rmSync(tmp, { recursive: true, force: true });
    }
  });

  it("returns empty response when session does not exist", async () => {
    const tmp = mkdtempSync(join(tmpDir(), "alix-test-"));

    const { url, close } = await startServer(tmp, "127.0.0.1", 0);
    try {
      const res = await fetch(`${url}/api/sessions/nonexistent/events`);
      assert.strictEqual(res.status, 200);
    } finally {
      await close();
      rmSync(tmp, { recursive: true, force: true });
    }
  });
});

import test from "node:test";
