    { jsonrpc: "2.0", id: "1", result: { protocolVersion: "2024-11-05", capabilities: { tools: {} }, serverInfo: { name: "test", version: "1.0" } } },
    { jsonrpc: "2.0", id: "2", result: { tools } }
  ]);
