      { command: "npm test", reason: "test" },
    ];
    const results: Array<{ check: VerificationCheck; result: VerificationResult }> = [
      { check: allChecks[0], result: { status: "failed", command: "npm test", output: "FAIL: expected 1 got 2" } },
