  --accent-2: #ff7448;
  --error-bg: rgba(255, 72, 72, 0.08);
  --error-border: rgba(255, 72, 72, 0.3);
  --success-bg: rgba(80, 220, 130, 0.06);
  --success-border: rgba(80, 220, 130, 0.25);
  --tool-bg: rgba(208, 255, 115, 0.04);
