import { existsSync } from "node:fs";
import { mkdir, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import type { AlixConfig } from "../config/schema.js";
import type { EventLog } from "../events/event-log.js";
import type { McpManager } from "../mcp/manager.js";
import { decidePolicy } from "../policy/policy-engine.js";
import { redactValue } from "../policy/secret-scanner.js";
import { readFile, searchDir } from "./file-tools.js";
import { runCommand } from "./shell-tool.js";
import { applyPatch } from "../patch/patch-engine.js";
import { buildEditFormatPolicy } from "../patch/edit-format-policy.js";
import type { EditFormat, EditFormatPolicy } from "../patch/edit-format-policy.js";
import { extractPatchPaths } from "../patch/patch-paths.js";
import { createFileCheckpoint, restoreFileCheckpoint } from "../checkpoints/checkpoint-manager.js";
import type { Checkpoint } from "../checkpoints/checkpoint-manager.js";
import type { ToolResult } from "./types.js";

export type ToolCallRequest = {
  toolCallId: string;
  name: string;
  args: Record<string, unknown>;
};

export type ExecuteResult = ToolResult | { kind: "denied"; reason: string };

export class ToolExecutor {
  constructor(
    private config: AlixConfig,
    private log: EventLog,
    private root: string,
    private mcpManager?: McpManager,
    private editFormatPolicy?: EditFormatPolicy,
    private extraHandlers?: Record<string, (args: Record<string, unknown>) => Promise<ToolResult>>
  ) {}

  private sessionId(): string {
    // Extract sessionId from EventLog sessionDir: .alix/sessions/<sessionId>
    const parts = this.log.sessionDir.split("sessions/");
    return parts.length > 1 ? parts[1] : "unknown";
  }

  private async logEvent(type: string, payload: Record<string, unknown>): Promise<void> {
    await this.log.append({ sessionId: this.sessionId(), actor: "system", type, payload });
  }

  async execute(request: ToolCallRequest): Promise<ExecuteResult> {
    const { toolCallId, name, args } = request;
    const capability = name;

    await this.logEvent("tool.requested", { toolCallId, toolName: name, argsPreview: args, capability });

    const policyDecision = decidePolicy(this.config, {
      toolCallId,
      capability,
      ...args as { path?: string; command?: string }
    });

    if (policyDecision.decision === "deny") {
      await this.logEvent("tool.failed", { toolCallId, toolName: name, error: policyDecision.reason, status: "denied" });
      return { kind: "denied", reason: policyDecision.reason };
    }

    // MCP availability check — policy said "ask" or "allow", but is the tool connected?
    if (name.startsWith("mcp.") && !this.mcpManager) {
      const msg = "MCP manager not initialized. No MCP servers are connected.";
      await this.logEvent("tool.failed", { toolCallId, toolName: name, error: msg, status: "unavailable" });
      return { kind: "denied", reason: msg };
    }

    await this.logEvent("tool.started", { toolCallId, toolName: name });

    let result: ToolResult;

    switch (name) {
      case "file.read": {
        const { root: r, path } = args as { root: string; path: string };
        result = await readFile({ root: r ?? this.root, path });
        if (result.kind === "success" && result.content) {
          // Suggest calling done if the file looks like a complete implementation
          const hasFunction = /^(?:async )?\s*function|^(?:async )?\s*def|^(?:async )?\s*const\s+\w+\s*=/m.test(result.content);
          const hasReturn = /return|yield/.test(result.content);
          if (hasFunction && hasReturn) {
            result.content = `${result.content.slice(0, 200)}\n\n[File contains a complete implementation. Call done if no further changes are needed.]`;
          }
        }
        break;
      }
      case "dir.search": {
        const { root: r, pattern, extensions } = args as { root: string; pattern: string; extensions: string[] };
        result = await searchDir({ root: r ?? this.root, pattern, extensions: extensions ?? [] });
        break;
      }
      case "shell.run": {
        const { root: r, command, cwd, timeoutMs } = args as { root?: string; command: string; cwd?: string; timeoutMs?: number };
        result = await runCommand({ command, cwd: cwd ?? r ?? this.root, timeoutMs });
        break;
      }
      case "patch.apply": {
        const { root: r, format, patchText } = args as { root: string; format: string; patchText: string };
        const patchRoot = r ?? this.root;
        const policy = this.editFormatPolicy ?? buildEditFormatPolicy({ provider: this.config.model.provider });
        const requestedFormat = format as EditFormat;
        const allowed = policy.allowed.includes(requestedFormat);
        await this.logEvent("patch.edit_format_policy", {
          toolCallId,
          provider: policy.provider,
          requestedFormat: format,
          preferredFormat: policy.preferred,
          allowedFormats: policy.allowed,
          matchesPreference: requestedFormat === policy.preferred,
          allowed,
          fullFileRewrite: policy.fullFileRewrite,
        });
        if (!allowed) {
          result = { kind: "error", message: `Patch format "${format}" is not allowed by edit format policy. Allowed formats: ${policy.allowed.join(", ")}`, retryable: false };
          break;
        }
        const changedFiles = extractPatchPaths(format, patchText);
        let checkpoint: Checkpoint | null = null;
        if (changedFiles.length > 0) {
          checkpoint = await createFileCheckpoint(patchRoot, changedFiles);
          await this.logEvent("patch.checkpoint_created", { toolCallId, checkpointId: checkpoint.id, files: checkpoint.files, missingFiles: checkpoint.missingFiles });
        }
        try {
          const patchResult = await applyPatch(patchRoot, format as any, patchText);
          result = patchResult.status === "applied"
            ? { kind: "success", changedFiles: patchResult.changedFiles }
            : { kind: "error", message: "Patch invalid" };
        } catch (e: unknown) {
          if (checkpoint) {
            await this.logEvent("patch.rollback_started", { toolCallId, checkpointId: checkpoint.id, files: checkpoint.files });
            try {
              await restoreFileCheckpoint(checkpoint);
              await this.logEvent("patch.rollback_completed", { toolCallId, checkpointId: checkpoint.id, files: checkpoint.files });
            } catch (rollbackError: unknown) {
              await this.logEvent("patch.rollback_failed", {
                toolCallId,
                checkpointId: checkpoint.id,
                error: rollbackError instanceof Error ? rollbackError.message : String(rollbackError),
              });
            }
          }
          result = { kind: "error", message: e instanceof Error ? e.message : String(e) };
        }
        break;
      }
      case "file.create": {
        const { root: r, path, content } = args as { root: string; path: string; content: string };
        if (!path || content === undefined) { result = { kind: "error", message: "file.create requires path and content" }; break; }
        const resolvedRoot = resolve(r ?? this.root);
        const resolvedPath = resolve(resolvedRoot, path);
        if (!resolvedPath.startsWith(resolvedRoot + "/") && resolvedPath !== resolvedRoot) {
          result = { kind: "error", message: "Path is outside workspace", retryable: false, hint: "Check the path is relative and inside the project directory." }; break;
        }
        if (existsSync(resolvedPath)) {
          result = { kind: "error", message: `File already exists: ${path}`, retryable: false, hint: `Use file.read to inspect the existing content, then use patch.apply to modify it.` }; break;
        }
        await mkdir(dirname(resolvedPath), { recursive: true });
        await writeFile(resolvedPath, content, "utf8");
        result = { kind: "success", output: `File created: ${path}`, createdPath: path, changedFiles: [path] };
        break;
      }
      case "file.delete": {
        const { root: r, path } = args as { root: string; path: string };
        if (!path) { result = { kind: "error", message: "file.delete requires path" }; break; }
        const resolvedRoot = resolve(r ?? this.root);
        const resolvedPath = resolve(resolvedRoot, path);
        if (!resolvedPath.startsWith(resolvedRoot + "/") && resolvedPath !== resolvedRoot) {
          result = { kind: "error", message: "Path is outside workspace", retryable: false, hint: "Check the path is relative and inside the project directory." }; break;
        }
        const { rm } = await import("node:fs/promises");
        try { await rm(resolvedPath); } catch (e) { result = { kind: "error", message: `Delete failed: ${e instanceof Error ? e.message : String(e)}` }; break; }
        result = { kind: "success", output: `File deleted: ${path}`, deletedPath: path };
        break;
      }
      case "file.exists": {
        const { root: r, path } = args as { root: string; path: string };
        if (!path) { result = { kind: "error", message: "file.exists requires path" }; break; }
        const resolvedRoot = resolve(r ?? this.root);
        const resolvedPath = resolve(resolvedRoot, path);
        if (!resolvedPath.startsWith(resolvedRoot + "/") && resolvedPath !== resolvedRoot) {
          result = { kind: "error", message: "Path is outside workspace", retryable: false }; break;
        }
        result = { kind: "success", output: existsSync(resolvedPath) ? `File exists: ${path}` : `File not found: ${path}`, exists: existsSync(resolvedPath) };
        break;
      }
      case "done": {
        result = { kind: "success", output: "Task complete.", completed: true };
        break;
      }
      case "delegate": {
        const handler = this.extraHandlers?.delegate;
        if (!handler) {
          result = { kind: "error", message: "Delegate handler not initialized", retryable: false };
        } else {
          result = await handler(args as Record<string, unknown>);
        }
        break;
      }
      default: {
        // Check if this is an MCP tool (mcp.server.tool format)
        if (name.startsWith("mcp.")) {
          if (!this.mcpManager) {
            result = { kind: "error", message: "MCP manager not initialized", retryable: false };
          } else {
            const parts = name.split(".");
            const serverName = parts[1];
            const toolName = parts.slice(2).join("_");
            const fullName = `${serverName}/${toolName}`;
            result = await this.mcpManager.callTool(fullName, args);
            // Classify MCP errors with hints
            if (result.kind === "error") {
              result = classifyError(result);
            }
          }
        } else {
          result = { kind: "error", message: `Unknown tool: ${name}`, retryable: false };
        }
      }
    }

    // Build log payload — redact secrets from output/error before logging
    const logPayload = result.kind === "success"
      ? redactValue({
          toolCallId, toolName: name, status: result.kind,
          outputSize: ((result.output?.length ?? 0) + (result.content?.length ?? 0)),
          outputPreview: (result.output ?? result.content ?? "").slice(0, 200),
        })
      : redactValue({
          toolCallId, toolName: name, status: result.kind,
          outputSize: 0,
          error: result.message,
        });
    await this.logEvent(result.kind === "success" ? "tool.completed" : "tool.failed", logPayload.redacted as Record<string, unknown>);

    return result;
  }
}

type ErrorResult = { kind: "error"; message: string; retryable?: boolean; hint?: string };

export function classifyError(result: ErrorResult): ErrorResult {
  const msg = result.message.toLowerCase();

  // Fatal — don't retry, model can't fix this
  if (msg.includes("unknown mcp tool") ||
      msg.includes("not initialized") ||
      msg.includes("authentication failed") ||
      msg.includes("401") ||
      msg.includes("403") ||
      msg.includes("invalid api key") ||
      msg.includes("permission denied") ||
      msg.includes("path is outside")) {
    return { ...result, retryable: false };
  }

  // Retryable — transient or server-side
  if (msg.includes("timed out") ||
      msg.includes("timeout") ||
      msg.includes("429") ||
      msg.includes("rate limit") ||
      msg.includes("connection") ||
      msg.includes("econnrefused") ||
      msg.includes("etimedout") ||
      msg.includes("503") ||
      msg.includes("unavailable")) {
    return { ...result, retryable: true };
  }

  // Unknown/ambiguous — retry once, model decides
  return { ...result, retryable: true };
}

import { existsSync } from "node:fs";
import { readdir, readFile as fsReadFile } from "node:fs/promises";
import { join, resolve, relative } from "node:path";
import type { ToolResult, FileMatch } from "./types.js";

const IGNORED_DIRS = new Set([".git", "node_modules", "dist", "build", "coverage", ".next", ".alix"]);

export async function readFile(args: { root: string; path: string }): Promise<ToolResult> {
  const { root, path } = args;
  const resolvedRoot = resolve(root);

  let resolvedPath: string;
  try {
    resolvedPath = resolve(resolvedRoot, path);
  } catch {
    return { kind: "error", message: `Invalid path: ${path}` };
  }

  if (!resolvedPath.startsWith(resolvedRoot + "/") && resolvedPath !== resolvedRoot) {
    return { kind: "error", message: `Path is outside workspace: ${path}` };
  }

  if (!existsSync(resolvedPath)) {
    return { kind: "error", message: `File not found: ${path}` };
  }

  try {
    const content = await fsReadFile(resolvedPath, "utf8");
    return { kind: "success", content };
  } catch (err) {
    return { kind: "error", message: err instanceof Error ? err.message : String(err) };
  }
}

export async function searchDir(args: { root: string; pattern: string; extensions: string[] }): Promise<ToolResult> {
  const { root, pattern, extensions } = args;
  const matches: FileMatch[] = [];

  async function walk(dir: string): Promise<void> {
    let entries;
    try {
      entries = await readdir(dir, { withFileTypes: true });
    } catch {
      return;
    }
    for (const entry of entries) {
      if (entry.isDirectory() && !IGNORED_DIRS.has(entry.name)) {
        await walk(join(dir, entry.name));
      } else if (entry.isFile()) {
        const ext = "." + (entry.name.split(".").pop() ?? "");
        if (extensions.length > 0 && !extensions.includes(ext)) continue;
        const filePath = join(dir, entry.name);
        const rel = relative(root, filePath);
        try {
          const content = await fsReadFile(filePath, "utf8");
          const lines = content.split("\n");
          for (let i = 0; i < lines.length; i++) {
            if (lines[i].includes(pattern)) {
              matches.push({ path: rel, lineNumber: i + 1, line: lines[i] });
            }
          }
        } catch {
          // skip binary or unreadable files
        }
      }
    }
  }

  await walk(root);
  return { kind: "success", matches };
}

import { spawn } from "node:child_process";
import type { ToolResult } from "./types.js";

const MAX_BYTES = 80_000;
const DEFAULT_TIMEOUT_MS = 120_000;

function normalizeTimeoutMs(timeoutMs: unknown): number {
  const value = typeof timeoutMs === "string" ? Number(timeoutMs) : timeoutMs;
  return typeof value === "number" && Number.isFinite(value) && value > 0
    ? value
    : DEFAULT_TIMEOUT_MS;
}

function normalizeCommand(command: unknown): string {
  return Array.isArray(command) && command.every((part) => typeof part === "string")
    ? command.join(" ")
    : String(command ?? "");
}

function truncate(text: string, maxBytes: number): string {
  if (Buffer.byteLength(text, "utf8") <= maxBytes) return text;
  let result = "";
  let byteCount = 0;
  const bytes = Buffer.from(text, "utf8");
  let cutIndex = 0;
  for (let i = 0; i < bytes.length; i++) {
    const b = bytes[i];
    const charBytes = b < 0x80 ? 1 : b < 0xe0 ? 2 : b < 0xf0 ? 3 : 4;
    if (byteCount + charBytes > maxBytes) break;
    byteCount += charBytes;
    cutIndex = i + 1;
  }
  const truncated = text.slice(0, cutIndex);
  const lines = (truncated.match(/\n/g) || []).length;
  const hiddenBytes = Buffer.byteLength(text, "utf8") - byteCount;
  return truncated + `[... ${lines} lines truncated, ${hiddenBytes} bytes hidden]`;
}

export async function runCommand(args: { command: string; cwd: string; timeoutMs?: number }): Promise<ToolResult> {
  const command = normalizeCommand(args.command);
  const { cwd } = args;
  const timeoutMs = normalizeTimeoutMs(args.timeoutMs);

  if (!command || typeof command !== "string" || !command.trim()) {
    return { kind: "error", message: "shell.run requires a non-empty command string" };
  }

  return new Promise((resolve) => {
    const child = spawn(command, [], { cwd: cwd || undefined, shell: true });
    let stdout = "";
    let stderr = "";
    let settled = false;
    const finish = (result: ToolResult) => {
      if (settled) return;
      settled = true;
      clearTimeout(timer);
      resolve(result);
    };

    const timer = setTimeout(() => {
      child.kill("SIGKILL");
      finish({ kind: "error", message: `Command timed out after ${timeoutMs}ms: ${command}` });
    }, timeoutMs);

    child.stdout.on("data", (chunk) => { stdout += chunk; });
    child.stderr.on("data", (chunk) => { stderr += chunk; });

    child.on("close", (code) => {
      const combined = stderr ? `${stdout}\n--- stderr ---\n${stderr}` : stdout;
      const output = truncate(combined, MAX_BYTES);
      if ((code ?? 0) !== 0) {
        finish({ kind: "error", message: `Command exited with code ${code}: ${command}\n${output}` });
        return;
      }
      finish({ kind: "success", output, exitCode: code ?? 0 });
    });

    child.on("error", (err) => {
      finish({ kind: "error", message: `Command failed: ${command} -- ${err.message}` });
    });
  });
}

export type ToolName = "file.read" | "file.create" | "file.delete" | "file.exists" | "dir.search" | "shell.run" | "patch.apply" | "done";

export type ToolResult =
  | { kind: "success"; content?: string; output?: string; matches?: FileMatch[]; changedFiles?: string[]; exitCode?: number; createdPath?: string; deletedPath?: string; exists?: boolean; completed?: boolean }
  | { kind: "error"; message: string; retryable?: boolean; hint?: string };
// retryable: true = safe to retry. false/undefined = fatal (don't spin).
// hint: short instruction for the model on how to recover.

export type FileMatch = {
  path: string;
  lineNumber: number;
  line: string;
};

export type ToolArgs = {
  "file.read": { root: string; path: string };
  "dir.search": { root: string; pattern: string; extensions: string[] };
  "shell.run": { command: string; cwd: string; timeoutMs?: number };
  "patch.apply": { root: string; format: string; patchText: string };
};

// src/skills/catalog.ts
import type { LoadedSkill } from "./types.js";

export class SkillCatalog {
  private byTrigger: Map<string, LoadedSkill> = new Map();
  private byPattern: Array<{ pattern: RegExp; skill: LoadedSkill }> = [];

  constructor(skills: LoadedSkill[]) {
    for (const skill of skills) {
      if (skill.manifest.trigger) {
        this.byTrigger.set(skill.manifest.trigger, skill);
      }
      if (skill.manifest.pattern) {
        try {
          this.byPattern.push({
            pattern: new RegExp(skill.manifest.pattern, "i"),
            skill,
          });
        } catch {
          // skip invalid regex
        }
      }
    }
  }

  /**
   * Match a user prompt against skill triggers and patterns.
   * Returns matched skills ordered by specificity (trigger > pattern).
   */
  match(prompt: string): LoadedSkill[] {
    const results: LoadedSkill[] = [];

    // Exact trigger match (e.g., "/tdd add feature")
    const triggerMatch = prompt.match(/^\/(\w+)/);
    if (triggerMatch) {
      const matched = this.byTrigger.get(`/${triggerMatch[1]}`);
      if (matched) results.push(matched);
    }

    // Pattern match
    for (const { pattern, skill } of this.byPattern) {
      if (pattern.test(prompt) && !results.includes(skill)) {
        results.push(skill);
      }
    }

    return results;
  }

  getAll(): LoadedSkill[] {
    const seen = new Set<string>();
    const result: LoadedSkill[] = [];
    for (const s of [...this.byTrigger.values(), ...this.byPattern.map(p => p.skill)]) {
      if (!seen.has(s.manifest.name)) { seen.add(s.manifest.name); result.push(s); }
    }
    return result;
  }

  get(name: string): LoadedSkill | undefined {
    return this.byTrigger.get(name)
      ?? this.byTrigger.get(`/${name}`)
      ?? this.byPattern.find(p => p.skill.manifest.name === name)?.skill;
  }
}

export function buildSkillCatalog(skills: LoadedSkill[]): SkillCatalog {
  return new SkillCatalog(skills);
}

import type { SkillFactoryConfig } from "../config/schema.js";
import { runSkillFactory } from "./factory.js";

export const DEFAULT_FACTORY_CONFIG: SkillFactoryConfig = {
  enabled: false,
  provider: "ollama",
  model: "llama3",
  maxStore: 50,
  maxCandidates: 200,
  autoPromote: true,
};

export type DispatchParams = {
  sessionId: string;
  sessionDir: string;
  summary: string;
  filesCreated: string[];
  filesChanged: string[];
  config: SkillFactoryConfig;
};

/**
 * Fire-and-forget skill factory dispatcher.
 * Returns immediately after queuing the job. Does not wait for Ollama.
 */
export async function skillFactoryProcess(params: DispatchParams): Promise<{ queued: boolean; sessionId: string }> {
  if (!params.config.enabled) return { queued: false, sessionId: params.sessionId };
  // Non-blocking: spawn the factory without awaiting it
  void runSkillFactory(params).catch((err) => {
    console.error("[skill-factory] Failed:", err);
  });
  return { queued: true, sessionId: params.sessionId };
}

// Public API
export const skillFactory = { process: skillFactoryProcess };

import { mkdir, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { createProvider } from "../providers/registry.js";
import type { SkillFactoryConfig } from "../config/schema.js";
import type { DispatchParams } from "./dispatcher.js";
import { parseSkillContent } from "./types.js";
import { promoteIfEligible } from "./promotion.js";

const homeDir = process.env.HOME ?? "";
const candidatesDir = join(homeDir, ".alix", "candidates");

/**
 * Run the skill factory: distill session patterns into a candidate skill.
 * This runs asynchronously and does NOT block the main loop.
 */
export async function runSkillFactory(params: DispatchParams): Promise<void> {
  if (!params.config.enabled) {
    return;
  }
  if (!params.summary && params.filesCreated.length === 0 && params.filesChanged.length === 0) {
    return;
  }

  // Build the distillation prompt
  const prompt = buildDistillationPrompt(params);

  // Call Ollama
  const provider = createProvider(
    { provider: params.config.provider, model: params.config.model },
    process.env[`${params.config.provider.toUpperCase()}_API_KEY`]
  );

  let skillContent = "";
  try {
    const response = await provider.complete({
      systemPrompt: "You are a skill distillation engine. Generate a Hermes-format skill from the provided session summary. Output ONLY the SKILL.md content with valid YAML front matter and a markdown body. No explanations, no preamble.",
      messages: [{ role: "user", content: prompt }],
      tools: [],
    });
    skillContent = response.text?.trim() ?? "";
  } catch (err) {
    // Ollama may not be running - that's fine, fire-and-forget
    console.warn("[skill-factory] Ollama call failed:", err);
    return;
  }

  if (!skillContent || skillContent.length < 100) {
    console.warn("[skill-factory] Content too short:", skillContent?.length ?? 0, "bytes");
    return;
  }

  // Validate the skill has front matter
  const { manifest } = parseSkillContent(skillContent);
  if (!manifest) {
    console.warn("[skill-factory] Invalid skill manifest from Ollama");
    return;
  }

  // Write to candidates directory
  // Note: The factory writes candidates to ~/.alix/candidates/, not to the workspace.
  // If skill verification against the workspace is needed in the future, use
  // runWithIsolation() from './test-isolation.js' to protect working tree changes.
  const sessionCandidateDir = join(candidatesDir, params.sessionId);
  await mkdir(sessionCandidateDir, { recursive: true });
  await writeFile(join(sessionCandidateDir, "SKILL.md"), skillContent, "utf8");

  if (!params.config.autoPromote) return; // skip entirely if not auto-promoting
  // Try to promote — on first write this will fail (successCount=1),
  // on second write it will succeed. Call every time to handle re-use.
  try {
    await promoteIfEligible(params.sessionId);
  } catch (err) {
    // best effort — non-blocking
    console.warn("[skill-factory] Promotion check failed:", err);
  }
}

function buildDistillationPrompt(params: DispatchParams): string {
  const files = [...params.filesCreated, ...params.filesChanged].join(", ") || "none";
  const lines = [
    "Distill this coding session into a reusable Hermes-format skill.",
    "",
    "Session summary: " + params.summary,
    "Files involved: " + files,
    "Session ID: " + params.sessionId,
    "",
    "Generate a SKILL.md file with:",
    "1. YAML front matter: name, description, trigger (slash command like /name), pattern (regex), version (1.0.0), is_core (false)",
    "2. Markdown body: the complete skill guidance as if written by an expert",
    "",
    "The skill should capture the reusable pattern/technique from this session, not the specific implementation details.",
    "",
    "Output format:",
    "---",
    "name: <skill-name>",
    "description: <one-line description>",
    "trigger: /<name>",
    'pattern: "<optional regex>"',
    'version: "1.0.0"',
    "is_core: false",
    "---",
    "# Skill Title",
    "",
    "[Full skill guidance in markdown]",
  ];
  return lines.join("\n");
}

// src/skills/lifecycle.ts
import { readdirSync, statSync, rmSync, existsSync, readFileSync } from "node:fs";
import { join } from "node:path";
import { parseSkillContent } from "./types.js";

export type LifecycleConfig = {
  maxStore: number;
  maxCandidates?: number;
};

export function evictIfNeeded(skillsDir: string, config: LifecycleConfig): void {
  if (!existsSync(skillsDir)) return;
  let entries: string[] = [];
  try {
    entries = readdirSync(skillsDir).filter(e => e !== ".usage.json" && e !== "node_modules");
  } catch { return; }

  if (entries.length <= config.maxStore) return; // No eviction needed

  const skills: Array<{ name: string; is_core: boolean; mtime: number }> = [];

  for (const entry of entries) {
    const skillPath = join(skillsDir, entry);
    try {
      if (!statSync(skillPath).isDirectory()) continue;
    } catch { continue; }
    const skillFile = join(skillPath, "SKILL.md");
    try {
      const content = readFileSync(skillFile, "utf8");
      const { manifest } = parseSkillContent(content);
      if (!manifest) continue;
      const mtime = statSync(skillPath).mtimeMs;
      skills.push({ name: entry, is_core: manifest.is_core ?? false, mtime });
    } catch { continue; }
  }

  // Sort: protected skills go last, then oldest first
  skills.sort((a, b) => {
    if (a.is_core && !b.is_core) return 1;
    if (!a.is_core && b.is_core) return -1;
    return a.mtime - b.mtime;
  });

  const toEvictCount = Math.max(0, skills.length - config.maxStore);
  if (toEvictCount > 0) {
    const toEvict = skills.filter(s => !s.is_core).slice(0, toEvictCount);
    for (const skill of toEvict) {
      try {
        rmSync(join(skillsDir, skill.name), { recursive: true });
      } catch { /* best effort */ }
    }
  }
}

// src/skills/loader.ts
import { readdir, readFile, stat } from "node:fs/promises";
import { join } from "node:path";
import { parseSkillContent } from "./types.js";
import type { LoadedSkill } from "./types.js";

/**
 * Discover and load all Hermes-format skills from a directory.
 * Each skill lives in a subdirectory: <root>/<skill-name>/SKILL.md
 */
export async function loadSkills(root: string): Promise<LoadedSkill[]> {
  const skills: LoadedSkill[] = [];
  let entries: string[] = [];
  try {
    entries = await readdir(root);
  } catch {
    return [];
  }

  for (const entry of entries) {
    const skillPath = join(root, entry);
    let isDir = false;
    try { isDir = (await stat(skillPath)).isDirectory(); } catch { continue; }
    if (!isDir) continue;
    const skillFile = join(skillPath, "SKILL.md");
    let content: string;
    try {
      content = await readFile(skillFile, "utf8");
    } catch {
      continue;
    }
    const { manifest, body } = parseSkillContent(content);
    if (!manifest) continue;
    skills.push({ manifest, body, path: skillPath });
  }

  return skills;
}

// src/skills/promotion.ts
import { readFileSync, writeFileSync, existsSync, mkdirSync } from "node:fs";
import { join } from "node:path";
import { parseSkillContent } from "./types.js";

const homeDir = process.env.HOME ?? "";
const candidatesDir = join(homeDir, ".alix", "candidates");
const skillsDir = join(homeDir, ".alix", "skills");

type UsageRecord = {
  lastUsed: string;
  successCount: number;
};

const usagePath = join(skillsDir, ".usage.json");

function readUsage(): Record<string, UsageRecord> {
  try { return JSON.parse(readFileSync(usagePath, "utf8")); } catch { return {}; }
}

function writeUsage(usage: Record<string, UsageRecord>): void {
  try {
    if (!existsSync(skillsDir)) mkdirSync(skillsDir, { recursive: true });
    writeFileSync(usagePath, JSON.stringify(usage, null, 2), "utf8");
  } catch {}
}

function readCandidate(sessionId: string): string | null {
  const candidatePath = join(candidatesDir, sessionId, "SKILL.md");
  try { return readFileSync(candidatePath, "utf8"); } catch { return null; }
}

export async function promoteIfEligible(sessionId: string): Promise<{ promoted: boolean; name: string }> {
  const content = readCandidate(sessionId);
  if (!content) return { promoted: false, name: "" };

  const { manifest } = parseSkillContent(content);
  if (!manifest) return { promoted: false, name: "" };

  const usage = readUsage();
  const skillName = manifest.name;

  if (!usage[skillName]) {
    usage[skillName] = { lastUsed: new Date().toISOString(), successCount: 0 };
  }
  usage[skillName].lastUsed = new Date().toISOString();
  usage[skillName].successCount++;

  const shouldPromote = usage[skillName].successCount >= 2;

  if (shouldPromote) {
    const finalName = resolveNamingCollision(skillName, manifest.version ?? "1.0.0");
    const targetDir = join(skillsDir, finalName);
    mkdirSync(targetDir, { recursive: true });
    writeFileSync(join(targetDir, "SKILL.md"), content, "utf8");
    usage[skillName] = { lastUsed: new Date().toISOString(), successCount: usage[skillName].successCount };
    writeUsage(usage);
    return { promoted: true, name: finalName };
  }

  writeUsage(usage);
  return { promoted: false, name: skillName };
}

export function resolveNamingCollision(name: string, version: string): string {
  const targetPath = join(skillsDir, name, "SKILL.md");
  if (!existsSync(targetPath)) return name;

  const existing = parseSkillContent(readFileSync(targetPath, "utf8"));
  if (!existing.manifest) return name;

  // If the existing file's name doesn't match our name, it's already suffixed.
  // Don't overwrite it — create a new suffixed version instead.
  if (existing.manifest.name !== name) {
    const suffix = version.replace(/\./g, "-");
    return `${name}-v${suffix}`;
  }

  const existingVer = existing.manifest.version ?? "1.0.0";
  if (compareVersions(version, existingVer) > 0) {
    return name; // improvement — overwrite
  }
  // Same or lower version — variation: add version suffix
  const suffix = version.replace(/\./g, "-");
  return `${name}-v${suffix}`;
}

function compareVersions(a: string, b: string): number {
  const partsA = a.split(".").map(Number);
  const partsB = b.split(".").map(Number);
  for (let i = 0; i < Math.max(partsA.length, partsB.length); i++) {
    const na = partsA[i] ?? 0;
    const nb = partsB[i] ?? 0;
    if (na > nb) return 1;
    if (na < nb) return -1;
  }
  return 0;
}

// src/skills/test-isolation.ts
import { spawn } from "node:child_process";

function gitStashList(cwd: string): Promise<string> {
  return new Promise((resolve) => {
    const proc = spawn("git", ["stash", "list"], { cwd, stdio: ["pipe", "pipe", "pipe"] });
    let output = "";
    proc.stdout?.on("data", (d) => (output += d.toString()));
    proc.stderr?.on("data", (d) => (output += d.toString()));
    proc.on("close", () => resolve(output));
    proc.on("error", () => resolve(""));
  });
}

function gitStashCount(cwd: string): Promise<number> {
  return gitStashList(cwd).then((list) => list.trim().split("\n").filter(Boolean).length);
}

/**
 * Stash working tree changes before running verification.
 * Returns stashId for later restore. Returns null if nothing to stash.
 */
export async function stashChanges(cwd: string): Promise<string | null> {
  const beforeCount = await gitStashCount(cwd);
  return new Promise((resolve) => {
    const proc = spawn("git", ["stash", "push", "-m", "skill-factory-isolation"], {
      cwd,
      stdio: ["pipe", "pipe", "pipe"],
    });
    let output = "";
    proc.stdout?.on("data", (d) => (output += d.toString()));
    proc.stderr?.on("data", (d) => (output += d.toString()));
    proc.on("close", () => {
      if (output.includes("No local changes to save") || output.includes("fatal:")) {
        resolve(null);
      } else {
        resolve(`stash@{${beforeCount}}`);
      }
    });
    proc.on("error", () => resolve(null));
  });
}

/**
 * Restore stashed changes after verification completes.
 */
export async function restoreChanges(cwd: string, stashId: string | null): Promise<boolean> {
  if (!stashId) return true;
  return new Promise((resolve) => {
    const proc = spawn("git", ["stash", "pop", "--index"], {
      cwd,
      stdio: ["pipe", "pipe", "pipe"],
    });
    let output = "";
    proc.stdout?.on("data", (d) => (output += d.toString()));
    proc.stderr?.on("data", (d) => (output += d.toString()));
    proc.on("close", (code) => resolve(code === 0));
    proc.on("error", () => resolve(false));
  });
}

/**
 * Run a verification command with git stash/restore isolation.
 * Stashes changes, runs command, restores changes.
 */
export async function runWithIsolation(
  cwd: string,
  command: string,
  timeoutMs = 120000
): Promise<{ passed: boolean; output: string; stashId: string | null }> {
  const stashId = await stashChanges(cwd);
  let passed = false;
  let output = "";

  try {
    output = await runCommand(command, cwd, timeoutMs);
    passed = true;
  } catch (err) {
    output = String(err);
  } finally {
    await restoreChanges(cwd, stashId);
  }

  return { passed, output, stashId };
}

function runCommand(cmd: string, cwd: string, timeoutMs: number): Promise<string> {
  return new Promise((resolve, reject) => {
    const proc = spawn("/bin/sh", ["-c", cmd], { cwd, stdio: ["pipe", "pipe", "pipe"] });
    let output = "";
    proc.stdout?.on("data", (d) => (output += d.toString()));
    proc.stderr?.on("data", (d) => (output += d.toString()));
    const timer = setTimeout(() => {
      proc.kill();
      reject(new Error(`Command timed out after ${timeoutMs}ms`));
    }, timeoutMs);
    proc.on("close", (code) => {
      clearTimeout(timer);
      if (code === 0) resolve(output);
      else reject(new Error(`Command failed with code ${code}: ${output}`));
    });
    proc.on("error", (err) => {
      clearTimeout(timer);
      reject(err);
    });
  });
}

export type SkillManifest = {
  name: string;
  description: string;
  trigger?: string;
  pattern?: string;
  version: string;
  is_core: boolean;
  tags?: string[];
  created_at?: string;
};

export type LoadedSkill = {
  manifest: SkillManifest;
  body: string;
  path: string;
};

export type SkillCandidate = {
  id: string;
  manifest: SkillManifest;
  body: string;
  path: string;
  created_at: string;
  sessionId: string;
  successCount: number;
};

export function parseFrontMatter(content: string): SkillManifest | null {
  // Support both full content with --- delimiters and raw YAML (no ---)
  const fullMatch = content.match(/^---\n([\s\S]*?)\n---/);
  const yaml = fullMatch ? fullMatch[1] : content;
  try {
    const raw = yamlToObject(yaml);
    if (!raw.name || !raw.description) return null;
    return {
      name: String(raw.name ?? ""),
      description: String(raw.description ?? ""),
      trigger: raw.trigger != null ? String(raw.trigger) : undefined,
      pattern: raw.pattern != null ? String(raw.pattern) : undefined,
      version: String(raw.version ?? "1.0.0"),
      is_core: raw.is_core === true,
      tags: raw.tags != null ? (Array.isArray(raw.tags) ? raw.tags as string[] : String(raw.tags).split(",").map((t) => t.trim())) : undefined,
      created_at: raw.created_at != null ? String(raw.created_at) : undefined,
    };
  } catch {
    // Returning null is intentional: missing front matter and parse errors are both silent failures.
    return null;
  }
}

function yamlToObject(yaml: string): Record<string, unknown> {
  const obj: Record<string, unknown> = {};
  for (const line of yaml.split("\n")) {
    const colonIdx = line.indexOf(":");
    if (colonIdx === -1) continue;
    const key = line.slice(0, colonIdx).trim();
    let value = line.slice(colonIdx + 1).trim();
    // Handle YAML arrays like [tag1, tag2]
    if (value.startsWith("[") && value.endsWith("]")) {
      const inner = value.slice(1, -1);
      obj[key] = inner.split(",").map((t: string) => t.trim()).filter(Boolean);
    } else if (value === "true") obj[key] = true;
    else if (value === "false") obj[key] = false;
    else if (!isNaN(Number(value)) && value !== "") obj[key] = Number(value);
    else obj[key] = value.replace(/^["']|["']$/g, "");
  }
  return obj;
}

export function parseSkillContent(content: string): { manifest: SkillManifest | null; body: string } {
  const match = content.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)/);
  if (!match) return { manifest: null, body: content };
  const manifest = parseFrontMatter(match[1]);
  return { manifest, body: match[2] ?? "" };
}

import { existsSync } from "node:fs";
import { readFile } from "node:fs/promises";
import { createServer, type ServerResponse } from "node:http";
import type { AddressInfo } from "node:net";
import { join } from "node:path";
import {
  InvalidSessionIdError,
  isValidSessionId,
  readSessionComparison,
  readSessionSnapshot,
  sessionEventsPath
} from "../inspector/session-reader.js";

function decodePathSegment(segment: string | undefined): string {
  if (!segment) return "";
  try {
    return decodeURIComponent(segment);
  } catch {
    return "";
  }
}

function rejectInvalidSessionId(res: ServerResponse): void {
  res.statusCode = 400;
  res.end("Invalid session id");
}

export function startServer(root: string, host: string, port: number): Promise<{ close: () => Promise<void>; url: string }> {
  const server = createServer(async (req, res) => {
    try {
      const url = new URL(req.url ?? "/", `http://${host}:${port}`);
      if (url.pathname === "/") {
        res.setHeader("content-type", "text/html");
        res.end(await readFile(join(root, "dist", "src", "ui", "index.html"), "utf8"));
        return;
      }
      if (url.pathname === "/app.js" || url.pathname === "/projection.js" || url.pathname === "/styles.css") {
        const file = join(root, "dist", "src", "ui", url.pathname.slice(1));
        res.setHeader("content-type", url.pathname.endsWith(".js") ? "text/javascript" : "text/css");
        if (url.pathname === "/projection.js" && !existsSync(file)) {
          res.end("export {};\n");
          return;
        }
        res.end(await readFile(file, "utf8"));
        return;
      }
      if (url.pathname === "/api/sessions/compare") {
        const left = url.searchParams.get("left");
        const right = url.searchParams.get("right");
        if (!left || !right) {
          res.statusCode = 400;
          res.end("Missing left or right session id");
          return;
        }
        if (!isValidSessionId(left) || !isValidSessionId(right)) {
          rejectInvalidSessionId(res);
          return;
        }

        res.setHeader("content-type", "application/json");
        res.end(JSON.stringify(await readSessionComparison(root, left, right)));
        return;
      }
      if (url.pathname.startsWith("/api/sessions/") && url.pathname.endsWith("/snapshot")) {
        const sessionId = decodePathSegment(url.pathname.split("/")[3]);
        if (!isValidSessionId(sessionId)) {
          rejectInvalidSessionId(res);
          return;
        }
        res.setHeader("content-type", "application/json");
        res.end(JSON.stringify(await readSessionSnapshot(root, sessionId)));
        return;
      }
      if (url.pathname.startsWith("/api/sessions/") && url.pathname.endsWith("/events")) {
        const sessionId = decodePathSegment(url.pathname.split("/")[3]);
        if (!isValidSessionId(sessionId)) {
          rejectInvalidSessionId(res);
          return;
        }
        const eventsPath = sessionEventsPath(root, sessionId);

        res.setHeader("content-type", "text/event-stream");
        res.setHeader("cache-control", "no-cache");
        res.setHeader("connection", "keep-alive");

        if (!existsSync(eventsPath)) {
          res.end();
          return;
        }

        // Honor Last-Event-ID for cursor-based resume on reconnect
        const rawResumeId = req.headers["last-event-id"];
        const resumeFromSeq = parseInt(Array.isArray(rawResumeId) ? rawResumeId[0] : (rawResumeId ?? "0"), 10);

        // Send existing events from resume cursor
        const text = await readFile(eventsPath, "utf8");
        for (const line of text.split("\n").filter(Boolean)) {
          try {
            const event = JSON.parse(line) as { seq: number };
            if (event.seq <= resumeFromSeq) continue;
            res.write(`event: alix\nid: ${event.seq}\ndata: ${line}\n\n`);
          } catch {
            // Skip malformed lines
          }
        }

        // Poll for new events
        let lastSize = (await readFile(eventsPath, "utf8")).length;
        const interval = setInterval(async () => {
          if (!existsSync(eventsPath)) {
            clearInterval(interval);
            res.end();
            return;
          }
          try {
            const currentSize = (await readFile(eventsPath, "utf8")).length;
            if (currentSize > lastSize) {
              const newText = (await readFile(eventsPath, "utf8")).slice(lastSize);
              lastSize = currentSize;
              for (const line of newText.split("\n").filter(Boolean)) {
                try {
                  const event = JSON.parse(line) as { seq: number };
                  res.write(`event: alix\nid: ${event.seq}\ndata: ${line}\n\n`);
                } catch {
                  // Skip malformed lines
                }
              }
            }
          } catch {
            clearInterval(interval);
            res.end();
          }
        }, 500);

        req.on("close", () => {
          clearInterval(interval);
        });

        return;
      }
      res.statusCode = 404;
      res.end("Not found");
    } catch (error) {
      if (error instanceof InvalidSessionIdError) {
        rejectInvalidSessionId(res);
        return;
      }
      res.statusCode = 500;
      res.end(error instanceof Error ? error.message : "Internal server error");
    }
  });

  return new Promise((resolve) => {
    server.listen(port, host, () => {
      const address = server.address() as AddressInfo;
      resolve({
        url: `http://${host}:${address.port}`,
        close: () => new Promise((done) => server.close(() => done()))
      });
    });
  });
}

import { readFile, writeFile, stat as statSync, mkdir } from "node:fs/promises";
import { Dirent } from "node:fs";
import { join, relative } from "node:path";
import { existsSync } from "node:fs";
import type { TaskType } from "../task-classifier.js";
import { buildDependencyGraph, type DependencyGraph } from "./dependency-graph.js";
import { extractTopLevelSymbols, type ExtractedSymbol } from "./symbol-extractor.js";
import { readGitActivity } from "./git-activity.js";
import { rankContextCandidate } from "./context-ranker.js";

export type ContextKind = "file" | "symbol" | "test" | "config" | "doc";

export type ContextItem = {
  path: string;
  kind: ContextKind;
  symbolName?: string;
  lineStart?: number;
  lineEnd?: number;
  score: number;
  tokenEstimate: number;
  reason: string;
};

export type ContextBundle = {
  id: string;
  taskType: TaskType;
  budget: {
    maxTokens: number;
    usedTokens: number;
  };
  primaryFiles: ContextItem[];
  supportingFiles: ContextItem[];
  tests: ContextItem[];
  pinned: ContextItem[];
};

type FileEntry = {
  path: string;
  kind: "source" | "test" | "config" | "docs" | "unknown";
  language?: string;
  lineCount?: number;
  content?: string;
};

type RepoMap = {
  sourceFiles: string[];
  testFiles: string[];
  configFiles: string[];
  docsFiles: string[];
  fileEntries: Map<string, FileEntry>;
  dependencyGraph: DependencyGraph;
  symbols: ExtractedSymbol[];
  gitActivity: Map<string, number>;
};

/** Token estimate: ~4 chars per token for English/prose, lower for code. */
function estimateFileTokens(path: string, lineCount: number, isSource: boolean): number {
  const base = isSource ? lineCount * 2 : lineCount * 1.5;
  return Math.ceil(base);
}

/** Extract file paths mentioned in the task string. */
function extractTaskMentions(task: string): string[] {
  const paths: string[] = [];
  const patterns = [
    /["'`]([^\s`]+?\.(?:ts|tsx|js|jsx|py|go|rs|java|kt|json|md|toml|yaml|yml))["'`]/g,
    /(?:^|\s)([\w./-]+\.(?:ts|tsx|js|jsx|py|go|rs|java|kt|cs|rb|php|swift|c|cpp|h|hpp|json|md|toml|yaml|yml))(?=\s|$)/gm,
  ];
  for (const pattern of patterns) {
    let match;
    while ((match = pattern.exec(task)) !== null) {
      paths.push(match[1]);
    }
  }
  return [...new Set(paths)];
}

/** Map a source file to its corresponding test file(s) by naming convention. */
function findTestsFor(path: string, testFiles: string[]): string[] {
  // src/foo.ts → tests/foo.test.ts, tests/foo.spec.ts, test/foo.ts
  // src/auth/handler.ts → tests/auth/handler.test.ts, test/auth/handler.spec.ts
  const normalized = path.replace(/^\.\//, "").replace(/\.(ts|tsx|js|jsx)$/, "");
  const candidates = [
    normalized.replace(/^src\//, "tests/"),
    normalized.replace(/^src\//, "test/"),
    normalized.replace(/\//g, "/"),
  ];
  const results: string[] = [];
  for (const tf of testFiles) {
    const tn = tf.replace(/\.(test|spec)\.(ts|tsx|js|jsx)$/, "").replace(/^tests?\//, "");
    if (candidates.some(c => tn.includes(c) || c.includes(tn))) {
      results.push(tf);
    }
  }
  return results;
}

function isSourceKind(kind: string): boolean {
  return kind === "source";
}

function classifyKind(path: string): FileEntry["kind"] {
  if (/package\.json$|tsconfig\.json$|pyproject\.toml$|Cargo\.toml$|go\.mod$|Makefile$/.test(path)) return "config";
  if (/README|AGENTS\.md$|CLAUDE\.md$|HARNESS\.md$|^docs\//.test(path)) return "docs";
  if (/(\.test\.|\.spec\.|^test\/|^tests\/|__tests__)/.test(path)) return "test";
  if (/\.(ts|tsx|js|jsx|py|go|rs|java|kt|cs|rb|php|swift|c|cpp|h|hpp)$/.test(path)) return "source";
  return "unknown";
}

async function buildRepoMap(root: string): Promise<RepoMap> {
  const { readdir, stat } = await import("node:fs/promises");
  const ignoredDirs = new Set([".git", "node_modules", "dist", "build", "coverage", ".next"]);
  const fileEntries = new Map<string, FileEntry>();
  const sourceFiles: string[] = [];
  const testFiles: string[] = [];
  const configFiles: string[] = [];
  const docsFiles: string[] = [];

  const dirs: string[] = [root];
  while (dirs.length > 0) {
    const current = dirs.pop()!;
    let entries: Dirent[] = [];
    try { entries = await readdir(current, { withFileTypes: true }); } catch { continue; }
    for (const entry of entries) {
      if (entry.isDirectory()) {
        if (ignoredDirs.has(entry.name)) continue;
        dirs.push(join(current, entry.name));
      } else if (entry.isFile()) {
        const fullPath = join(current, entry.name);
        const rel = relative(root, fullPath);
        const kind = classifyKind(rel);
        let info: import("node:fs").Stats;
        try { info = await stat(fullPath); } catch { continue; }
        let content: string | undefined;
        if (info.size < 100_000) {
          try { content = await readFile(fullPath, "utf8"); } catch { /* ignore */ }
        }
        const lineCount = content ? content.split("\n").length : Math.ceil(info.size / 80);
        const fileEntry: FileEntry = { path: rel, kind, lineCount, content };
        fileEntries.set(rel, fileEntry);
        if (kind === "source") sourceFiles.push(rel);
        else if (kind === "test") testFiles.push(rel);
        else if (kind === "config") configFiles.push(rel);
        else if (kind === "docs") docsFiles.push(rel);
      }
    }
  }

  const dependencyGraph = buildDependencyGraph([...fileEntries.values()].map(e => ({ path: e.path, content: e.content })));
  const symbols = [...fileEntries.values()].filter(e => e.kind === "source" && e.content).flatMap(e => extractTopLevelSymbols(e.path, e.content ?? ""));

  return { sourceFiles, testFiles, configFiles, docsFiles, fileEntries, dependencyGraph, symbols, gitActivity: new Map() };
}

/** Score a file for relevance to a task mention. */
function scoreMention(file: string, mentions: string[]): number {
  const normalized = file.replace(/^\.\//, "");
  let best = 0;
  for (const mention of mentions) {
    if (normalized === mention) return 100;
    if (normalized.includes(mention) || mention.includes(normalized)) best = Math.max(best, 70);
    const mentionBase = mention.replace(/\.[^.]+$/, "");
    const fileBase = normalized.replace(/\.[^.]+$/, "");
    if (fileBase === mentionBase) best = Math.max(best, 60);
  }
  return best;
}

export class ContextCompiler {
  private repoMap?: RepoMap;
  private cachePath?: string;
  private cacheTimestamp = 0;

  async warm(root: string): Promise<void> {
    // Check for valid cache first
    this.cachePath = join(root, ".alix", "context-cache.json");
    const cached = await this.loadFromCache(root);
    if (cached) {
      this.repoMap = cached;
      return;
    }
    // Build fresh and cache
    this.repoMap = await buildRepoMap(root);
    await this.saveToCache(root);
  }

  private async loadFromCache(root: string): Promise<RepoMap | null> {
    const cachePath = join(root, ".alix", "context-cache.json");
    try {
      const mtime = (await statSync(cachePath)).mtimeMs;
      const rootMtime = (await statSync(root)).mtimeMs;
      if (mtime < rootMtime) return null; // stale

      const content = await readFile(cachePath, "utf8");
      const data = JSON.parse(content);

      // Verify repo hasn't changed significantly (check top-level dirs)
      const { readdir } = await import("node:fs/promises");
      const entries = await readdir(root, { withFileTypes: true });
      const cacheMtime = data._cacheTime || 0;

      // If any src file is newer than cache, invalidate
      for (const entry of entries) {
        if (entry.name === "src" && entry.isDirectory()) {
          const srcMtime = (await statSync(join(root, "src"))).mtimeMs;
          if (srcMtime > cacheMtime) return null;
        }
      }

      return {
        sourceFiles: data.sourceFiles,
        testFiles: data.testFiles,
        configFiles: data.configFiles,
        docsFiles: data.docsFiles,
        fileEntries: new Map(data.fileEntries),
        dependencyGraph: data.dependencyGraph,
        symbols: data.symbols,
        gitActivity: new Map(data.gitActivity),
      };
    } catch {
      return null;
    }
  }

  private async saveToCache(root: string): Promise<void> {
    if (!this.repoMap || !this.cachePath) return;
    try {
      await mkdir(join(root, ".alix"), { recursive: true });
      const data = {
        _cacheTime: Date.now(),
        sourceFiles: this.repoMap.sourceFiles,
        testFiles: this.repoMap.testFiles,
        configFiles: this.repoMap.configFiles,
        docsFiles: this.repoMap.docsFiles,
        fileEntries: [...this.repoMap.fileEntries.entries()],
        dependencyGraph: this.repoMap.dependencyGraph,
        symbols: this.repoMap.symbols,
        gitActivity: [...this.repoMap.gitActivity.entries()],
      };
      await writeFile(this.cachePath, JSON.stringify(data), "utf8");
    } catch {
      // ignore cache write failures
    }
  }

  async compile(
    task: string,
    taskType: TaskType,
    maxTokens: number,
    pinnedPaths: string[] = []
  ): Promise<ContextBundle> {
    const { fileEntries, sourceFiles, testFiles, configFiles, docsFiles, dependencyGraph, symbols } = this.repoMap ?? await buildRepoMap(process.cwd());

    const mentions = extractTaskMentions(task);

    const items: ContextItem[] = [];

    // 1. Task-mentioned files → primary
    for (const mention of mentions) {
      for (const sf of sourceFiles) {
        const entry = fileEntries.get(sf);
        if (!entry) continue;
        const score = scoreMention(sf, [mention]);
        if (score > 0) {
          items.push({
            path: sf,
            kind: "file",
            score,
            tokenEstimate: estimateFileTokens(sf, entry.lineCount ?? 100, true),
            reason: score >= 100 ? "task_mention_exact" : "task_mention_fuzzy",
          });
        }
      }
    }

    // 2. Config files → supporting
    for (const cf of configFiles) {
      const entry = fileEntries.get(cf);
      if (!entry) continue;
      items.push({
        path: cf,
        kind: "config",
        score: 10,
        tokenEstimate: estimateFileTokens(cf, entry.lineCount ?? 20, false),
        reason: "config_file",
      });
    }

    // 3. Test files related to primary sources → tests
    const primaryPaths = new Set(items.filter(i => i.kind === "file").map(i => i.path));
    for (const pf of primaryPaths) {
      const related = findTestsFor(pf, testFiles);
      for (const tf of related) {
        const entry = fileEntries.get(tf);
        if (!entry) continue;
        items.push({
          path: tf,
          kind: "test",
          score: 40,
          tokenEstimate: estimateFileTokens(tf, entry.lineCount ?? 50, false),
          reason: `test_relationship:${pf}`,
        });
      }
    }

    // 4. Pinned files → always included, highest score
    for (const pinned of pinnedPaths) {
      if (!items.some(i => i.path === pinned)) {
        const entry = fileEntries.get(pinned);
        if (entry) {
          items.push({
            path: pinned,
            kind: entry.kind === "test" ? "test" : entry.kind === "config" ? "config" : "file",
            score: 200,
            tokenEstimate: estimateFileTokens(pinned, entry.lineCount ?? 100, isSourceKind(entry.kind)),
            reason: "pinned",
          });
        }
      }
    }

    // 4b. Dependency-related files for mentioned source files
    const currentPrimaryPaths = new Set(items.filter(i => i.kind === "file").map(i => i.path));
    for (const primaryPath of currentPrimaryPaths) {
      for (const relatedPath of [...dependencyGraph.dependenciesOf(primaryPath), ...dependencyGraph.dependentsOf(primaryPath)]) {
        const entry = fileEntries.get(relatedPath);
        if (!entry || entry.kind !== "source") continue;
        const ranked = rankContextCandidate({
          path: relatedPath,
          baseKind: entry.kind,
          mentionScore: 0,
          dependencyDistance: 1,
          symbolMatched: false,
          relatedTest: false,
          config: false,
          gitTouches: 0,
        });
        items.push({
          path: relatedPath,
          kind: "file",
          score: ranked.score,
          tokenEstimate: estimateFileTokens(relatedPath, entry.lineCount ?? 100, true),
          reason: ranked.reasons.join(","),
        });
      }
    }

    // 4c. Symbol matches — when task mentions a symbol name
    const taskWords = new Set(task.toLowerCase().split(/[^a-zA-Z0-9_$]+/).filter(Boolean));
    for (const symbol of symbols) {
      if (!taskWords.has(symbol.name.toLowerCase())) continue;
      const ranked = rankContextCandidate({
        path: symbol.path,
        baseKind: "source",
        mentionScore: 0,
        dependencyDistance: null,
        symbolMatched: true,
        relatedTest: false,
        config: false,
        gitTouches: 0,
      });
      items.push({
        path: symbol.path,
        kind: "symbol",
        symbolName: symbol.name,
        lineStart: symbol.line,
        lineEnd: symbol.line,
        score: ranked.score,
        tokenEstimate: 20,
        reason: ranked.reasons.join(","),
      });
    }

    // 5. Task type signal — bugfix needs tests more, docs needs docs more
    if (taskType === "bugfix") {
      for (const tf of testFiles.slice(0, 5)) {
        if (!items.some(i => i.path === tf)) {
          const entry = fileEntries.get(tf);
          if (entry) {
            items.push({
              path: tf,
              kind: "test",
              score: 20,
              tokenEstimate: estimateFileTokens(tf, entry.lineCount ?? 50, false),
              reason: "bugfix_hint",
            });
          }
        }
      }
    }

    // Deduplicate by path, keeping highest score
    const deduped = new Map<string, ContextItem>();
    for (const item of items) {
      const existing = deduped.get(item.path);
      if (!existing || item.score > existing.score) {
        deduped.set(item.path, item);
      }
    }
    items.length = 0;
    for (const [, v] of deduped) items.push(v);

    // Sort by score descending
    items.sort((a, b) => b.score - a.score);

    // Budget: fill until maxTokens, then stop
    let usedTokens = 0;
    const budgeted: ContextItem[] = [];
    for (const item of items) {
      if (usedTokens + item.tokenEstimate > maxTokens && budgeted.length > 0) break;
      budgeted.push(item);
      usedTokens += item.tokenEstimate;
    }

    const pinned = budgeted.filter(i => i.reason === "pinned");
    const primary = budgeted.filter(i => (i.kind === "file" || i.kind === "symbol") && i.reason !== "pinned");
    const tests = budgeted.filter(i => i.kind === "test");
    const supporting = budgeted.filter(i => i.kind === "config" || i.kind === "doc");

    return {
      id: `bundle-${Date.now()}`,
      taskType,
      budget: { maxTokens, usedTokens },
      primaryFiles: primary,
      supportingFiles: supporting,
      tests,
      pinned,
    };
  }
}

export type RankInput = {
  path: string;
  baseKind: "source" | "test" | "config" | "docs" | "unknown";
  mentionScore: number;
  dependencyDistance: number | null;
  symbolMatched: boolean;
  relatedTest: boolean;
  config: boolean;
  gitTouches: number;
};

export type RankOutput = {
  score: number;
  reasons: string[];
};

export function rankContextCandidate(input: RankInput): RankOutput {
  let score = 0;
  const reasons: string[] = [];

  if (input.mentionScore > 0) {
    score += input.mentionScore;
    reasons.push(`task_mention:${input.mentionScore}`);
  }
  if (input.dependencyDistance !== null) {
    const dependencyScore = Math.max(0, 30 - input.dependencyDistance * 10);
    if (dependencyScore > 0) {
      score += dependencyScore;
      reasons.push(`dependency_distance:${input.dependencyDistance}`);
    }
  }
  if (input.symbolMatched) {
    score += 25;
    reasons.push("symbol_match");
  }
  if (input.relatedTest) {
    score += 40;
    reasons.push("related_test");
  }
  if (input.config) {
    score += 10;
    reasons.push("config_file");
  }
  if (input.gitTouches > 0) {
    const recencyScore = Math.min(18, input.gitTouches * 6);
    score += recencyScore;
    reasons.push(`git_activity:${input.gitTouches}`);
  }

  return { score, reasons };
}

import { dirname, join, normalize } from "node:path";

export type DependencyInputFile = {
  path: string;
  content?: string;
};

export type DependencyGraph = {
  dependenciesOf(path: string): string[];
  dependentsOf(path: string): string[];
};

const IMPORT_RE = /(?:import\s+(?:[\s\S]*?)\s+from\s+["']([^"']+)["']|export\s+[^"']*from\s+["']([^"']+)["']|import\s*\(\s*["']([^"']+)["']\s*\))/g;
const EXTENSIONS = [".ts", ".tsx", ".js", ".jsx"];

export function buildDependencyGraph(files: DependencyInputFile[]): DependencyGraph {
  const knownPaths = new Set(files.map((file) => normalizePath(file.path)));
  const dependencies = new Map<string, Set<string>>();
  const dependents = new Map<string, Set<string>>();

  for (const file of files) {
    const from = normalizePath(file.path);
    const imports = extractImportSpecifiers(file.content ?? "");
    for (const specifier of imports) {
      if (!specifier.startsWith(".")) continue;
      const resolved = resolveRelativeImport(from, specifier, knownPaths);
      if (!resolved) continue;
      addEdge(dependencies, from, resolved);
      addEdge(dependents, resolved, from);
    }
  }

  return {
    dependenciesOf(path: string) {
      return [...(dependencies.get(normalizePath(path)) ?? [])].sort();
    },
    dependentsOf(path: string) {
      return [...(dependents.get(normalizePath(path)) ?? [])].sort();
    },
  };
}

function extractImportSpecifiers(content: string): string[] {
  const specifiers: string[] = [];
  for (const match of content.matchAll(IMPORT_RE)) {
    const specifier = match[1] ?? match[2] ?? match[3];
    if (specifier) specifiers.push(specifier);
  }
  return specifiers;
}

function resolveRelativeImport(fromPath: string, specifier: string, knownPaths: Set<string>): string | null {
  const base = normalizePath(join(dirname(fromPath), specifier));
  const candidates = [
    base,
    ...EXTENSIONS.map((ext) => `${base}${ext}`),
    ...EXTENSIONS.map((ext) => `${base}/index${ext}`),
  ];
  return candidates.find((candidate) => knownPaths.has(candidate)) ?? null;
}

function addEdge(map: Map<string, Set<string>>, from: string, to: string): void {
  const set = map.get(from) ?? new Set<string>();
  set.add(to);
  map.set(from, set);
}

function normalizePath(path: string): string {
  return normalize(path).replace(/\\/g, "/");
}

import { execFile } from "node:child_process";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

export type GitActivityOptions = {
  maxCommits?: number;
  runGitLog?: () => Promise<string>;
};

export async function readGitActivity(root: string, options: GitActivityOptions = {}): Promise<Map<string, number>> {
  const maxCommits = options.maxCommits ?? 50;
  let output: string;

  try {
    output = options.runGitLog
      ? await options.runGitLog()
      : (await execFileAsync("git", ["log", `--max-count=${maxCommits}`, "--name-only", "--pretty=format:"], { cwd: root })).stdout;
  } catch {
    return new Map();
  }

  const activity = new Map<string, number>();
  for (const line of output.split("\n")) {
    const path = line.trim();
    if (!path || path.includes("\t")) continue;
    activity.set(path, (activity.get(path) ?? 0) + 1);
  }
  return activity;
}

import { readdir, readFile, stat } from "node:fs/promises";
import { join, relative } from "node:path";

export type RepoFileKind = "source" | "test" | "config" | "docs" | "asset" | "unknown";

export type RepoFileSummary = {
  path: string;
  kind: RepoFileKind;
  language?: string;
  sizeBytes: number;
  lineCount?: number;
};

export type SymbolSummary = {
  path: string;
  name: string;
  kind: "function" | "class" | "type" | "interface" | "const" | "unknown";
  line?: number;
};

export type RepoMapLite = {
  root: string;
  generatedAt: string;
  files: RepoFileSummary[];
  configFiles: string[];
  docsFiles: string[];
  testFiles: string[];
  sourceFiles: string[];
  topLevelSymbols: SymbolSummary[];
};

const IGNORED_DIRS = new Set([".git", "node_modules", "dist", "build", "coverage", ".next"]);

export async function buildRepoMapLite(root: string): Promise<RepoMapLite> {
  const paths = await walk(root);
  const files: RepoFileSummary[] = [];
  const topLevelSymbols: SymbolSummary[] = [];

  for (const path of paths) {
    const fullPath = join(root, path);
    let info: Awaited<ReturnType<typeof stat>>;
    try {
      info = await stat(fullPath);
    } catch (err: unknown) {
      if ((err as NodeJS.ErrnoException).code === "ENOENT") continue;
      throw err;
    }
    const text = await readTextIfSmall(fullPath, info.size);
    const lineCount = text ? text.split("\n").length : undefined;
    const kind = classify(path);
    files.push({ path, kind, language: languageFor(path), sizeBytes: info.size, lineCount });
    if (text && kind === "source") {
      topLevelSymbols.push(...extractSymbols(path, text));
    }
  }

  return {
    root,
    generatedAt: new Date().toISOString(),
    files,
    configFiles: files.filter((file) => file.kind === "config").map((file) => file.path),
    docsFiles: files.filter((file) => file.kind === "docs").map((file) => file.path),
    testFiles: files.filter((file) => file.kind === "test").map((file) => file.path),
    sourceFiles: files.filter((file) => file.kind === "source").map((file) => file.path),
    topLevelSymbols
  };
}

async function walk(root: string, dir = root): Promise<string[]> {
  const files: string[] = [];
  const dirs = [dir];
  while (dirs.length > 0) {
    const current = dirs.pop()!;
    const entries = await readdir(current, { withFileTypes: true });
    for (const entry of entries) {
      if (entry.isDirectory() && IGNORED_DIRS.has(entry.name)) continue;
      const fullPath = join(current, entry.name);
      if (entry.isDirectory()) {
        dirs.push(fullPath);
      } else if (entry.isFile()) {
        files.push(relative(root, fullPath));
      }
    }
  }
  return files.sort();
}

async function readTextIfSmall(path: string, size: number): Promise<string | undefined> {
  if (size > 200_000) return undefined;
  try {
    return await readFile(path, "utf8");
  } catch {
    return undefined;
  }
}

function classify(path: string): RepoFileKind {
  if (/package\.json$|tsconfig\.json$|pyproject\.toml$|Cargo\.toml$|go\.mod$|Makefile$/.test(path)) return "config";
  if (/README|AGENTS\.md$|CLAUDE\.md$|HARNESS\.md$|^docs\//.test(path)) return "docs";
  if (/(\.test\.|\.spec\.|^test\/|^tests\/|__tests__)/.test(path)) return "test";
  if (/\.(ts|tsx|js|jsx|py|go|rs|java|kt|cs|rb|php|swift|c|cpp|h|hpp)$/.test(path)) return "source";
  return "unknown";
}

function languageFor(path: string): string | undefined {
  return path.split(".").pop();
}

function extractSymbols(path: string, text: string): SymbolSummary[] {
  const symbols: SymbolSummary[] = [];
  const lines = text.split("\n");
  lines.forEach((line, index) => {
    const match =
      line.match(/export\s+function\s+(\w+)/) ??
      line.match(/function\s+(\w+)/) ??
      line.match(/class\s+(\w+)/) ??
      line.match(/export\s+const\s+(\w+)/);
    if (match) {
      symbols.push({
        path,
        name: match[1],
        kind: line.includes("class") ? "class" : line.includes("const") ? "const" : "function",
        line: index + 1
      });
    }
  });
  return symbols;
}

export type ExtractedSymbolKind = "function" | "class" | "interface" | "type" | "const";

export type ExtractedSymbol = {
  path: string;
  name: string;
  kind: ExtractedSymbolKind;
  line: number;
  signature: string;
};

const SYMBOL_PATTERNS: Array<{ kind: ExtractedSymbolKind; pattern: RegExp }> = [
  { kind: "function", pattern: /^\s*export\s+(?:async\s+)?function\s+([A-Za-z_$][\w$]*)/ },
  { kind: "class", pattern: /^\s*export\s+class\s+([A-Za-z_$][\w$]*)/ },
  { kind: "interface", pattern: /^\s*export\s+interface\s+([A-Za-z_$][\w$]*)/ },
  { kind: "type", pattern: /^\s*export\s+type\s+([A-Za-z_$][\w$]*)/ },
  { kind: "const", pattern: /^\s*export\s+const\s+([A-Za-z_$][\w$]*)/ },
  { kind: "function", pattern: /^\s*(?:async\s+)?function\s+([A-Za-z_$][\w$]*)/ },
  { kind: "class", pattern: /^\s*class\s+([A-Za-z_$][\w$]*)/ },
];

export function extractTopLevelSymbols(path: string, content: string): ExtractedSymbol[] {
  const symbols: ExtractedSymbol[] = [];
  const lines = content.split("\n");

  lines.forEach((line, index) => {
    for (const { kind, pattern } of SYMBOL_PATTERNS) {
      const match = line.match(pattern);
      if (!match) continue;
      symbols.push({
        path,
        name: match[1],
        kind,
        line: index + 1,
        signature: line.trim(),
      });
      break;
    }
  });

  return symbols;
}

import { randomUUID } from "node:crypto";
import { TextDecoder } from "node:util";
import type {
  ModelAdapter,
  NormalizedRequest,
  NormalizedResponse,
  StreamChunk,
  ToolDef,
  ToolCall,
} from "./types.js";
import { ApiError } from "./base.js";

export type AnthropicConfig = {
  apiKey?: string;
  model?: string;
  maxTokens?: number;
};

// Built-in tools exposed to the model
const ALIX_TOOLS: ToolDef[] = [
  {
    name: "file.read",
    description: "Read the contents of a file from the workspace.",
    input_schema: {
      type: "object",
      properties: {
        root: { type: "string", description: "Root directory (defaults to workspace)" },
        path: { type: "string", description: "Relative path to the file" }
      },
      required: ["path"]
    }
  },
  {
    name: "dir.search",
    description: "Search for a pattern across all files in the workspace.",
    input_schema: {
      type: "object",
      properties: {
        root: { type: "string", description: "Root directory (defaults to workspace)" },
        pattern: { type: "string", description: "Text pattern to search for" },
        extensions: { type: "string[]", description: "File extensions to include, e.g. ['.ts', '.js']" }
      },
      required: ["pattern"]
    }
  },
  {
    name: "shell.run",
    description: "Run a shell command in the workspace.",
    input_schema: {
      type: "object",
      properties: {
        command: { type: "string", description: "The shell command to run" },
        cwd: { type: "string", description: "Working directory (defaults to workspace)" },
        timeoutMs: { type: "number", description: "Timeout in milliseconds" }
      },
      required: ["command"]
    }
  },
  {
    name: "patch.apply",
    description: "Apply a code patch to one or more files using search/replace.",
    input_schema: {
      type: "object",
      properties: {
        root: { type: "string", description: "Root directory (defaults to workspace)" },
        format: { type: "string", description: "Patch format: search_replace or structured_patch" },
        patchText: { type: "string", description: "The patch content" }
      },
      required: ["format", "patchText"]
    }
  }
];

export class AnthropicProvider implements ModelAdapter {
  id = "anthropic";
  editFormatPreference = "search_replace" as const;
  longContextStrategy = "trimmed_context" as const;

  private _apiKey: string;
  private _model: string;
  private _maxTokens: number;

  constructor(config: AnthropicConfig = {}) {
    this._apiKey = config.apiKey ?? process.env.ANTHROPIC_API_KEY ?? "";
    this._model = config.model ?? "claude-sonnet-4-6";
    this._maxTokens = config.maxTokens ?? 8192;
  }

  get capabilities() {
    return {
      provider: "anthropic" as const,
      model: this._model,
      inputTokenLimit: 200_000,
      outputTokenLimit: 8192,
      supportsTools: true,
      supportsStreaming: true,
      supportsStructuredOutput: true,
      supportsVision: true
    };
  }

  async complete(request: NormalizedRequest): Promise<NormalizedResponse> {
    if (!this._apiKey) {
      throw new Error("ANTHROPIC_API_KEY is not set");
    }

    const tools = request.tools ?? ALIX_TOOLS;

    const body: Record<string, unknown> = {
      model: this._model,
      max_tokens: this._maxTokens,
      system: request.systemPrompt,
      messages: request.messages.map((m) => ({
        role: m.role,
        content: m.content
      }))
    };

    if (tools.length > 0) {
      body.tools = tools;
    }

    if (request.structuredOutputSchema) {
      body.output = {
        type: "json",
        schema: request.structuredOutputSchema,
      };
    }

    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": this._apiKey,
        "anthropic-version": "2023-06-01"
      },
      body: JSON.stringify(body),
      signal: AbortSignal.timeout(120_000)
    });

    if (!response.ok) {
      const body = await response.text();
      let detail = body;
      try {
        const parsed = JSON.parse(body);
        if (parsed.error?.type === "invalid_request_error") {
          detail = parsed.error.message ?? body;
        }
      } catch { /* not json */ }
      throw new ApiError(response.status, detail);
    }

    const data = (await response.json()) as {
      content: Array<{ type: string; id?: string; name?: string; input?: Record<string, unknown>; text?: string }>;
      stop_reason?: string;
    };

    const toolCalls: ToolCall[] = [];
    let text = "";

    for (const block of data.content) {
      if (block.type === "text") {
        text += block.text ?? "";
      } else if (block.type === "tool_use") {
        toolCalls.push({
          id: block.id ?? randomUUID(),
          name: block.name ?? "",
          args: block.input ?? {}
        });
      }
    }

    return { text: text.trim(), toolCalls };
  }

  async *stream(request: NormalizedRequest): AsyncGenerator<StreamChunk> {
    if (!this._apiKey) throw new Error("ANTHROPIC_API_KEY is not set");

    const tools = request.tools ?? ALIX_TOOLS;
    const body: Record<string, unknown> = {
      model: this._model,
      max_tokens: this._maxTokens,
      system: request.systemPrompt,
      messages: request.messages.map((m) => ({ role: m.role, content: m.content })),
      stream: true,
    };
    if (tools.length > 0) body.tools = tools;

    const res = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": this._apiKey,
        "anthropic-version": "2023-06-01"
      },
      body: JSON.stringify(body),
      signal: AbortSignal.timeout(120_000),
    });

    if (!res.ok) {
      const body = await res.text();
      let detail = body;
      try {
        const parsed = JSON.parse(body);
        if (parsed.error?.type === "invalid_request_error") {
          detail = parsed.error.message ?? body;
        }
      } catch { /* not json */ }
      yield { type: "error" as const, error: detail };
      return;
    }
    if (!res.body) { yield { type: "error" as const, error: "No response body" }; return; }

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";

    let pendingTool: { id: string; name: string; args: string } | null = null;

    while (true) {
      const { done, value } = await reader.read();
      if (done) { yield { type: "done" }; return; }
      buffer += decoder.decode(value, { stream: true });
      const parts = buffer.split("\n\n");
      buffer = parts.pop() ?? "";

      for (const part of parts) {
        const dataLine = part.split("\n").find(l => l.startsWith("data:"));
        if (!dataLine) continue;
        const data = dataLine.slice(5);
        if (data === "[DONE]") { yield { type: "done" }; return; }
        try {
          const event = JSON.parse(data);
          if (event.type === "content_block_start") {
            const block = event.content_block;
            if (block?.type === "tool_use") {
              pendingTool = { id: block.id, name: block.name, args: "" };
            }
          } else if (event.type === "content_block_delta") {
            if (event.delta?.type === "text_delta") {
              yield { type: "text_delta", text: event.delta.text };
            } else if (event.delta?.type === "input_json_delta" && pendingTool) {
              pendingTool.args += event.delta.partial_json ?? "";
            }
          } else if (event.type === "content_block_stop") {
            if (pendingTool) {
              const args = pendingTool.args ? JSON.parse(pendingTool.args) : {};
              yield {
                type: "tool_call" as const,
                toolCall: { id: pendingTool.id, name: pendingTool.name, args }
              };
              pendingTool = null;
            }
          } else if (event.type === "message_delta" && event.usage) {
            yield { type: "usage", usage: { inputTokens: event.usage.input_tokens, outputTokens: event.usage.output_tokens } };
          }
        } catch { /* skip */ }
      }
    }
  }
}

import type { ModelAdapter, ModelCapabilities, NormalizedRequest, NormalizedResponse, StreamChunk, ToolCall } from "./types.js";
import type { EditFormat } from "../patch/edit-format-policy.js";

export class ApiError extends Error {
  constructor(
    public readonly status: number,
    public readonly detail: string
  ) {
    super(`API error ${status}: ${detail}`);
    this.name = "ApiError";
  }
}

export abstract class BaseProvider implements ModelAdapter {
  protected _apiKey: string;
  protected _model: string;
  protected _baseUrl: string;
  protected _timeoutMs: number;

  constructor(options: { apiKey?: string; model: string; baseUrl: string; timeoutMs?: number }) {
    this._apiKey = options.apiKey ?? "";
    this._model = options.model;
    this._baseUrl = options.baseUrl;
    this._timeoutMs = options.timeoutMs ?? 120_000;
  }

  protected async post(body: Record<string, unknown>): Promise<Response> {
    const headers: Record<string, string> = {
      "Content-Type": "application/json",
    };
    if (this._apiKey) {
      headers["Authorization"] = `Bearer ${this._apiKey}`;
    }
    const extra = this.extraHeaders();
    for (const [k, v] of Object.entries(extra)) {
      headers[k] = v;
    }

    return fetch(`${this._baseUrl}/v1/chat/completions`, {
      method: "POST",
      headers,
      body: JSON.stringify({ model: this._model, ...body }),
      signal: AbortSignal.timeout(this._timeoutMs),
    });
  }

  protected extraHeaders(): Record<string, string> {
    return {};
  }

  protected safeToolId(id: string | null | undefined): string {
    return id ?? `call_${Date.now()}_${Math.random().toString(36).slice(2)}`;
  }

  protected parseChoiceToolCalls(choice: { message?: { content?: string | null; tool_calls?: Array<{ id: string; function: { name: string; arguments: string } }> } }): ToolCall[] {
    const message = choice.message;
    // Path 1: message.tool_calls (OpenAI-compatible)
    if (message?.tool_calls?.length) {
      return message.tool_calls.map((tc) => ({
        id: this.safeToolId(tc.id),
        name: tc.function.name ?? "",
        args: tc.function.arguments ? JSON.parse(tc.function.arguments) : {},
      }));
    }
    // Path 2: message.content as array (OpenAI function-calling in content)
    return this.parseOpenAIToolCalls(message?.content);
  }

  // parseOpenAIToolCalls parses content when it's an array of {type:"function", function:{name, arguments}}
  protected parseOpenAIToolCalls(content: unknown): ToolCall[] {
    const toolCalls: ToolCall[] = [];
    if (!Array.isArray(content)) return toolCalls;
    for (const block of content) {
      if (block && typeof block === "object" && "type" in block && block.type === "function" && "function" in block && block.function && typeof block.function === "object") {
        const fn = block.function as { name?: string; arguments?: string };
        toolCalls.push({ id: this.safeToolId(null), name: fn.name ?? "", args: fn.arguments ? JSON.parse(fn.arguments) : {} });
      }
    }
    return toolCalls;
  }

  protected async *streamSSE(res: Response): AsyncGenerator<StreamChunk> {
    if (!res.ok) { yield { type: "error", error: `API error ${res.status}` }; return; }
    if (!res.body) { yield { type: "error", error: "No response body" }; return; }

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";

    // Accumulate tool calls across deltas by index
    const partialTools: Record<number, { id: string; name: string; args: string }> = {};

    while (true) {
      const { done, value } = await reader.read();
      if (done) { yield { type: "done" }; return; }
      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = lines.pop() ?? "";
      for (const line of lines) {
        if (!line.startsWith("data: ")) continue;
        const data = line.slice(6);
        if (data === "[DONE]") { yield { type: "done" }; return; }
        try {
          const event = JSON.parse(data);
          if (event.choices?.[0]?.delta?.content) yield { type: "text_delta", text: event.choices[0].delta.content };

          if (event.choices?.[0]?.delta?.tool_calls) {
            for (const tc of event.choices[0].delta.tool_calls) {
              const idx = tc.index ?? 0;
              if (tc.id && !partialTools[idx]) partialTools[idx] = { id: tc.id, name: "", args: "" };
              if (tc.function?.name) partialTools[idx].name = tc.function.name;
              // arguments can be a string (raw JSON) or already-parsed object
              const rawArgs = tc.function?.arguments;
              if (rawArgs !== undefined) {
                const argsStr = typeof rawArgs === "string" ? rawArgs : JSON.stringify(rawArgs);
                partialTools[idx].args += argsStr;
              }
              // Yield when arguments JSON is complete (ends with })
              const current = partialTools[idx].args.trim();
              if (current.endsWith("}")) {
                const t = partialTools[idx];
                if (t.name) {
                  try {
                    yield { type: "tool_call" as const, toolCall: { id: t.id, name: t.name, args: JSON.parse(t.args) } };
                  } catch { /* incomplete JSON, keep accumulating */ }
                }
                delete partialTools[idx];
              }
            }
          }

          if (event.usage) yield { type: "usage", usage: { inputTokens: event.usage.prompt_tokens, outputTokens: event.usage.completion_tokens } };
        } catch { /* skip */ }
      }
    }
  }

  abstract get capabilities(): ModelCapabilities;
  abstract id: string;
  abstract editFormatPreference: EditFormat;
  abstract longContextStrategy: "expanded_context" | "trimmed_context";
  abstract complete(request: NormalizedRequest): Promise<NormalizedResponse>;
  abstract stream(request: NormalizedRequest): AsyncGenerator<StreamChunk>;
}

