    { id: "zhipuai", name: "ZhipuAI", envKey: "ZHIPUAI_API_KEY" },
    { id: "grokai", name: "GrokAI", envKey: "GROKAI_API_KEY" },
    { id: "deepseek", name: "DeepSeek", envKey: "DEEPSEEK_API_KEY" },
  ];
}

// Message content parts
import type { DeferredToolEntry } from "../mcp/tool-deferral.js";

export type TextPart = {
  type: "text";
  text: string;
};

export type ImagePart = {
  type: "image";
  source: string; // base64 or URL
  mediaType?: string;
};

export type FilePart = {
  type: "file";
  source: string; // base64 or URL
  mediaType: string;
  filename: string;
};

export type ContentPart = TextPart | ImagePart | FilePart;

// Messages
export type NormalizedMessage = {
  role: "user" | "assistant";
  content: string | ContentPart[];
};

// Token usage
export type TokenUsage = {
  inputTokens: number;
  outputTokens: number;
};

// Cost profile
export type CostTier = {
  maxTokens: number;
  pricePerMillion: number;
};

export type CostProfile = {
  currency: string;
  inputPricePerMillion: number;
  outputPricePerMillion: number;
  inputTiers?: CostTier[];
  outputTiers?: CostTier[];
};

// Model capabilities
export type ModelCapabilities = {
  provider: string;
  model: string;
  inputTokenLimit: number;
  outputTokenLimit: number;
  effectiveContextBudget?: number;
  supportsTools: boolean;
  supportsStreaming: boolean;
  supportsStructuredOutput: boolean;
  supportsVision: boolean;
  costProfile?: CostProfile;
};

// Tool definitions
export type ToolParamBase = {
  type: string;
  description?: string;
  enum?: string[];
};

export type ToolParam = ToolParamBase | {
  type: "array";
  description?: string;
  items: { type: string };
};

export type ToolDef = {
  name: string;
  description: string;
  input_schema: {
    type: "object";
    properties: Record<string, ToolParam>;
    required?: string[];
  };
};

// Tool results (returned from tool executions)
export type NormalizedToolResult = {
  toolUseId: string;
  content: string;
};

// Request and response
export type NormalizedRequest = {
  systemPrompt: string;
  messages: NormalizedMessage[];
  tools?: (ToolDef | DeferredToolEntry)[];
  toolResults?: NormalizedToolResult[];
  temperature?: number;
  maxOutputTokens?: number;
  stream?: boolean;  // when true, provider may use streaming response
  structuredOutputSchema?: {
    name: string;
    description?: string;
    properties: Record<string, unknown>;
    required?: string[];
  };
};

export type ToolCall = {
  id: string;
  name: string;
  args: Record<string, unknown>;
};

export type NormalizedResponse = {
  text: string;
  toolCalls: ToolCall[];
  usage?: TokenUsage;
  finishReason?: string;
};

// Streaming chunks
export type StreamChunk =
  | { type: "text_delta"; text: string }
  | { type: "tool_call"; toolCall: ToolCall }
  | { type: "usage"; usage: TokenUsage }
  | { type: "done" }
  | { type: "error"; error: string };

// Negotiated capabilities (result of capability negotiation)
export type NegotiatedCapabilities = {
  contextBudget: number;
  outputBudget: number;
  editFormat: "structured_patch" | "unified_diff" | "search_replace" | "full_file";
  toolsEnabled: boolean;
  structuredOutputEnabled: boolean;
  visionEnabled: boolean;
};

// Model adapter interface
export type ModelAdapter = {
  id: string;
  capabilities: ModelCapabilities;
  editFormatPreference: "structured_patch" | "unified_diff" | "search_replace" | "full_file";
  longContextStrategy: "expanded_context" | "trimmed_context";
  complete(request: NormalizedRequest): Promise<NormalizedResponse>;
  stream?(request: NormalizedRequest): AsyncGenerator<StreamChunk>;
  negotiate?(request: NormalizedRequest): Promise<NegotiatedCapabilities>;
};

import { BaseProvider, ApiError } from "./base.js";
import type { ModelCapabilities, NormalizedRequest, NormalizedResponse, StreamChunk } from "./types.js";

export type ZhipuAIConfig = {
  apiKey?: string;
  model?: string;
};

export class ZhipuAIProvider extends BaseProvider {
  id = "zhipuai";
  editFormatPreference = "search_replace" as const;
  longContextStrategy = "trimmed_context" as const;

  constructor(config: ZhipuAIConfig = {}) {
    super({
      apiKey: config.apiKey ?? process.env.ZHIPUAI_API_KEY ?? "",
      model: config.model ?? "glm-4-flash",
      baseUrl: "https://open.bigmodel.cn",
    });
  }

  get capabilities(): ModelCapabilities {
    return {
      provider: "zhipuai",
      model: this._model,
      inputTokenLimit: 128_000,
      outputTokenLimit: 8_192,
      supportsTools: true,
      supportsStreaming: true,
      supportsStructuredOutput: false,
      supportsVision: false,
    };
  }

  private async fetch(body: Record<string, unknown>): Promise<Response> {
    const headers: Record<string, string> = {
      "Content-Type": "application/json",
    };
    if (this._apiKey) {
      headers["Authorization"] = `Bearer ${this._apiKey}`;
    }
    return fetch(`${this._baseUrl}/api/paas/v4/chat/completions`, {
      method: "POST",
      headers,
      body: JSON.stringify(body),
      signal: AbortSignal.timeout(120_000),
    });
  }

  async complete(request: NormalizedRequest): Promise<NormalizedResponse> {
    if (!this._apiKey) throw new Error("ZHIPUAI_API_KEY is not set");

    const messages: Array<{ role: string; content: string }> = request.messages.map((m) => ({
      role: m.role,
      content: typeof m.content === "string" ? m.content : String(m.content),
    }));

    if (request.systemPrompt) {
      messages.unshift({ role: "system", content: request.systemPrompt });
    }

    const body: Record<string, unknown> = {
      model: this._model,
      messages,
    };

    if (request.tools?.length) {
      body.tools = request.tools.map((t) => ({
        type: "function",
        function: { name: t.name, description: t.description, parameters: t.input_schema },
      }));
    }

    if (request.temperature !== undefined) body.temperature = request.temperature;
    if (request.maxOutputTokens) body.max_tokens = request.maxOutputTokens;

    const response = await this.fetch(body);

    if (!response.ok) {
      const err = await response.text();
      throw new ApiError(response.status, err);
    }

    const data = (await response.json()) as {
      choices: Array<{
        message: {
          content: string | null;
          tool_calls?: Array<{ id: string; function: { name: string; arguments: string } }>;
        };
      }>;
    };

    const choice = data.choices.at(-1)!;
    const toolCalls = this.parseChoiceToolCalls(choice as any);
    let text = "";
    if (typeof choice.message?.content === "string") text = choice.message.content;

    return { text: text.trim(), toolCalls };
  }

  async *stream(request: NormalizedRequest): AsyncGenerator<StreamChunk> {
    if (!this._apiKey) throw new Error("ZHIPUAI_API_KEY is not set");

    const messages: Array<{ role: string; content: string }> = request.messages.map((m) => ({
      role: m.role,
      content: typeof m.content === "string" ? m.content : String(m.content),
    }));
    if (request.systemPrompt) messages.unshift({ role: "system", content: request.systemPrompt });

    const body: Record<string, unknown> = { model: this._model, messages, stream: true };
    if (request.tools?.length) body.tools = request.tools.map((t) => ({ type: "function", function: { name: t.name, description: t.description, parameters: t.input_schema } }));
    if (request.temperature !== undefined) body.temperature = request.temperature;
    if (request.maxOutputTokens) body.max_tokens = request.maxOutputTokens;

    const res = await this.fetch(body);
    if (!res.ok) { yield { type: "error", error: `API error ${res.status}` }; return; }
    if (!res.body) { yield { type: "error", error: "No response body" }; return; }

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";

    while (true) {
      const { done, value } = await reader.read();
      if (done) { yield { type: "done" }; return; }
      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = lines.pop() ?? "";
      for (const line of lines) {
        if (!line.startsWith("data: ")) continue;
        const data = line.slice(6);
        if (data === "[DONE]") { yield { type: "done" }; return; }
        try {
          const event = JSON.parse(data);
          if (event.choices?.[0]?.delta?.content) yield { type: "text_delta", text: event.choices[0].delta.content };
          if (event.choices?.[0]?.delta?.tool_calls) {
            for (const tc of event.choices[0].delta.tool_calls) {
              yield { type: "tool_call", toolCall: { id: tc.id ?? this.safeToolId(null), name: tc.function?.name ?? "", args: tc.function?.arguments ? JSON.parse(tc.function.arguments) : {} } };
            }
          }
          if (event.usage) yield { type: "usage", usage: { inputTokens: event.usage.prompt_tokens, outputTokens: event.usage.completion_tokens } };
        } catch { /* skip */ }
      }
    }
  }
}

import { randomUUID } from "node:crypto";

export type ApprovalStatus = "pending" | "approved" | "denied";

export type Approval = {
  id: string;
  prompt: string;
  status: ApprovalStatus;
};

export class ApprovalQueue {
  private approvals = new Map<string, Approval>();

  request(prompt: string): Approval {
    const approval = { id: randomUUID(), prompt, status: "pending" as const };
    this.approvals.set(approval.id, approval);
    return approval;
  }

  resolve(id: string, status: Exclude<ApprovalStatus, "pending">): Approval {
    const approval = this.approvals.get(id);
    if (!approval) throw new Error(`Unknown approval: ${id}`);
    if (approval.status !== "pending") return approval;
    const resolved = { ...approval, status };
    this.approvals.set(id, resolved);
    return resolved;
  }

  pending(): Approval[] {
    return Array.from(this.approvals.values()).filter((approval) => approval.status === "pending");
  }
}

import type { AlixConfig, Decision, SessionMode } from "../config/schema.js";

export type ToolRequest = {
  toolCallId: string;
  capability: string;
  path?: string;
  command?: string;
};

export type PolicyDecision = {
  decision: Decision;
  reason: string;
};

function applySessionMode(toolDecision: Decision, mode: SessionMode): Decision {
  if (toolDecision === "allow") return "allow";
  if (toolDecision === "deny") return "deny"; // deny always wins, even in bypass
  // toolDecision === "ask"
  if (mode === "auto") return "allow";
  if (mode === "bypass") return "allow";
  return "ask"; // mode === "ask"
}

export function decidePolicy(config: AlixConfig, request: ToolRequest): PolicyDecision {
  if (request.path && isProtectedPath(config.permissions.protectedPaths, request.path)) {
    return { decision: "deny", reason: `Path is protected: ${request.path}` };
  }

  if (request.command && config.permissions.denyCommands.includes(request.command)) {
    return { decision: "deny", reason: `Command is denied: ${request.command}` };
  }

  const toolDecision = config.permissions.tools[request.capability];
  const mode = config.permissions.sessionMode ?? "ask";
  if (toolDecision) {
    const effective = applySessionMode(toolDecision, mode);
    return { decision: effective, reason: `Matched tool policy for ${request.capability} (mode: ${mode})` };
  }

  return { decision: config.permissions.default, reason: "Matched default policy" };
}

function isProtectedPath(patterns: string[], path: string): boolean {
  return patterns.some((pattern) => {
    if (pattern.endsWith("/**")) return path.startsWith(pattern.slice(0, -3));
    if (pattern.endsWith(".*")) return path === pattern.slice(0, -2) || path.startsWith(pattern.slice(0, -1));
    return path === pattern;
  });
}

/**
 * Detect and redact secrets from strings.
 * Used to sanitize tool results, prompts, logs, and UI streams.
 */

const SECRET_PATTERNS: Array<{ pattern: RegExp; label: string }> = [
  // Bearer tokens
  { pattern: /(?<![a-zA-Z0-9])[bB]earer\s+[A-Za-z0-9_\-]{10,}/g, label: "[BEARER_TOKEN]" },
  // Generic API keys (various formats)
  { pattern: /(?<![a-zA-Z0-9])(?:api[_-]?key|apikey|apiSecret|api_secret)\s*[:=]\s*["']?([A-Za-z0-9_\-]{16,})["']?/gi, label: "[API_KEY]" },
  // AWS access keys
  { pattern: /(?<![A-Za-z0-9/])AKIA[0-9A-Z]{16}(?![A-Za-z0-9/])/g, label: "[AWS_KEY]" },
  // AWS secret keys
  { pattern: /(?<![a-zA-Z0-9])[A-Za-z0-9/+=]{40}(?![a-zA-Z0-9/+=])/g, label: "[AWS_SECRET]" },
  // GitHub tokens
  { pattern: /(?<![a-zA-Z0-9])gh[pousr]_[A-Za-z0-9_]{36,}/g, label: "[GITHUB_TOKEN]" },
  // OpenAI / generic sk- keys
  { pattern: /(?<![a-zA-Z0-9])sk-[A-Za-z0-9_\-]{20,}/g, label: "[API_TOKEN]" },
  // Anthropic keys
  { pattern: /(?<![a-zA-Z0-9])sk-ant-[A-Za-z0-9_\-]{30,}/g, label: "[API_TOKEN]" },
  // Google API keys
  { pattern: /(?<![a-zA-Z0-9])AIza[0-9A-Za-z_-]{30,}/g, label: "[API_KEY]" },
  // Private keys (PEM, RSA, EC)
  { pattern: /-----BEGIN\s+(?:RSA\s+)?PRIVATE\s+KEY-----[\s\S]*?-----END\s+(?:RSA\s+)?PRIVATE\s+KEY-----/g, label: "[PRIVATE_KEY]" },
  { pattern: /-----BEGIN\s+EC\s+PRIVATE\s+KEY-----[\s\S]*?-----END\s+EC\s+PRIVATE\s+KEY-----/g, label: "[PRIVATE_KEY]" },
  // JWT tokens
  { pattern: /(?<![a-zA-Z0-9])eyJ[A-Za-z0-9_\-]+\.eyJ[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+(?![a-zA-Z0-9])/g, label: "[JWT_TOKEN]" },
  // Generic secret values (long alphanumeric strings that look like tokens)
  { pattern: /(?<![a-zA-Z0-9])[a-zA-Z0-9_\-]{40,}(?![a-zA-Z0-9])(?=\s|$)/g, label: "[SECRET]" },
  // Connection strings with credentials
  { pattern: /(?:password|passwd|pwd|secret)\s*[:=]\s*["']?([^\s'"]{8,})["']?/gi, label: "[SECRET]" },
];

/**
 * Redact secrets from a string. Returns a new string with secrets replaced by labels.
 */
export function redactSecrets(input: string): string {
  let result = input;
  for (const { pattern, label } of SECRET_PATTERNS) {
    result = result.replace(pattern, label);
  }
  return result;
}

/**
 * Check if a string contains any secrets.
 */
export function containsSecrets(input: string): boolean {
  for (const { pattern } of SECRET_PATTERNS) {
    if (pattern.test(input)) return true;
  }
  return false;
}

export type RedactedValue<T> = {
  original: T;
  redacted: T;
  hadSecrets: boolean;
};

/**
 * Redact secrets from a value, returning both original and redacted versions.
 * Works on strings, arrays of strings, and objects with string values.
 */
export function redactValue<T extends string | string[] | Record<string, unknown>>(value: T): RedactedValue<T> {
  if (typeof value === "string") {
    const redacted = redactSecrets(value);
    return { original: value, redacted: redacted as T, hadSecrets: value !== redacted };
  }
  if (Array.isArray(value)) {
    const redactedArr = value.map((v) => redactSecrets(v));
    const hadSecrets = value.some((v) => v !== redactSecrets(v));
    return { original: value, redacted: redactedArr as T, hadSecrets };
  }
  if (value !== null && typeof value === "object") {
    const redactedObj = Object.fromEntries(
      Object.entries(value as Record<string, unknown>).map(([k, v]) => [
        k,
        typeof v === "string" ? redactSecrets(v) : v,
      ])
    );
    const hadSecrets = Object.values(value as Record<string, unknown>).some(
      (v) => typeof v === "string" && v !== redactSecrets(v)
    );
    return { original: value, redacted: redactedObj as T, hadSecrets };
  }
  return { original: value, redacted: value, hadSecrets: false };
}

export type EditFormat = "structured_patch" | "unified_diff" | "search_replace" | "full_file";

export type EditFormatPolicy = {
  provider: string;
  preferred: EditFormat;
  allowed: EditFormat[];
  fullFileRewrite: "deny" | "ask" | "allow_for_new_or_generated";
};

export type EditFormatPolicyInput = {
  provider: string;
  preferred?: EditFormat;
};

const EXECUTABLE_PATCH_FORMATS: Array<Extract<EditFormat, "structured_patch" | "search_replace">> = [
  "structured_patch",
  "search_replace",
];

export function defaultEditFormatForProvider(provider: string): EditFormat {
  if (["google", "local", "ollama", "minimax", "zhipuai", "grokai"].includes(provider)) {
    return "search_replace";
  }
  return "structured_patch";
}

export function buildEditFormatPolicy(input: EditFormatPolicyInput): EditFormatPolicy {
  const defaultFormat = defaultEditFormatForProvider(input.provider);
  const requested = input.preferred ?? defaultFormat;
  const preferred = normalizePreferredFormat(input.provider, requested);
  const alternate = preferred === "search_replace" ? "structured_patch" : "search_replace";

  return {
    provider: input.provider,
    preferred,
    allowed: [preferred, alternate],
    fullFileRewrite: "deny",
  };
}

function normalizePreferredFormat(provider: string, preferred: EditFormat): Extract<EditFormat, "structured_patch" | "search_replace"> {
  if (provider === "google") return "search_replace";
  if (preferred === "full_file") return "search_replace";
  if (EXECUTABLE_PATCH_FORMATS.includes(preferred as Extract<EditFormat, "structured_patch" | "search_replace">)) {
    return preferred as Extract<EditFormat, "structured_patch" | "search_replace">;
  }
  const fallback = defaultEditFormatForProvider(provider);
  return fallback === "search_replace" ? "search_replace" : "structured_patch";
}

import { createHash } from "node:crypto";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import type { EditFormat } from "./edit-format-policy.js";
import { applySearchReplace, parseSearchReplace, validateSearchReplace } from "./search-replace.js";
import { parseStructuredPatch } from "./structured-patch.js";
import { validatePatchOperations, DEFAULT_PATCH_GUARD_CONFIG, type PatchOperation } from "./patch-guard.js";

export type PatchApplyResult = {
  status: "applied" | "invalid";
  changedFiles: string[];
};

export async function applyPatch(root: string, format: EditFormat, patchText: string): Promise<PatchApplyResult> {
  if (format === "search_replace") {
    const blocks = parseSearchReplace(patchText);
    if (blocks.length === 0) throw new Error("No patch changes found");
    const ops: PatchOperation[] = blocks.map((b) => ({ path: b.path, operation: "modify" as const, content: b.replace }));
    const result = validatePatchOperations(ops, DEFAULT_PATCH_GUARD_CONFIG);
    if (!result.valid) throw new Error("Patch blocked by safety guard: " + result.reason);
    const plannedWrites: Array<{ path: string; content: string }> = [];
    for (const block of blocks) {
      const path = resolvePatchPath(root, block.path);
      const content = await readFile(path, "utf8");
      validateSearchReplace(content, block);
      plannedWrites.push({ path, content: applySearchReplace(content, block) });
    }
    for (const write of plannedWrites) {
      await writeFile(write.path, write.content, "utf8");
    }
    return { status: "applied", changedFiles: blocks.map((block) => block.path) };
  }

  if (format === "structured_patch") {
    const patch = parseStructuredPatch(patchText);
    if (patch.files.length === 0) throw new Error("No patch changes found");
    const ops: PatchOperation[] = patch.files.map((f) => ({
      path: f.path,
      operation: f.operation,
      content: f.content,
    }));
    const result = validatePatchOperations(ops, DEFAULT_PATCH_GUARD_CONFIG);
    if (!result.valid) throw new Error("Patch blocked by safety guard: " + result.reason);
    const changedFiles: string[] = [];
    for (const file of patch.files) {
      const path = resolvePatchPath(root, file.path);
      if (file.operation === "modify") {
        const content = await readFile(path, "utf8");
        if (!file.preimageHash || sha256(content) !== file.preimageHash) {
          throw new Error(`Preimage validation failed for ${file.path}`);
        }
      }
      if (file.operation === "delete" && file.preimageHash) {
        const content = await readFile(path, "utf8");
        if (sha256(content) !== file.preimageHash) throw new Error(`Preimage validation failed for ${file.path}`);
      }
    }
    for (const file of patch.files) {
      const path = resolvePatchPath(root, file.path);
      if (file.operation === "modify") {
        await writeFile(path, file.content ?? "", "utf8");
        changedFiles.push(file.path);
      }
      if (file.operation === "create") {
        await mkdir(dirname(path), { recursive: true });
        await writeFile(path, file.content ?? "", "utf8");
        changedFiles.push(file.path);
      }
      if (file.operation === "delete") {
        const path = resolvePatchPath(root, file.path);
        const { rm } = await import("node:fs/promises");
        await rm(path);
        changedFiles.push(file.path);
      }
    }
    return { status: "applied", changedFiles };
  }

  throw new Error(`Unsupported edit format: ${format}`);
}

export function sha256(content: string): string {
  return createHash("sha256").update(content).digest("hex");
}

function resolvePatchPath(root: string, patchPath: string): string {
  const resolvedRoot = resolve(root);
  const resolvedPath = resolve(resolvedRoot, patchPath);
  if (resolvedPath !== resolvedRoot && !resolvedPath.startsWith(`${resolvedRoot}/`)) {
    throw new Error(`Patch path is outside workspace: ${patchPath}`);
  }
  return resolvedPath;
}

export type PatchOperation = {
  path: string;
  operation: "modify" | "create" | "delete";
  content?: string;
};

export type PatchGuardConfig = {
  protectedPaths: string[];
  maxFileSizeBytes: number;
};

export type ValidationResult = {
  valid: boolean;
  reason?: string;
};

export function isProtectedPath(patterns: string[], path: string): boolean {
  return patterns.some((pattern) => {
    if (pattern.endsWith("/**")) {
      const prefix = pattern.slice(0, -3);
      return path === prefix || path.startsWith(prefix + "/");
    }
    if (pattern.endsWith(".*")) return path === pattern.slice(0, -2) || path.startsWith(pattern.slice(0, -1));
    return path === pattern;
  });
}

export function isPathSafe(path: string): boolean {
  if (path.startsWith("..")) return false;
  if (path.startsWith("/")) return false;
  if (path.includes("../")) return false;
  if (path.startsWith("~")) return false;
  if (path.startsWith("$")) return false;
  return true;
}

export const DEFAULT_PATCH_GUARD_CONFIG: PatchGuardConfig = {
  protectedPaths: [".git/**", ".env", ".env.*", "secrets/**"],
  maxFileSizeBytes: 10 * 1024 * 1024,
};

export function validatePatchOperations(ops: PatchOperation[], config: PatchGuardConfig): ValidationResult {
  for (const op of ops) {
    if (!isPathSafe(op.path)) {
      return { valid: false, reason: `Path is unsafe: ${op.path}` };
    }

    if (isProtectedPath(config.protectedPaths, op.path)) {
      return { valid: false, reason: `Path is protected: ${op.path}` };
    }

    if (op.content !== undefined) {
      const sizeBytes = new TextEncoder().encode(op.content).length;
      if (sizeBytes > config.maxFileSizeBytes) {
        return { valid: false, reason: `Content exceeds max file size: ${op.path}` };
      }
    }
  }

  return { valid: true };
}

export function extractPatchPaths(format: string | undefined, patchTextValue: unknown): string[] {
  const patchText = typeof patchTextValue === "string" ? patchTextValue : "";
  const paths = new Set<string>();

  if (format === "structured_patch") {
    try {
      const parsed = JSON.parse(patchText) as { files?: Array<{ path?: unknown }> };
      for (const file of parsed.files ?? []) {
        if (typeof file.path === "string" && file.path.length > 0) paths.add(file.path);
      }
    } catch {
      // Invalid patches are rejected by the patch engine later. Scope extraction should not hide that error.
    }
  }

  for (const match of patchText.matchAll(/<<<<<<< SEARCH path=([^\s\n]+)/g)) {
    paths.add(match[1]);
  }

  for (const match of patchText.matchAll(/^[+-]{3} (?:[ab]\/)?(.+)$/gm)) {
    const path = match[1].trim();
    if (path && path !== "/dev/null") paths.add(path);
  }

  return [...paths];
}

export type SearchReplaceBlock = {
  path: string;
  search: string;
  replace: string;
};

const BLOCK_RE = /<<<<<<< SEARCH path=(.+?)\n([\s\S]*?)\n=======\n([\s\S]*?)\n>>>>>>> REPLACE/g;

export function parseSearchReplace(input: string): SearchReplaceBlock[] {
  const blocks: SearchReplaceBlock[] = [];
  for (const match of input.matchAll(BLOCK_RE)) {
    blocks.push({ path: match[1].trim(), search: match[2], replace: match[3] });
  }
  return blocks;
}

export function applySearchReplace(content: string, block: SearchReplaceBlock): string {
  validateSearchReplace(content, block);
  const first = content.indexOf(block.search);
  return content.slice(0, first) + block.replace + content.slice(first + block.search.length);
}

export function validateSearchReplace(content: string, block: SearchReplaceBlock): void {
  const first = content.indexOf(block.search);
  if (first === -1) throw new Error(`Search block not found for ${block.path}`);
  const second = content.indexOf(block.search, first + block.search.length);
  if (second !== -1) throw new Error(`Search block is ambiguous for ${block.path}`);
}

export type StructuredPatch = {
  version: 1;
  files: StructuredPatchFile[];
};

export type StructuredPatchFile = {
  path: string;
  operation: "create" | "modify" | "delete";
  preimageHash?: string;
  content?: string;
};

export function parseStructuredPatch(input: string): StructuredPatch {
  const parsed = JSON.parse(input) as StructuredPatch;
  if (parsed.version !== 1) throw new Error("Unsupported structured patch version");
  if (!Array.isArray(parsed.files)) throw new Error("Structured patch requires files");
  return parsed;
}

import type { McpServerCapabilities, Tool } from "./types.js";

export type MappedPolicyRule = {
  id: string;
  capability: string;
  effect: "allow" | "ask" | "deny";
  reason: string;
};

export function mapServerCapabilities(
  serverName: string,
  capabilities: McpServerCapabilities,
  tools: Tool[]
): MappedPolicyRule[] {
  const rules: MappedPolicyRule[] = [];

  // Default rule for the entire server — always "ask"
  rules.push({
    id: `mcp:${serverName}:default`,
    capability: `mcp.${serverName}.*`,
    effect: "ask",
    reason: `MCP server '${serverName}' — requires explicit approval`
  });

  // Per-tool rules
  if (capabilities.tools) {
    for (const tool of tools) {
      const safeName = tool.name.replace(/[^a-zA-Z0-9_]/g, "_");
      rules.push({
        id: `mcp:${serverName}:tool:${safeName}`,
        capability: `mcp.${serverName}.${safeName}`,
        effect: "ask",
        reason: `Tool '${tool.name}' from MCP server '${serverName}'`
      });
    }
  }

  return rules;
}

import type { JsonRpcRequest, JsonRpcResponse, JsonRpcNotification, McpServerCapabilities, Tool, CallToolResult } from "./types.js";
import type { McpTransport } from "./transport.js";

const PROTOCOL_VERSION = "2024-11-05";

export class McpClient {
  private transport: McpTransport;
  private pendingRequests = new Map<string, { resolve: (v: JsonRpcResponse) => void; reject: (e: Error) => void }>();
  private messageId = 0;
  private _capabilities: McpServerCapabilities | null = null;
  private _tools: Tool[] = [];
  private _serverInfo: { name: string; version: string } | null = null;

  constructor(transport: McpTransport) {
    this.transport = transport;
    transport.onMessage((msg) => this.handleMessage(msg));
  }

  async initialize(clientName = "alix", clientVersion = "1.0"): Promise<McpServerCapabilities> {
    await this.transport.connect();

    const result = await this.transport.send({
      jsonrpc: "2.0",
      id: this.nextId(),
      method: "initialize",
      params: {
        protocolVersion: PROTOCOL_VERSION,
        capabilities: { tools: {}, resources: {}, prompts: {} },
        clientInfo: { name: clientName, version: clientVersion }
      }
    });

    if ("error" in result && result.error) {
      throw new Error(`Initialize failed: ${result.error.message}`);
    }

    const init = result.result as { protocolVersion: string; capabilities: McpServerCapabilities; serverInfo: { name: string; version: string } };
    this._capabilities = init.capabilities;
    this._serverInfo = { name: init.serverInfo.name, version: init.serverInfo.version };

    // Send initialized notification
    await this.transport.sendNotification({
      jsonrpc: "2.0",
      method: "notifications/initialized",
      params: {}
    });

    return init.capabilities;
  }

  async listTools(): Promise<Tool[]> {
    if (this._tools.length > 0) return this._tools;

    const result = await this.transport.send({
      jsonrpc: "2.0",
      id: this.nextId(),
      method: "tools/list",
      params: {}
    });

    if ("error" in result && result.error) {
      throw new Error(`tools/list failed: ${result.error.message}`);
    }

    const list = result.result as { tools: Tool[] };
    this._tools = list.tools ?? [];
    return this._tools;
  }

  async callTool(name: string, args: Record<string, unknown> = {}): Promise<CallToolResult> {
    const result = await this.transport.send({
      jsonrpc: "2.0",
      id: this.nextId(),
      method: "tools/call",
      params: { name, arguments: args }
    });

    if ("error" in result && result.error) {
      throw new Error(`tools/call failed: ${result.error.message}`);
    }

    return result.result as CallToolResult;
  }

  get capabilities(): McpServerCapabilities | null { return this._capabilities; }
  get serverInfo(): { name: string; version: string } | null { return this._serverInfo; }
  get tools(): Tool[] { return this._tools; }

  async close(): Promise<void> { await this.transport.close(); }

  private handleMessage(msg: JsonRpcResponse | JsonRpcNotification): void {
    if ("id" in msg && msg.id !== undefined) {
      const pending = this.pendingRequests.get(String(msg.id));
      if (pending) {
        this.pendingRequests.delete(String(msg.id));
        if ("error" in msg && msg.error) {
          pending.reject(new Error(msg.error.message));
        } else {
          pending.resolve(msg as JsonRpcResponse);
        }
      }
    }
  }

  private nextId(): string { return String(++this.messageId); }
}

import type { AlixConfig } from "../config/schema.js";
import type { McpServerConfig } from "../config/schema.js";
import type { ToolResult } from "../tools/types.js";
import { McpToolRegistry, RegisteredTool } from "./registry.js";
import { ProcessManager } from "./process-manager.js";
import { McpClient } from "./client.js";
import { mapServerCapabilities, type MappedPolicyRule } from "./capability-mapper.js";

import { McpToolDeferral } from "./tool-deferral.js";

export class McpManager {
  private registry: McpToolRegistry;
  private processManager: ProcessManager;
  private capabilityRules = new Map<string, MappedPolicyRule[]>();
  private _deferral: McpToolDeferral | null = null;

  constructor(private config: AlixConfig) {
    this.registry = new McpToolRegistry();
    this.processManager = new ProcessManager();
  }

  async initialize(): Promise<void> {
    const servers = this.config.mcpServers ?? [];

    for (const serverConfig of servers) {
      try {
        await this.connectServer(serverConfig);
      } catch (err) {
        console.error(`[McpManager] Failed to connect to server '${serverConfig.name}':`, err instanceof Error ? err.message : String(err));
      }
    }

    if (this.config.mcpServerPaths) {
      for (const path of this.config.mcpServerPaths) {
        try {
          await this.autoDiscoverServer(path);
        } catch (err) {
          console.error(`[McpManager] Auto-discover failed for '${path}':`, err instanceof Error ? err.message : String(err));
        }
      }
    }
  }

  private async connectServer(config: McpServerConfig): Promise<void> {
    try {
      await this.registry.registerServer(config);
    } catch (err) {
      // Remove any partial state left behind by a failed registration
      this.registry.closeServer(config.name);
      throw err;
    }

    const client = this.registry.getClient(config.name);
    if (!client) return;

    if (this._deferral) {
      this._deferral.clearServerCache(config.name);
    }

    const tools = await client.listTools();
    if (client.capabilities) {
      const rules = mapServerCapabilities(config.name, client.capabilities, tools);
      this.capabilityRules.set(config.name, rules);
    }
  }

  private async autoDiscoverServer(path: string): Promise<void> {
    const config: McpServerConfig & { type: "stdio" } = {
      type: "stdio",
      name: path,
      command: "npx",
      args: ["--yes", path]
    };

    try {
      await this.connectServer(config);
    } catch {
      const directConfig: McpServerConfig & { type: "stdio" } = {
        type: "stdio",
        name: path,
        command: path
      };
      try {
        await this.connectServer(directConfig);
      } catch {
        // Both failed — skip silently
      }
    }
  }

  async callTool(fullName: string, args: Record<string, unknown>): Promise<ToolResult> {
    return this.registry.callTool(fullName, args);
  }

  listTools(): RegisteredTool[] {
    return this.registry.listTools();
  }

  listServers(): string[] {
    return this.registry.listMcpServers();
  }

  getCapabilityRules(): MappedPolicyRule[] {
    return [...this.capabilityRules.values()].flat();
  }

  getClient(serverName: string): McpClient | undefined {
    return this.registry.getClient(serverName);
  }

  getDeferral(cacheOptions?: { ttlMs?: number; maxSize?: number }): McpToolDeferral {
    if (!this._deferral) this._deferral = new McpToolDeferral(this.registry, cacheOptions);
    return this._deferral;
  }

  async closeServer(name: string): Promise<void> {
    await this.registry.closeServer(name);
    this.capabilityRules.delete(name);
    if (this._deferral) this._deferral.clearServerCache(name);
  }

    async discoverServer(packageName: string): Promise<{ name: string; version: string; toolCount: number; toolNames: string[] }> {
    const config: McpServerConfig & { type: "stdio" } = {
      type: "stdio",
      name: packageName,
      command: "uvx",
      args: [packageName]
    };
    try {
      await this.connectServer(config);
    } catch {
      // Fall back to npx
      const npxConfig: McpServerConfig & { type: "stdio" } = {
        type: "stdio",
        name: packageName,
        command: "npx",
        args: ["--yes", packageName]
      };
      try {
        await this.connectServer(npxConfig);
      } catch {
        throw new Error(`Could not connect to '${packageName}'. Is it a valid MCP server package?`);
      }
    }
    const client = this.registry.getClient(packageName);
    if (!client?.serverInfo) throw new Error(`Connected but no server info for '${packageName}'`);
    const tools = await client.listTools();
    return {
      name: client.serverInfo.name,
      version: client.serverInfo.version,
      toolCount: tools.length,
      toolNames: tools.map((t) => t.name)
    };
  }

  async closeAll(): Promise<void> {
    await this.processManager.closeAll();
    // Close any discoverServer-ad-hoc clients that are tracked in the registry
    // but not managed by processManager (e.g. discoverServer's temp processes).
    for (const name of this.registry.listMcpServers()) {
      await this.registry.closeServer(name);
    }
  }
}

import { spawn } from "node:child_process";
import type { ChildProcess } from "node:child_process";
import type { McpServerConfig } from "../config/schema.js";
import { McpClient } from "./client.js";
import { StdioTransport } from "./transports/stdio-transport.js";

export class ProcessManager {
  private processes = new Map<string, {
    proc: ChildProcess;
    transport: StdioTransport;
    client: McpClient;
    lastUsed: number;
  }>();

  async getOrCreate(
    name: string,
    config: McpServerConfig & { type: "stdio" }
  ): Promise<McpClient> {
    const existing = this.processes.get(name);
    if (existing) {
      existing.lastUsed = Date.now();
      return existing.client;
    }

    const proc = spawn(config.command, config.args ?? [], {
      stdio: ["pipe", "pipe", "pipe"],
      env: { ...process.env, ...config.env }
    });

    const transport = new StdioTransport(name, proc);
    const client = new McpClient(transport);
    await client.initialize();

    this.processes.set(name, {
      proc,
      transport,
      client,
      lastUsed: Date.now()
    });

    return client;
  }

  async closeServer(name: string): Promise<void> {
    const entry = this.processes.get(name);
    if (!entry) return;

    await entry.transport.close();
    entry.proc.kill();
    this.processes.delete(name);
  }

  async closeIdle(timeoutMs = 300_000): Promise<void> {
    const now = Date.now();
    for (const [name, entry] of this.processes) {
      if (now - entry.lastUsed > timeoutMs) {
        await this.closeServer(name);
      }
    }
  }

  async closeAll(): Promise<void> {
    for (const name of [...this.processes.keys()]) {
      await this.closeServer(name);
    }
  }

  listActiveServers(): string[] {
    return [...this.processes.keys()];
  }
}

import type { McpServerConfig } from "../config/schema.js";
import type { McpTransport } from "./transport.js";
import type { Tool } from "./types.js";
import type { ToolResult } from "../tools/types.js";
import { McpClient } from "./client.js";
import { StdioTransport } from "./transports/stdio-transport.js";
import { HttpTransport } from "./transports/http-transport.js";
import { WebSocketTransport } from "./transports/websocket-transport.js";
import { spawn } from "node:child_process";

export interface RegisteredTool {
  fullName: string;     // e.g., "github/repos.list"
  serverName: string;  // e.g., "github"
  toolName: string;     // e.g., "repos.list"
  description?: string;
  inputSchema: Record<string, unknown>;
  isMcp: boolean;
}

export class McpToolRegistry {
  private tools = new Map<string, RegisteredTool>();
  private clients = new Map<string, McpClient>();

  createTransport(config: McpServerConfig): McpTransport {
    switch (config.type) {
      case "stdio": {
        const proc = spawn(config.command, config.args ?? [], {
          stdio: ["pipe", "pipe", "pipe"],
          env: { ...process.env, ...config.env }
        });
        return new StdioTransport(config.name, proc);
      }
      case "http":
        return new HttpTransport(config.name, config.url, config.headers);
      case "websocket":
        return new WebSocketTransport(config.name, config.url, config.headers);
    }
  }

  async registerServer(config: McpServerConfig): Promise<void> {
    const transport = this.createTransport(config);
    const client = new McpClient(transport);
    // Let errors propagate — McpManager catches them per-server
    await client.initialize();

    this.clients.set(config.name, client);

    const tools = await client.listTools();
    for (const tool of tools) {
      // MCP servers may prefix tool.name with server name (e.g. "fetch/fetch").
      // Strip the prefix so fullName is always "server/tool" without duplication.
      const cleanName = tool.name.startsWith(`${config.name}/`)
        ? tool.name.slice(config.name.length + 1)
        : tool.name;
      const fullName = `${config.name}/${cleanName}`;
      this.tools.set(fullName, {
        fullName,
        serverName: config.name,
        toolName: cleanName,
        description: tool.description,
        inputSchema: tool.inputSchema as Record<string, unknown>,
        isMcp: true
      });
    }
  }

  getTool(fullName: string): RegisteredTool | undefined {
    return this.tools.get(fullName);
  }

  listTools(): RegisteredTool[] {
    return [...this.tools.values()];
  }

  listMcpServers(): string[] {
    return [...this.clients.keys()];
  }

  getClient(serverName: string): McpClient | undefined {
    return this.clients.get(serverName);
  }

  async callTool(fullName: string, args: Record<string, unknown>): Promise<ToolResult> {
    const tool = this.tools.get(fullName);
    if (!tool) {
      return { kind: "error", message: `Unknown MCP tool: ${fullName}` };
    }

    const client = this.clients.get(tool.serverName);
    if (!client) {
      return { kind: "error", message: `MCP server '${tool.serverName}' is not connected` };
    }

    try {
      const result = await client.callTool(tool.toolName, args);
      const content = result.content
        .map(c => c.type === "text" ? c.text ?? "" : JSON.stringify(c))
        .join("\n");

      return result.isError
        ? { kind: "error", message: content }
        : { kind: "success", output: content };
    } catch (e) {
      return { kind: "error", message: e instanceof Error ? e.message : String(e) };
    }
  }

  async closeServer(name: string): Promise<void> {
    const client = this.clients.get(name);
    if (client) {
      await client.close();
      this.clients.delete(name);
    }

    for (const key of [...this.tools.keys()]) {
      if (key.startsWith(`${name}/`)) {
        this.tools.delete(key);
      }
    }
  }
}

import type { ToolDef } from "../providers/types.js";

export type SchemaCacheOptions = {
  ttlMs?: number;    // evict entries older than this (default: no TTL)
  maxSize?: number;  // evict oldest when size exceeds this (default: no limit)
};

interface CacheEntry {
  schema: ToolDef;
  timestamp: number;
}

/**
 * Session-scoped cache for resolved MCP tool schemas.
 * Eviction: TTL-based (by timestamp) and/or LRU-style (by access order).
 */
export class SchemaCache {
  private cache = new Map<string, CacheEntry>();
  private accessOrder: string[] = []; // LRU order

  constructor(private options: SchemaCacheOptions = {}) {}

  get(name: string): ToolDef | undefined {
    const entry = this.cache.get(name);
    if (!entry) return undefined;

    // Check TTL
    if (this.options.ttlMs !== undefined) {
      if (Date.now() - entry.timestamp > this.options.ttlMs) {
        this.cache.delete(name);
        this.accessOrder = this.accessOrder.filter(k => k !== name);
        return undefined;
      }
    }

    // Update LRU order
    this.accessOrder = this.accessOrder.filter(k => k !== name);
    this.accessOrder.push(name);

    return entry.schema;
  }

  set(name: string, schema: ToolDef): void {
    // Evict oldest if at capacity
    if (this.options.maxSize !== undefined && this.cache.size >= this.options.maxSize) {
      const oldest = this.accessOrder.shift();
      if (oldest) {
        this.cache.delete(oldest);
      }
    }

    this.cache.set(name, { schema, timestamp: Date.now() });
    this.accessOrder = this.accessOrder.filter(k => k !== name);
    this.accessOrder.push(name);
  }

  has(name: string): boolean {
    // Check TTL on has() too
    if (this.options.ttlMs !== undefined) {
      const entry = this.cache.get(name);
      if (entry && Date.now() - entry.timestamp > this.options.ttlMs) {
        this.cache.delete(name);
        this.accessOrder = this.accessOrder.filter(k => k !== name);
        return false;
      }
    }
    return this.cache.has(name);
  }

  clearPrefix(prefix: string): void {
    for (const key of [...this.cache.keys()]) {
      if (key.startsWith(prefix)) {
        this.cache.delete(key);
        this.accessOrder = this.accessOrder.filter(k => k !== key);
      }
    }
  }

  get size(): number {
    return this.cache.size;
  }

  get maxSize(): number | undefined {
    return this.options.maxSize;
  }

  clear(): void {
    this.cache.clear();
    this.accessOrder = [];
  }
}

import type { McpToolRegistry, RegisteredTool } from "./registry.js";
import type { ToolDef } from "../providers/types.js";
import { SchemaCache } from "./tool-cache.js";
import { searchTools, type SearchResult } from "./tool-search.js";

export interface DeferredToolEntry {
  name: string;       // mcp_github_repos_list — what the model uses
  execName: string;  // mcp.github.repos.list — internal executor name
  serverName: string;
  toolName: string;
  description: string;
  input_schema?: { type: "object"; properties: Record<string, unknown> };
  [key: string]: string | number | boolean | object | undefined;
}

/**
 * McpToolDeferral manages lazy loading of MCP tool schemas.
 *
 * At session start: only names + descriptions are sent to the model (lightweight).
 * On tool call: full ToolDef is resolved from cache or registry and cached.
 * On unknown name: fuzzy search finds the closest match.
 */
export class McpToolDeferral {
  private cache: SchemaCache;
  private _index: DeferredToolEntry[] | null = null;
  private _usedTools = new Set<string>();
  private _discoveredTools = new Set<string>();

  constructor(private registry: McpToolRegistry, private cacheOptions?: { ttlMs?: number; maxSize?: number }) {
    this.cache = new SchemaCache(this.cacheOptions);
  }

  /**
   * Build the deferred tool index — names + descriptions only.
   * Called once at session start; result is sent to the model.
   */
  buildIndex(): DeferredToolEntry[] {
    if (this._index) return this._index;
    this._index = this.registry.listTools().map(tool => ({
      name: mcpToolName(tool.serverName, tool.toolName),
      execName: mcpToolExecName(tool.serverName, tool.toolName),
      serverName: tool.serverName,
      toolName: tool.toolName,
      description: tool.description ?? "",
      input_schema: { type: "object" as const, properties: {} },
    }));
    return this._index;
  }

  /**
   * Resolve the full ToolDef for a tool the model called.
   * Uses cache first; on miss, builds from registry and caches.
   */
  resolve(mcpName: string): ToolDef | undefined {
    if (this.cache.has(mcpName)) return this.cache.get(mcpName)!;

    const entry = this.findEntry(mcpName);
    if (!entry) return undefined;

    const tool = this.registry.getTool(`${entry.serverName}/${entry.toolName}`);
    if (!tool) return undefined;

    const def: ToolDef = {
      name: entry.name,
      description: entry.description,
      input_schema: tool.inputSchema as ToolDef["input_schema"],
    };

    this.cache.set(mcpName, def);
    this._usedTools.add(mcpName);
    return def;
  }

  /**
   * Fallback search when model uses an unknown or misspelled tool name.
   * Returns top matches from the deferred index.
   */
  search(query: string, limit = 3): SearchResult<DeferredToolEntry>[] {
    const results = searchTools(query, this.buildIndex()).slice(0, limit);
    for (const r of results) {
      this._discoveredTools.add(r.item.name);
    }
    return results;
  }

  /**
   * Clear schema cache for a server (called when server reconnects with new schemas).
   */
  clearServerCache(serverName: string): void {
    this.cache.clearPrefix(`mcp_${serverName}_`);
    this._index = null;
  }

  getUsedTools(): string[] { return [...this._usedTools]; }
  getDiscoveredTools(): string[] { return [...this._discoveredTools]; }

  private findEntry(name: string): DeferredToolEntry | undefined {
    const idx = this.buildIndex();
    return idx.find(e =>
      e.name === name ||
      e.execName === name ||
      `${e.serverName}/${e.toolName}` === name
    );
  }
}

function mcpToolName(serverName: string, toolName: string): string {
  return "mcp_" + serverName + "_" + toolName.replace(/\./g, "_");
}

function mcpToolExecName(serverName: string, toolName: string): string {
  return "mcp." + serverName + "." + toolName;
}

import type { DeferredToolEntry } from "./tool-deferral.js";
import { searchTools } from "./tool-search.js";
import type { ToolResult } from "../tools/types.js";

export class ToolDiscovery {
  constructor(private allTools: DeferredToolEntry[]) {}

  async search(query: string): Promise<ToolResult> {
    if (!query.trim()) {
      const list = this.allTools.map(t => `  - ${t.name}: ${t.description}`).join("\n");
      return {
        kind: "success",
        output: `Available ${this.allTools.length} MCP tools:\n${list}`,
      };
    }

    const matches = searchTools(query, this.allTools).slice(0, 10);

    if (matches.length === 0) {
      return {
        kind: "success",
        output: `No tools found matching "${query}". Try a different keyword.`,
      };
    }

    const lines = matches.map(m =>
      `  - ${m.item.name}: ${m.item.description}\n    Use as: ${m.item.execName}`
    );
    return {
      kind: "success",
      output: `Found ${matches.length} tool(s) matching "${query}":\n${lines.join("\n")}\n\nThese tools are now available for use.`,
    };
  }
}

export interface SearchResult<T> {
  item: T;
  score: number; // higher = better match, 0 = no match
}

/**
 * Simple Levenshtein distance (no external dep).
 */
function levenshtein(a: string, b: string): number {
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;
  const matrix: number[][] = [];
  for (let i = 0; i <= b.length; i++) matrix[i] = [i];
  for (let j = 0; j <= a.length; j++) matrix[0][j] = j;
  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      const cost = b[i - 1] === a[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,      // deletion
        matrix[i][j - 1] + 1,      // insertion
        matrix[i - 1][j - 1] + cost // substitution
      );
    }
  }
  return matrix[b.length][a.length];
}

interface ScoredTool {
  name: string;
  description: string;
  [key: string]: string | number | boolean | object | undefined;
}

/**
 * Search tools by fuzzy matching on name and description.
 * Scoring: exact prefix > substring > Levenshtein distance.
 * Returns results sorted by score descending.
 */
export function searchTools<T extends ScoredTool>(
  query: string,
  tools: T[],
  options: { nameField?: string; descriptionField?: string } = {}
): SearchResult<T>[] {
  const nameField = options.nameField ?? "name";
  const descField = options.descriptionField ?? "description";
  const q = query.toLowerCase();

  const results: SearchResult<T>[] = [];

  // If query exactly matches a tool name, return just that result
  for (const tool of tools) {
    const name = String(tool[nameField] ?? "").toLowerCase();
    if (name === q) {
      return [{ item: tool, score: 100 }];
    }
  }

  for (const tool of tools) {
    const name = String(tool[nameField] ?? "").toLowerCase();
    const desc = String(tool[descField] ?? "").toLowerCase();

    let score = 0;

    const nameExact = name === q;
    const namePrefix = name.startsWith(q);
    const nameSubstring = name.includes(q);
    const descExact = desc === q;
    const descPrefix = desc.startsWith(q);
    const descSubstring = desc.includes(q);

    // Exact match
    if (nameExact || descExact) {
      score = 100;
    }
    // Exact prefix (name only, not desc to avoid double-counting)
    else if (namePrefix) {
      score = 80;
    }
    // Substring anywhere
    else if (nameSubstring || descSubstring) {
      score = 50 + (nameSubstring ? 10 : 0);
    }
    // Levenshtein — only if lengths are similar enough
    else {
      const maxLen = Math.max(name.length, q.length);
      if (maxLen > 0 && maxLen <= 30 && Math.abs(name.length - q.length) <= 5) {
        const dist = levenshtein(name, q);
        const relative = dist / maxLen;
        if (relative <= 0.5) score = Math.round((1 - relative) * 40);
      }
    }

    if (score > 0) {
      results.push({ item: tool, score });
    }
  }

  return results.sort((a, b) => b.score - a.score);
}

import type { DeferredToolEntry } from "./tool-deferral.js";

const SAFE_FALLBACK_NAMES = ["filesystem_read", "fetch_get", "files_read", "http_request"];

export type ToolSelectorOptions = {
  maxTools: number;
  tokenBudget: number;
  preferKeywordScoring?: boolean;
};

// Floor estimate — individual tools may exceed this for complex schemas.
const MIN_TOKENS_PER_TOOL = 25;

export class ToolSelector {
  private computeNgrams(text: string, n: number = 2): Set<string> {
    const words = text.toLowerCase().split(/\W+/).filter(w => w.length >= 2);
    const ngrams = new Set<string>();
    for (let i = 0; i <= words.length - n; i++) {
      ngrams.add(words.slice(i, i + n).join(" "));
    }
    return ngrams;
  }

  private jaccardSimilarity(a: Set<string>, b: Set<string>): number {
    if (a.size === 0 && b.size === 0) return 0;
    let intersection = 0;
    for (const item of a) {
      if (b.has(item)) intersection++;
    }
    const union = a.size + b.size - intersection;
    return union === 0 ? 0 : intersection / union;
  }

  constructor(
    private tools: DeferredToolEntry[],
    private options: ToolSelectorOptions
  ) {}

  select(taskDescription: string): DeferredToolEntry[] {
    const { maxTools, tokenBudget, preferKeywordScoring } = this.options;
    const maxByBudget = Math.floor(tokenBudget / MIN_TOKENS_PER_TOOL);
    const effectiveMax = Math.min(maxTools, maxByBudget, this.tools.length);

    if (effectiveMax >= this.tools.length) return [...this.tools];

    const taskWords = new Set(
      taskDescription.toLowerCase().split(/\W+/).filter(w => w.length >= 2)
    );

    const scored = this.tools.map(tool => {
      const nameParts = tool.name.toLowerCase().split(/[_\.]/);
      const descWords = new Set(
        tool.description.toLowerCase().split(/\W+/).filter(w => w.length >= 2)
      );

      let score = 0;
      for (const word of taskWords) {
        if (nameParts.includes(word)) {
          score += 3;
        } else if (tool.name.toLowerCase().includes(word)) {
          score += 1;
        }
        if (descWords.has(word)) score += 1;
      }

      // Semantic scoring using n-gram similarity (disabled when preferKeywordScoring)
      if (!preferKeywordScoring) {
        const taskNgrams = this.computeNgrams(taskDescription);
        const descNgrams = this.computeNgrams(tool.description);
        const semanticScore = this.jaccardSimilarity(taskNgrams, descNgrams);
        score += Math.round(semanticScore * 2);
      }

      return { tool, score };
    });

    scored.sort((a, b) => {
      if (b.score !== a.score) return b.score - a.score;
      return a.tool.serverName.localeCompare(b.tool.serverName);
    });

    let result = scored.slice(0, effectiveMax);

    const hasFallback = result.some(t =>
      SAFE_FALLBACK_NAMES.some(fb => t.tool.name.includes(fb))
    );
    if (!hasFallback) {
      // Build index map for O(1) lookup by object reference
      const scoredIndex = new Map(scored.map((s, i) => [s, i]));
      const fallback = scored.find(s =>
        SAFE_FALLBACK_NAMES.some(fb => s.tool.name.includes(fb))
      );
      if (fallback) {
        if (result.length < effectiveMax) {
          result.push(fallback);
        } else {
          // Insert fallback: keep at most effectiveMax items total
          const fallbackIdx = scoredIndex.get(fallback) ?? -1;
          // Replace the last item if fallback is ranked after effectiveMax-1
          if (fallbackIdx >= effectiveMax) {
            if (effectiveMax > 0) {
              result[effectiveMax - 1] = fallback;
            }
          }
        }
      }
    }

    return result.map(s => s.tool);
  }
}

import type { JsonRpcRequest, JsonRpcResponse, JsonRpcNotification } from "./types.js";
import type { McpTransportType } from "../config/schema.js";

export interface McpTransport {
  readonly name: string;
  readonly type: McpTransportType;

  connect(): Promise<void>;
  send(message: JsonRpcRequest): Promise<JsonRpcResponse>;
  sendNotification(message: JsonRpcNotification): Promise<void>;
  onMessage(handler: (message: JsonRpcResponse | JsonRpcNotification) => void): void;
  close(): Promise<void>;
}

// JSON-RPC 2.0 base types
export interface JsonRpcRequest {
  jsonrpc: "2.0";
  id: number | string;
  method: string;
  params?: Record<string, unknown>;
}

export interface JsonRpcResponse {
  jsonrpc: "2.0";
  id: number | string;
  result?: unknown;
  error?: JsonRpcError;
}

export interface JsonRpcError {
  code: number;
  message: string;
  data?: unknown;
}

export interface JsonRpcNotification {
  jsonrpc: "2.0";
  method: string;
  params?: Record<string, unknown>;
}

// MCP protocol types
export interface McpServerCapabilities {
  tools?: { listChanged?: boolean };
  resources?: { subscribe?: boolean; listChanged?: boolean };
  prompts?: { listChanged?: boolean };
}

export interface JsonSchema {
  type?: string;
  properties?: Record<string, JsonSchema>;
  required?: string[];
  additionalProperties?: boolean | JsonSchema;
  items?: JsonSchema;
