import type { JsonRpcRequest, JsonRpcResponse, JsonRpcNotification } from "../../mcp/types.js";
import type { McpTransport } from "../../mcp/transport.js";
import type { McpTransportType } from "../../config/schema.js";

export class HttpTransport implements McpTransport {
  readonly name: string;
  readonly type: McpTransportType = "http";

  private url: string;
  private headers: Record<string, string>;
  private messageHandler: ((msg: JsonRpcResponse | JsonRpcNotification) => void) | null = null;

  constructor(name: string, url: string, headers: Record<string, string> = {}) {
    this.name = name;
    this.url = url;
    this.headers = headers;
  }

  async connect(): Promise<void> {
    // HTTP transport connects lazily on first request
  }

  async send(message: JsonRpcRequest): Promise<JsonRpcResponse> {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 60_000);

    try {
      const response = await fetch(`${this.url}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          ...this.headers
        },
        body: JSON.stringify(message),
        signal: controller.signal
      });

      clearTimeout(timeout);

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`HTTP ${response.status}: ${errorText}`);
      }

      const contentType = response.headers.get("content-type") ?? "";

      if (contentType.includes("text/event-stream")) {
        return await this.handleSSEStream(response);
      }

      const data = await response.json() as JsonRpcResponse;
      return data;
    } catch (err) {
      clearTimeout(timeout);
      if (err instanceof Error && err.name === "AbortError") {
        throw new Error(`Request timed out after 60s`);
      }
      throw err;
    }
  }

  private async handleSSEStream(response: Response): Promise<JsonRpcResponse> {
    const reader = response.body?.getReader();
    if (!reader) throw new Error("No response body");

    let buffer = "";
    const decoder = new TextDecoder();
    let result: JsonRpcResponse | null = null;

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = lines.pop() ?? "";

      for (const line of lines) {
        if (line.startsWith("data: ")) {
          const data = line.slice(6).trim();
          if (data && data !== "[DONE]") {
            try {
              const msg = JSON.parse(data) as JsonRpcResponse | JsonRpcNotification;
              this.messageHandler?.(msg);
              if ("result" in msg && !("error" in msg) && !result) {
                result = msg as JsonRpcResponse;
              }
            } catch {}
          }
        }
      }
    }

    return result ?? { jsonrpc: "2.0", id: "", result: {} };
  }

  async sendNotification(message: JsonRpcNotification): Promise<void> {
    fetch(`${this.url}`, {
      method: "POST",
      headers: { "Content-Type": "application/json", ...this.headers },
      body: JSON.stringify(message)
    }).catch(() => {}); // best effort
  }

  onMessage(handler: (message: JsonRpcResponse | JsonRpcNotification) => void): void {
    this.messageHandler = handler;
  }

  async close(): Promise<void> {
    // HTTP is stateless — nothing to close
  }
}

import type { ChildProcess } from "node:child_process";
import type { JsonRpcRequest, JsonRpcResponse, JsonRpcNotification } from "../../mcp/types.js";
import type { McpTransport } from "../../mcp/transport.js";
import type { McpTransportType } from "../../config/schema.js";

export class StdioTransport implements McpTransport {
  readonly name: string;
  readonly type: McpTransportType = "stdio";

  private proc: ChildProcess;
  private messageHandler: ((msg: JsonRpcResponse | JsonRpcNotification) => void) | null = null;
  private readBuffer = "";

  constructor(name: string, proc: ChildProcess) {
    this.name = name;
    this.proc = proc;

    // Collect stderr for logging
    proc.stderr?.on("data", (chunk: Buffer) => {
      console.error(`[MCP:${name} stderr] ${chunk.toString().trim()}`);
    });

    // Single stdout listener handles all routing.
    // Pending requests check pendingCallbacks by ID first; everything else
    // is forwarded to the messageHandler (notifications, stray messages).
    proc.stdout?.on("data", (chunk: Buffer) => {
      this.readBuffer += chunk.toString();
      const lines = this.readBuffer.split("\n");
      this.readBuffer = lines.pop() ?? "";
      for (const line of lines) {
        if (!line.trim()) continue;
        try {
          const msg = JSON.parse(line) as JsonRpcResponse | JsonRpcNotification;
          // Route request responses to their pending callbacks
          if ("id" in msg && msg.id !== undefined) {
            const id = String(msg.id);
            const pending = this.pendingCallbacks.get(id);
            if (pending) {
              this.pendingCallbacks.delete(id);
              pending.resolve(msg as JsonRpcResponse);
              continue;
            }
          }
          this.messageHandler?.(msg);
        } catch {
          // Skip malformed JSON
        }
      }
    });

    proc.on("exit", (code) => {
      if (code !== 0 && code !== null) {
        console.error(`[MCP:${name}] process exited with code ${code}`);
      }
    });
  }

  async connect(): Promise<void> {
    // stdio processes connect immediately on spawn
  }

  async send(message: JsonRpcRequest): Promise<JsonRpcResponse> {
    return new Promise((resolve, reject) => {
      if (!this.proc.stdin) {
        reject(new Error("stdin not available"));
        return;
      }

      const id = String(message.id);
      const timeout = setTimeout(() => {
        reject(new Error(`Request ${id} timed out after 10s`));
      }, 10_000);

      this.pendingCallbacks.set(id, {
        resolve: (msg: JsonRpcResponse) => {
          clearTimeout(timeout);
          this.pendingCallbacks.delete(id);
          if ("error" in msg && msg.error) {
            reject(new Error(msg.error.message));
          } else {
            resolve(msg);
          }
        },
        reject: (err: Error) => {
          clearTimeout(timeout);
          this.pendingCallbacks.delete(id);
          reject(err);
        }
      });

      const msgStr = JSON.stringify(message) + "\n";
      const flushed = this.proc.stdin.write(msgStr);
      if (!flushed) {
        // Back-pressure: absorb the drain event. We only care that the write
        // eventually reaches the kernel buffer — not the timing.
        this.proc.stdin.once("drain", () => {});
      }

      // If the process is already dead, reject now to avoid hanging.
      // Otherwise register a one-time exit handler to reject if it dies later.
      if (this.proc.exitCode !== null && this.proc.exitCode !== 0) {
        clearTimeout(timeout);
        this.pendingCallbacks.delete(id);
        reject(new Error(`Request ${id} failed: process exited with code ${this.proc.exitCode}`));
      } else {
        this.proc.once("exit", () => {
          clearTimeout(timeout);
          this.pendingCallbacks.delete(id);
          reject(new Error(`Request ${id} failed: process exited`));
        });
      }
    });
  }

  private pendingCallbacks = new Map<string, {
    resolve: (msg: JsonRpcResponse) => void;
    reject: (err: Error) => void;
  }>();

  async sendNotification(message: JsonRpcNotification): Promise<void> {
    return new Promise((resolve, reject) => {
      if (!this.proc.stdin) {
        resolve();
        return;
      }
      const msgStr = JSON.stringify(message) + "\n";
      this.proc.stdin.write(msgStr, (err) => {
        if (err) reject(err);
        else resolve();
      });
    });
  }

  onMessage(handler: (message: JsonRpcResponse | JsonRpcNotification) => void): void {
    this.messageHandler = handler;
  }

  async close(): Promise<void> {
    // Kill the process first — this forces the OS to close its pipes.
    // After kill, the process is guaranteed to exit (either immediately or on the
    // next event loop tick), so we don't need to wait for the "exit" event.
    this.proc.kill();
    this.proc.stdin?.destroy();
    this.proc.stdout?.destroy();
    this.proc.stderr?.destroy();
    // The process is dead. No need to wait — destroy() closes the pipes and kill()
    // ensures the OS delivers SIGTERM. Returning immediately lets callers proceed.
  }
}

import type { JsonRpcRequest, JsonRpcResponse, JsonRpcNotification } from "../../mcp/types.js";
import type { McpTransport } from "../../mcp/transport.js";
import type { McpTransportType } from "../../config/schema.js";

export class WebSocketTransport implements McpTransport {
  readonly name: string;
  readonly type: McpTransportType = "websocket";

  private url: string;
  private headers: Record<string, string>;
  private messageHandler: ((msg: JsonRpcResponse | JsonRpcNotification) => void) | null = null;
  private ws: WebSocket | null = null;
  private pendingRequests = new Map<string, { resolve: (v: JsonRpcResponse) => void; reject: (e: Error) => void; timeout: ReturnType<typeof setTimeout> }>();
  private messageId = 0;
  private reconnectDelay = 1000;
  private maxReconnectDelay = 30_000;
  private shouldReconnect = true;

  constructor(name: string, url: string, headers: Record<string, string> = {}) {
    this.name = name;
    this.url = url;
    this.headers = headers;
  }

  async connect(): Promise<void> {
    return new Promise((resolve, reject) => {
      this.ws = new WebSocket(this.url, {
        headers: this.headers
      });

      this.ws.onopen = () => {
        this.reconnectDelay = 1000;
        resolve();
      };

      this.ws.onmessage = (event) => {
        try {
          const msg = JSON.parse(event.data as string) as JsonRpcResponse | JsonRpcNotification;
          this.messageHandler?.(msg);

          if ("id" in msg && msg.id !== undefined) {
            const id = String(msg.id);
            const pending = this.pendingRequests.get(id);
            if (pending) {
              clearTimeout(pending.timeout);
              this.pendingRequests.delete(id);
              if ("error" in msg && msg.error) {
                pending.reject(new Error(msg.error.message));
              } else {
                pending.resolve(msg as JsonRpcResponse);
              }
            }
          }
        } catch {}
      };

      this.ws.onerror = () => {
        // error logged via onclose
      };

      this.ws.onclose = () => {
        if (this.shouldReconnect && this.reconnectDelay <= this.maxReconnectDelay) {
          setTimeout(() => {
            this.reconnectDelay = Math.min(this.reconnectDelay * 2, this.maxReconnectDelay);
            this.connect().catch(() => {});
          }, this.reconnectDelay);
        }
      };

      setTimeout(() => reject(new Error("WebSocket connection timeout")), 30_000);
    });
  }

  async send(message: JsonRpcRequest): Promise<JsonRpcResponse> {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
      await this.connect();
    }

    return new Promise((resolve, reject) => {
      const id = String(message.id ?? ++this.messageId);
      const timeout = setTimeout(() => {
        this.pendingRequests.delete(id);
        reject(new Error(`Request ${id} timed out`));
      }, 60_000);

      this.pendingRequests.set(id, { resolve, reject, timeout });
      this.ws!.send(JSON.stringify({ ...message, id }));
    });
  }

  async sendNotification(message: JsonRpcNotification): Promise<void> {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;
    this.ws.send(JSON.stringify(message));
  }

  onMessage(handler: (message: JsonRpcResponse | JsonRpcNotification) => void): void {
    this.messageHandler = handler;
  }

  async close(): Promise<void> {
    this.shouldReconnect = false;
    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }
    for (const [, pending] of this.pendingRequests) {
      clearTimeout(pending.timeout);
      pending.reject(new Error("Connection closed"));
    }
    this.pendingRequests.clear();
  }
}

import type { AlixEvent, InspectorComparison, InspectorContextItem, InspectorSnapshot } from "../events/types.js";

type UnknownRecord = Record<string, unknown>;

function asRecord(value: unknown): UnknownRecord {
  return value && typeof value === "object" ? (value as UnknownRecord) : {};
}

function optionalString(value: unknown): string | undefined {
  return typeof value === "string" ? value : undefined;
}

function stringArray(value: unknown): string[] {
  return Array.isArray(value) ? value.filter((item): item is string => typeof item === "string") : [];
}

function contextItems(value: unknown): InspectorContextItem[] {
  if (!Array.isArray(value)) return [];
  return value.filter((item): item is InspectorContextItem => {
    const record = asRecord(item);
    return typeof record.path === "string" && typeof record.kind === "string";
  });
}

function commandFromPayload(payload: UnknownRecord): string | undefined {
  const argsPreview = asRecord(payload.argsPreview);
  return optionalString(argsPreview.command);
}

function findByToolCallId<T extends { toolCallId?: string }>(items: T[], toolCallId: string | undefined): T | undefined {
  return toolCallId ? items.find((item) => item.toolCallId === toolCallId) : undefined;
}

function statusForEndedSession(reason: string | undefined): InspectorSnapshot["summary"]["status"] {
  return reason === "completed" ? "completed" : "failed";
}

function verificationSummary(snapshot: InspectorSnapshot): string {
  if (snapshot.verification.length === 0) return "none";

  const statuses = new Set(snapshot.verification.map((item) => item.status ?? "unknown"));
  if (statuses.size === 1) {
    const [status] = statuses;
    return status ?? "unknown";
  }
  return "mixed";
}

function changedFileSet(snapshot: InspectorSnapshot): Set<string> {
  return new Set(snapshot.diffs.flatMap((diff) => diff.changedFiles));
}

function sortedValues(values: Iterable<string>): string[] {
  return [...values].sort((left, right) => left.localeCompare(right));
}

function checkpointFilesFromPayload(payload: UnknownRecord): string[] {
  const files = stringArray(payload.files);
  return files.length > 0 ? files : stringArray(payload.checkpointFiles);
}

export function buildInspectorSnapshot(sessionId: string, events: AlixEvent[]): InspectorSnapshot {
  const snapshot: InspectorSnapshot = {
    sessionId,
    summary: {
      eventCount: events.length,
      status: "unknown",
      latestSeq: events.at(-1)?.seq
    },
    timeline: events,
    diffs: [],
    terminal: [],
    approvals: [],
    verification: [],
    tokens: {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      entries: []
    }
  };

  for (const event of events) {
    const payload = asRecord(event.payload);
    const toolCallId = optionalString(payload.toolCallId);
    const toolName = optionalString(payload.toolName);

    switch (event.type) {
      case "session.started":
        snapshot.summary.status = "running";
        snapshot.summary.startedAt ??= event.timestamp;
        break;
      case "session.ended": {
        const reason = optionalString(payload.reason);
        snapshot.summary.status = statusForEndedSession(reason);
        snapshot.summary.reason = reason;
        snapshot.summary.endedAt = event.timestamp;
        break;
      }
      case "context.bundle_compiled": {
        const budget = asRecord(payload.budget);
        const maxTokens = budget.maxTokens;
        const usedTokens = budget.usedTokens;
        snapshot.context = {
          taskType: optionalString(payload.taskType),
          budget:
            typeof maxTokens === "number" && typeof usedTokens === "number"
              ? { maxTokens, usedTokens }
              : undefined,
          primaryFiles: contextItems(payload.primaryFiles),
          tests: contextItems(payload.tests),
          supportingFiles: contextItems(payload.supportingFiles),
          pinned: contextItems(payload.pinned)
        };
        break;
      }
      case "tool.requested":
        if (toolName === "shell.run") {
          const command = commandFromPayload(payload);
          if (command) snapshot.terminal.push({ toolCallId, command });
        }
        break;
      case "tool.completed":
      case "tool.failed":
        if (toolName === "shell.run") {
          const terminal = findByToolCallId(snapshot.terminal, toolCallId);
          if (terminal) {
            const status = optionalString(payload.status);
            const outputPreview = optionalString(payload.outputPreview);
            const error = optionalString(payload.error);
            if (status) terminal.status = status;
            if (outputPreview) terminal.outputPreview = outputPreview;
            if (error) terminal.error = error;
          }
        }
        if (toolName === "patch.apply") {
          const changedFiles = stringArray(payload.changedFiles);
          const existing = findByToolCallId(snapshot.diffs, toolCallId);
          if (existing) {
            existing.changedFiles = changedFiles.length > 0 ? changedFiles : existing.checkpointFiles;
            existing.status = event.type === "tool.failed" ? "failed" : "applied";
          } else {
            snapshot.diffs.push({
              toolCallId,
              changedFiles,
              checkpointFiles: [],
              rolledBack: false,
              status: event.type === "tool.failed" ? "failed" : "applied"
            });
          }
        }
        break;
      case "patch.checkpoint_created":
        snapshot.diffs.push({
          toolCallId,
          changedFiles: [],
          checkpointFiles: checkpointFilesFromPayload(payload),
          rolledBack: false,
          status: "checkpointed"
        });
        break;
      case "patch.rollback_completed": {
        const diff = findByToolCallId(snapshot.diffs, toolCallId);
        if (diff) {
          diff.rolledBack = true;
          diff.status = "rolled_back";
        }
        break;
      }
      case "autonomy.scope_expansion":
        snapshot.approvals.push({ toolCallId, toolName, paths: stringArray(payload.paths), status: "pending" });
        break;
      case "autonomy.scope_approved":
      case "autonomy.scope_auto_approved":
      case "autonomy.scope_denied":
      case "autonomy.scope_skipped": {
        const status = event.type.replace("autonomy.scope_", "");
        snapshot.approvals.push({
          toolCallId,
          toolName,
          paths: stringArray(payload.paths),
          status: status === "auto_approved" ? "auto_approved" : (status as "approved" | "denied" | "skipped")
        });
        break;
      }
      case "verification.check_started": {
        const command = optionalString(payload.command);
        if (command) {
          snapshot.verification.push({ command, reason: optionalString(payload.reason), status: "running" });
        }
        break;
      }
      case "verification.check_finished": {
        const command = optionalString(payload.command);
        if (command) {
          const check = snapshot.verification.findLast((item) => item.command === command && item.status === "running");
          const finished = check ?? snapshot.verification[snapshot.verification.push({ command }) - 1];
          finished.status = optionalString(payload.status);
          finished.output = optionalString(payload.output);
        }
        break;
      }
      case "model.usage": {
        const inputTokens = typeof payload.inputTokens === "number" ? payload.inputTokens : 0;
        const outputTokens = typeof payload.outputTokens === "number" ? payload.outputTokens : 0;
        snapshot.tokens.totalInputTokens += inputTokens;
        snapshot.tokens.totalOutputTokens += outputTokens;
        snapshot.tokens.entries.push({
          provider: optionalString(payload.provider),
          model: optionalString(payload.model),
          inputTokens,
          outputTokens
        });
        break;
      }
    }
  }

  return snapshot;
}

export type SubagentEvent = {
  type: "subagent.started" | "subagent.completed" | "subagent.failed";
  subagentId: string;
  role: string;
  timestamp: string;
  duration?: number;
  status?: "success" | "failed";
};

export function projectSubagentEvents(events: AlixEvent[]): SubagentEvent[] {
  return events
    .filter(e => e.actor === "subagent" && e.type.startsWith("subagent."))
    .map(e => {
      const payload = e.payload as Record<string, unknown>;
      return {
        type: e.type as SubagentEvent["type"],
        subagentId: String(payload?.subagentId ?? ""),
        role: String(payload?.role ?? ""),
        timestamp: e.timestamp,
        duration: e.type === "subagent.completed"
          ? new Date(e.timestamp).getTime() - new Date(events.find(x => x.type === "subagent.started" && (x.payload as Record<string, unknown>)?.subagentId === payload?.subagentId)?.timestamp ?? e.timestamp).getTime()
          : undefined,
        status: e.type === "subagent.completed" ? "success" : e.type === "subagent.failed" ? "failed" : undefined,
      };
    });
}

export function compareInspectorSnapshots(left: InspectorSnapshot, right: InspectorSnapshot): InspectorComparison {
  const leftFiles = changedFileSet(left);
  const rightFiles = changedFileSet(right);

  return {
    leftSessionId: left.sessionId,
    rightSessionId: right.sessionId,
    changedFilesOnlyLeft: sortedValues([...leftFiles].filter((file) => !rightFiles.has(file))),
    changedFilesOnlyRight: sortedValues([...rightFiles].filter((file) => !leftFiles.has(file))),
    changedFilesBoth: sortedValues([...leftFiles].filter((file) => rightFiles.has(file))),
    verificationStatus: { left: verificationSummary(left), right: verificationSummary(right) },
    tokenDelta: {
      inputTokens: right.tokens.totalInputTokens - left.tokens.totalInputTokens,
      outputTokens: right.tokens.totalOutputTokens - left.tokens.totalOutputTokens
    }
  };
}

import { readFile } from "node:fs/promises";
import { join } from "node:path";
import type { AlixEvent, InspectorComparison, InspectorSnapshot } from "../events/types.js";
import { buildInspectorSnapshot, compareInspectorSnapshots } from "./projection.js";

const SESSION_ID_PATTERN = /^[A-Za-z0-9][A-Za-z0-9._-]*$/;

export class InvalidSessionIdError extends Error {
  constructor(readonly sessionId: string) {
    super("Invalid session id");
    this.name = "InvalidSessionIdError";
  }
}

export function isValidSessionId(sessionId: string): boolean {
  return SESSION_ID_PATTERN.test(sessionId) && !sessionId.includes("..");
}

export function assertValidSessionId(sessionId: string): string {
  if (!isValidSessionId(sessionId)) throw new InvalidSessionIdError(sessionId);
  return sessionId;
}

export function sessionEventsPath(root: string, sessionId: string): string {
  return join(root, ".alix", "sessions", assertValidSessionId(sessionId), "events.jsonl");
}

export async function readSessionEvents(root: string, sessionId: string): Promise<AlixEvent[]> {
  try {
    const text = await readFile(sessionEventsPath(root, sessionId), "utf8");
    return text
      .split("\n")
      .filter((line) => line.trim().length > 0)
      .map((line) => JSON.parse(line) as AlixEvent);
  } catch (error) {
    if (error && typeof error === "object" && "code" in error && error.code === "ENOENT") {
      return [];
    }
    throw error;
  }
}

export async function readSessionSnapshot(root: string, sessionId: string): Promise<InspectorSnapshot> {
  return buildInspectorSnapshot(sessionId, await readSessionEvents(root, sessionId));
}

export async function readSessionComparison(root: string, leftSessionId: string, rightSessionId: string): Promise<InspectorComparison> {
  const [left, right] = await Promise.all([
    readSessionSnapshot(root, leftSessionId),
    readSessionSnapshot(root, rightSessionId)
  ]);
  return compareInspectorSnapshots(left, right);
}

