}

import type { LoadedExtension } from "./registry.js";
import type { SkillExtension, HookExtension, McpExtension, RecipeExtension, SubagentExtension } from "./manifest.js";
import { HOOK_TRIGGERS } from "./manifest.js";

export type ExtensionBundle = {
  skills: Map<string, LoadedExtension>;         // key: trigger or name
  hooks: Map<string, LoadedExtension[]>;        // key: pre_task | post_task | on_change
  mcp: Map<string, LoadedExtension>;            // key: extension name
  recipes: Map<string, LoadedExtension>;       // key: extension name
  subagents: Map<string, LoadedExtension>;     // key: extension name
};

export function loadExtensions(registry: { list: () => LoadedExtension[] }): ExtensionBundle {
  const skills = new Map<string, LoadedExtension>();
  const hooks = new Map<string, LoadedExtension[]>(
    HOOK_TRIGGERS.map(t => [t, [] as LoadedExtension[]])
  );
  const mcp = new Map<string, LoadedExtension>();
  const recipes = new Map<string, LoadedExtension>();
  const subagents = new Map<string, LoadedExtension>();

  for (const ext of registry.list()) {
    switch (ext.manifest.type) {
      case "skill": {
        const trigger = (ext.manifest as SkillExtension).trigger;
        const key = trigger ?? ext.manifest.name;
        skills.set(key, ext);
        break;
      }
      case "hook": {
        const trigger = (ext.manifest as HookExtension).trigger;
        const list = hooks.get(trigger) ?? [];
        list.push(ext);
        hooks.set(trigger, list);
        break;
      }
      case "mcp":
        mcp.set(ext.manifest.name, ext);
        break;
      case "recipe":
        recipes.set(ext.manifest.name, ext);
        break;
      case "subagent":
        subagents.set(ext.manifest.name, ext);
        break;
    }
  }

  return { skills, hooks, mcp, recipes, subagents };
}

export const EXTENSION_TYPES = ["skill", "hook", "mcp", "recipe", "subagent"] as const;
export type ExtensionType = typeof EXTENSION_TYPES[number];

export const HOOK_TRIGGERS = ["pre_task", "post_task", "on_change"] as const;
export type HookTrigger = typeof HOOK_TRIGGERS[number];

// --- Permission types ---
export type PermissionLevel = "none" | "read" | "write" | "dangerous";

export type ExtensionPermission = {
  level: PermissionLevel;
  description: string;
  reason?: string;
};

// --- Shared fields ---
type BaseExtension = {
  name: string;
  version: string;
  description: string;
  author?: string;
  tags?: string[];
  is_core?: boolean;
  permissions?: ExtensionPermission[];
  requires_confirmation?: boolean;
  license?: string;
  homepage?: string;
  installed_at?: string;
};

// --- Skill extension ---
export type SkillExtension = BaseExtension & {
  type: "skill";
  trigger?: string;       // slash command, e.g. "/tdd"
  pattern?: string;        // regex pattern
  auto_load?: boolean;    // load on startup
};

// --- Hook extension ---
export type HookExtension = BaseExtension & {
  type: "hook";
  trigger: "pre_task" | "post_task" | "on_change";
  command: string;
  env?: Record<string, string>;
  cwd?: string;
};

// --- MCP extension ---
export type McpExtension = BaseExtension & {
  type: "mcp";
  transport: "stdio" | "http" | "websocket";
  command?: string;       // for stdio
  args?: string[];
  env?: Record<string, string>;
  url?: string;           // for http/websocket
  headers?: Record<string, string>;
  tools?: string[];       // explicit tool allowlist (empty = all)
};

// --- Recipe extension ---
// Note: steps are expressed as flat arrays of tool names in the manifest.
// Full step objects are used when recipes are compiled at runtime.
// e.g. "steps: [bash, npm-test]" not nested objects.
export type RecipeExtension = BaseExtension & {
  type: "recipe";
  steps: string[];          // flat array of tool names, not nested objects
  prerequisites?: string[];
  estimated_tokens?: number;
};

// --- Subagent extension ---
export type SubagentExtension = BaseExtension & {
  type: "subagent";
  model?: string;
  readonly?: boolean;
  system_prompt?: string;
  files?: string[];      // owned file patterns
};

export type ExtensionManifest =
  | SkillExtension
  | HookExtension
  | McpExtension
  | RecipeExtension
  | SubagentExtension;

// Minimal YAML parser (no new dependency)
function yamlToObject(yaml: string): Record<string, unknown> {
  const obj: Record<string, unknown> = {};
  const lines = yaml.split("\n");
  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    const colonIdx = line.indexOf(":");
    if (colonIdx === -1) { i++; continue; }
    const key = line.slice(0, colonIdx).trim();
    let value = line.slice(colonIdx + 1).trim();
    if (value === "") {
      // look ahead for block value
      const items: string[] = [];
      i++;
      while (i < lines.length && lines[i].startsWith("  ")) {
        const item = lines[i].trim();
        if (item.startsWith("-")) items.push(item.slice(1).trim());
        else items.push(item);
        i++;
      }
      if (items.length > 0) { obj[key] = items; continue; }
      i--; // back up so outer loop processes this
    } else if (value.startsWith("[") && value.endsWith("]")) {
      obj[key] = value.slice(1, -1).split(",").map(t => t.trim()).filter(Boolean);
    } else if (value === "true") obj[key] = true;
    else if (value === "false") obj[key] = false;
    else if (!isNaN(Number(value)) && value !== "") obj[key] = Number(value);
    else obj[key] = value.replace(/^["']|["']$/g, "");
    i++;
  }
  return obj;
}

export function parseExtensionManifest(yaml: string, type: ExtensionType): ExtensionManifest | null {
  const raw = yamlToObject(yaml);
  if (!raw.name || !raw.description) return null;

  const base = {
    name: String(raw.name),
    version: String(raw.version ?? "1.0.0"),
    description: String(raw.description),
    author: raw.author != null ? String(raw.author) : undefined,
    tags: (raw.tags as string[] | undefined),
    is_core: raw.is_core === true,
    license: raw.license != null ? String(raw.license) : undefined,
    homepage: raw.homepage != null ? String(raw.homepage) : undefined,
    installed_at: raw.installed_at != null ? String(raw.installed_at) : undefined,
    permissions: raw.permissions as ExtensionPermission[] | undefined,
    requires_confirmation: raw.requires_confirmation === true,
  };

  switch (type) {
    case "skill":
      return { ...base, type: "skill", trigger: raw.trigger as any, pattern: raw.pattern as any, auto_load: raw.auto_load === true };
    case "hook":
      const validHookTrigger = raw.trigger as string;
      if (validHookTrigger && !HOOK_TRIGGERS.includes(validHookTrigger as any)) {
        return null; // invalid hook trigger
      }
      return { ...base, type: "hook", trigger: raw.trigger as any, command: String(raw.command ?? ""), env: raw.env as any, cwd: raw.cwd as any };
    case "mcp":
      const validTransport = raw.transport as string;
      if (validTransport && !["stdio", "http", "websocket"].includes(validTransport)) {
        return null; // invalid transport type
      }
      return { ...base, type: "mcp", transport: (raw.transport as any) ?? "stdio", command: raw.command as any, args: raw.args as any, env: raw.env as any, url: raw.url as any, headers: raw.headers as any, tools: raw.tools as any };
    case "recipe":
      return { ...base, type: "recipe", steps: (raw.steps as string[] | undefined) ?? [], prerequisites: raw.prerequisites as any, estimated_tokens: raw.estimated_tokens as any };
    case "subagent":
      return { ...base, type: "subagent", model: raw.model as any, readonly: raw.readonly === true, system_prompt: raw.system_prompt as any, files: raw.files as any };
  }
}

export function getExtensionId(manifest: ExtensionManifest): string {
  return `${manifest.type}/${manifest.name}`;
}

export function isCoreExtension(manifest: ExtensionManifest): boolean {
  return manifest.is_core === true;
}

// src/extensions/registry.ts
import { existsSync, readFileSync, readdirSync, mkdirSync, writeFileSync, rmSync, copyFileSync } from "node:fs";
import { join, basename } from "node:path";
import { parseExtensionManifest, type ExtensionManifest, type ExtensionType, type SkillExtension, type HookExtension, getExtensionId, isCoreExtension } from "./manifest.js";

export type LoadedExtension = {
  manifest: ExtensionManifest;
  path: string;
  installedAt: string;
};

export type VersionInfo = {
  version: string;
  installedAt: string;
};

export type ListOptions = {
  type?: ExtensionType;
  tag?: string;
  trigger?: string;
  hookTrigger?: "pre_task" | "post_task" | "on_change";
};

export class ExtensionRegistry {
  private extensions = new Map<string, LoadedExtension>();

  constructor(private storePath: string) {
    this.load();
  }

  private load(): void {
    this.extensions.clear();
    if (!existsSync(this.storePath)) return;
    for (const entry of readdirSync(this.storePath, { withFileTypes: true })) {
      if (!entry.isDirectory()) continue;
      const manifestPath = join(this.storePath, entry.name, "EXTENSION.yaml");
      if (!existsSync(manifestPath)) continue;
      try {
        const content = readFileSync(manifestPath, "utf8");
        const type = this.inferType(entry.name);
        const manifest = parseExtensionManifest(content, type);
        if (!manifest) continue;
        const id = getExtensionId(manifest);
        this.extensions.set(id, {
          manifest,
          path: manifestPath,
          installedAt: manifest.installed_at ?? new Date().toISOString(),
        });
      } catch { /* skip invalid entries */ }
    }
  }

  private inferType(dirName: string): ExtensionType {
    const dashIdx = dirName.indexOf("-");
    if (dashIdx !== -1) {
      const prefix = dirName.slice(0, dashIdx);
      if ((["skill", "hook", "mcp", "recipe", "subagent"] as const).includes(prefix as any)) {
        return prefix as ExtensionType;
      }
    }
    return "skill"; // default
  }

  get(id: string): LoadedExtension | undefined {
    return this.extensions.get(id);
  }

  list(options?: ListOptions): LoadedExtension[] {
    let results = [...this.extensions.values()];
    if (options?.type) {
      results = results.filter(e => e.manifest.type === options.type);
    }
    if (options?.tag) {
      results = results.filter(e => e.manifest.tags?.includes(options.tag!));
    }
    if (options?.trigger) {
      results = results.filter(e => {
        if (e.manifest.type !== "skill") return false;
        const sk = e.manifest as SkillExtension;
        return sk.trigger === options.trigger;
      });
    }
    if (options?.hookTrigger) {
      results = results.filter(e => {
        if (e.manifest.type !== "hook") return false;
        const hk = e.manifest as HookExtension;
        return hk.trigger === options.hookTrigger;
      });
    }
    return results;
  }

  async install(sourcePath: string): Promise<LoadedExtension | null> {
    const manifestPath = join(sourcePath, "EXTENSION.yaml");
    if (!existsSync(manifestPath)) return null;

    const srcDirName = basename(sourcePath);
    const type = this.inferType(srcDirName);
    const content = readFileSync(manifestPath, "utf8");
    const manifest = parseExtensionManifest(content, type);
    if (!manifest) return null;

    const id = getExtensionId(manifest);
    const targetDir = join(this.storePath, `${manifest.type}-${manifest.name}`);

    mkdirSync(targetDir, { recursive: true });

    try {
      for (const entry of readdirSync(sourcePath, { withFileTypes: true })) {
        const src = join(sourcePath, entry.name);
        const dst = join(targetDir, entry.name);
        if (entry.isDirectory()) {
          mkdirSync(dst, { recursive: true });
          copyDirRecursive(src, dst);
        } else {
          copyFileSync(src, dst);
        }
      }
    } catch {
      rmSync(targetDir, { recursive: true, force: true });
      return null;
    }

    this.load();
    return this.extensions.get(id) ?? null;
  }

  async uninstall(id: string): Promise<boolean> {
    const ext = this.extensions.get(id);
    if (!ext) return false;
    if (isCoreExtension(ext.manifest)) return false;

    const dir = join(this.storePath, `${ext.manifest.type}-${ext.manifest.name}`);
    try {
      rmSync(dir, { recursive: true, force: true });
    } catch { return false; }
    this.extensions.delete(id);
    return true;
  }

  count(): number { return this.extensions.size; }

  getVersionInfo(id: string): VersionInfo | null {
    const ext = this.extensions.get(id);
    if (!ext) return null;
    return {
      version: ext.manifest.version,
      installedAt: ext.installedAt,
    };
  }

  async updateVersion(id: string, newVersion: string): Promise<boolean> {
    const ext = this.extensions.get(id);
    if (!ext || isCoreExtension(ext.manifest)) return false;

    const manifestPath = join(this.storePath, `${ext.manifest.type}-${ext.manifest.name}`, "EXTENSION.yaml");
    let content: string;
    try {
      content = readFileSync(manifestPath, "utf8");
    } catch { return false; }

    const lines = content.split("\n");
    const updatedLines = lines.map(line => {
      const trimmed = line.trim();
      if (trimmed === `version:` || trimmed.startsWith("version:")) {
        // Only update top-level version (no leading spaces)
        if (!line.startsWith(" ") && !line.startsWith("\t")) {
          return `version: ${newVersion}`;
        }
      }
      return line;
    });
    const updated = updatedLines.join("\n");
    writeFileSync(manifestPath, updated, "utf8");
    this.load();
    return true;
  }
}

function copyDirRecursive(src: string, dst: string): void {
  mkdirSync(dst, { recursive: true });
  for (const entry of readdirSync(src, { withFileTypes: true })) {
    const s = join(src, entry.name);
    const d = join(dst, entry.name);
    if (entry.isDirectory()) {
      copyDirRecursive(s, d);
    } else {
      copyFileSync(s, d);
    }
  }
}

import { existsSync } from "node:fs";
import { appendFile, mkdir, readFile } from "node:fs/promises";
import { randomUUID } from "node:crypto";
import { dirname, join } from "node:path";
import type { AlixEvent, NewEvent } from "./types.js";

export class EventLog {
  readonly path: string;
  private nextSeq = 1;

  constructor(readonly sessionDir: string) {
    this.path = join(sessionDir, "events.jsonl");
  }

  async init(): Promise<void> {
    await mkdir(dirname(this.path), { recursive: true });
    const events = await this.readAll();
    this.nextSeq = events.length + 1;
  }

  async append<TType extends string, TPayload>(
    event: NewEvent<TType, TPayload>
  ): Promise<AlixEvent<TType, TPayload>> {
    const fullEvent: AlixEvent<TType, TPayload> = {
      ...event,
      id: randomUUID(),
      seq: this.nextSeq++,
      version: 1,
      timestamp: new Date().toISOString()
    };
    await appendFile(this.path, `${JSON.stringify(fullEvent)}\n`, "utf8");
    return fullEvent;
  }

  async readAll(): Promise<AlixEvent[]> {
    if (!existsSync(this.path)) return [];
    const text = await readFile(this.path, "utf8");
    return text
      .split("\n")
      .filter(Boolean)
      .map((line) => JSON.parse(line) as AlixEvent);
  }
}

import type { AlixEvent, SessionProjection } from "./types.js";

export function replay(events: AlixEvent[]): SessionProjection {
  const sessionId = events[0]?.sessionId ?? "";
  const projection: SessionProjection = {
    sessionId,
    eventCount: events.length,
    approvals: {},
    changedFiles: []
  };

  for (const event of events) {
    if (event.type === "patch.applied") {
      const payload = event.payload as { changedFiles?: string[] };
      projection.changedFiles.push(...(payload.changedFiles ?? []));
    }
    if (event.type === "session.ended") {
      const payload = event.payload as { summary?: string };
      projection.summary = payload.summary;
    }
  }

  projection.changedFiles = Array.from(new Set(projection.changedFiles));
  return projection;
}

export type EventActor = "user" | "agent" | "system" | "tool" | "policy" | "verifier" | "subagent";

export type AlixEvent<TType extends string = string, TPayload = unknown> = {
  id: string;
  seq: number;
  version: 1;
  sessionId: string;
  runId?: string;
  parentEventId?: string;
  timestamp: string;
  type: TType;
  actor: EventActor;
  payload: TPayload;
};

export type NewEvent<TType extends string = string, TPayload = unknown> = Omit<
  AlixEvent<TType, TPayload>,
  "id" | "seq" | "version" | "timestamp"
>;

export type SessionProjection = {
  sessionId: string;
  eventCount: number;
  approvals: Record<string, unknown>;
  changedFiles: string[];
  summary?: string;
};

