export type ValidationIssue = {
  path: string;
  level: "error" | "warning";
  message: string;
};

export type ConfigValidationResult = {
  valid: boolean;
  issues: ValidationIssue[];
};

import type { AlixConfig, ConfigValidationResult, ValidationIssue } from "./schema.js";

const VALID_PROVIDERS = ["mock","anthropic","openai","google","openrouter","groq","ollama","perplexity","minimax","zhipuai","grokai","deepseek"] as const;

export function validateConfig(config: AlixConfig): ConfigValidationResult {
  const issues: ValidationIssue[] = [];

  // model.provider must be valid
  if (!VALID_PROVIDERS.includes(config.model.provider as any)) {
    issues.push({ path: "model.provider", level: "error", message: `Unknown provider "${config.model.provider}"` });
  }

  // model.name must be a non-empty string
  if (!config.model.name || typeof config.model.name !== "string") {
    issues.push({ path: "model.name", level: "error", message: "model.name must be a non-empty string" });
  }

  // ui.port must be 1024-65535
  if (config.ui.port < 1024 || config.ui.port > 65535) {
    issues.push({ path: "ui.port", level: "warning", message: `Port ${config.ui.port} is outside typical range (1024-65535)` });
  }

  // context.maxRepoMapTokens must be positive integer
  if (!Number.isInteger(config.context.maxRepoMapTokens) || config.context.maxRepoMapTokens <= 0) {
    issues.push({ path: "context.maxRepoMapTokens", level: "error", message: "maxRepoMapTokens must be a positive integer" });
  }

  // runtime.commandTimeoutMs must be positive
  if (config.runtime.commandTimeoutMs <= 0) {
    issues.push({ path: "runtime.commandTimeoutMs", level: "error", message: "commandTimeoutMs must be positive" });
  }

  // permissions.protectedPaths must be strings
  for (const p of config.permissions.protectedPaths) {
    if (typeof p !== "string") issues.push({ path: "permissions.protectedPaths", level: "error", message: "protectedPaths must contain only strings" });
  }

  // permissions.denyCommands must be strings
  for (const cmd of config.permissions.denyCommands) {
    if (typeof cmd !== "string") issues.push({ path: "permissions.denyCommands", level: "error", message: "denyCommands must contain only strings" });
  }

  // permissions.default must be "ask" | "allow" | "deny"
  if (!["ask","allow","deny"].includes(config.permissions.default)) {
    issues.push({ path: "permissions.default", level: "error", message: "permissions.default must be ask, allow, or deny" });
  }

  // context.repoMapMode must be "lite" | "full"
  if (!["lite","full"].includes(config.context.repoMapMode)) {
    issues.push({ path: "context.repoMapMode", level: "error", message: "context.repoMapMode must be lite or full" });
  }

  // runtime.provider must be "process" | "docker" | "remote"
  if (!["process","docker","remote"].includes(config.runtime.provider)) {
    issues.push({ path: "runtime.provider", level: "error", message: "runtime.provider must be process, docker, or remote" });
  }

  return { valid: issues.filter(i => i.level === "error").length === 0, issues };
}

import { randomUUID } from "node:crypto";
import { existsSync } from "node:fs";
import { copyFile, mkdir, rm } from "node:fs/promises";
import { dirname, join, resolve } from "node:path";

export type Checkpoint = {
  id: string;
  root: string;
  files: string[];
  missingFiles: string[];
};

export async function createFileCheckpoint(root: string, files: string[]): Promise<Checkpoint> {
  const id = randomUUID();
  const missingFiles: string[] = [];
  for (const file of files) {
    const source = resolveCheckpointPath(root, file);
    const target = join(root, ".alix", "checkpoints", id, file);
    if (!existsSync(source)) {
      missingFiles.push(file);
      continue;
    }
    await mkdir(dirname(target), { recursive: true });
    await copyFile(source, target);
  }
  return { id, root, files, missingFiles };
}

export async function restoreFileCheckpoint(checkpoint: Checkpoint): Promise<void> {
  for (const file of checkpoint.files) {
    const destination = resolveCheckpointPath(checkpoint.root, file);
    if (checkpoint.missingFiles.includes(file)) {
      await rm(destination, { force: true });
      continue;
    }
    const source = join(checkpoint.root, ".alix", "checkpoints", checkpoint.id, file);
    await mkdir(dirname(destination), { recursive: true });
    await copyFile(source, destination);
  }
}

function resolveCheckpointPath(root: string, file: string): string {
  const resolvedRoot = resolve(root);
  const resolvedPath = resolve(resolvedRoot, file);
  if (resolvedPath !== resolvedRoot && !resolvedPath.startsWith(`${resolvedRoot}/`)) {
    throw new Error(`Checkpoint path is outside workspace: ${file}`);
  }
  return resolvedPath;
}

import { resolve } from "node:path";

export type AgentState = "planning" | "executing" | "verifying" | "repairing" | "summarizing" | "stopped";

export type ScopeTracker = {
  state: AgentState;
  initialFiles: Set<string>;
  approvedFiles: Set<string>;
  pendingApproval: string | null;
  transition(newState: AgentState): void;
  checkMutation(path: string): "allowed" | "scope_expansion" | "approved" | "denied";
  approveScope(path: string): void;
  denyScope(path: string): void;
  setPending(path: string): void;
  clearPending(): void;
  getDeniedMessage(): string | null;
};

/**
 * Parse file paths mentioned in the task string.
 * Detects patterns like: src/foo.ts, "file.ts", `file.ts`
 */
export function extractInitialScope(task: string): string[] {
  const paths: string[] = [];
  // Match quoted or backtick paths, or paths with slashes that look like file references
  const patterns = [
    /["'`]([^\s`]+?\.(?:ts|tsx|js|jsx|py|go|rs|java|kt|cs|rb|php|swift|c|cpp|h|hpp|json|md|toml|yaml|yml))["'`]/g,
    /(?:^|\s)([\w./-]+\.(?:ts|tsx|js|jsx|py|go|rs|java|kt|cs|rb|php|swift|c|cpp|h|hpp|json|md|toml|yaml|yml))(?=\s|$)/gm,
  ];
  for (const pattern of patterns) {
    let match;
    while ((match = pattern.exec(task)) !== null) {
      paths.push(match[1]);
    }
  }
  return [...new Set(paths)];
}

/**
 * Normalize a path for comparison (relative to root, trailing slashes removed).
 */
function normalize(path: string, root: string): string {
  try { return resolve(root, path); } catch { return path; }
}

export function createScopeTracker(
  initialFiles: string[],
  root: string
): ScopeTracker {
  const initialSet = new Set(initialFiles.map(p => normalize(p, root)));
  const approvedSet = new Set(initialSet); // initial scope is auto-approved
  const deniedSet = new Set<string>(); // files explicitly denied by user

  let currentState: AgentState = "planning";
  let pendingFile: string | null = null;

  return {
    get state() { return currentState; },

    get initialFiles() { return initialSet; },
    get approvedFiles() { return approvedSet; },
    get pendingApproval() { return pendingFile; },

    transition(newState: AgentState) {
      currentState = newState;
      pendingFile = null;
    },

    checkMutation(path: string): "allowed" | "scope_expansion" | "approved" | "denied" {
      const n = normalize(path, root);
      if (deniedSet.has(n)) return "denied";
      if (approvedSet.has(n)) return "approved";
      if (initialSet.has(n)) return "allowed"; // initial scope — auto-approved for mutation
      return "scope_expansion";
    },

    approveScope(path: string) {
      const n = normalize(path, root);
      approvedSet.add(n);
      deniedSet.delete(n);
      pendingFile = null;
    },

    denyScope(path: string) {
      const n = normalize(path, root);
      deniedSet.add(n);
      pendingFile = null;
    },

    setPending(path: string) {
      pendingFile = path;
    },

    clearPending() {
      pendingFile = null;
    },

    getDeniedMessage() {
      return pendingFile ? `Scope expansion denied for: ${pendingFile}` : null;
    },
  };
}

import type { AgentState } from "./scope-tracker.js";

export type RunLimits = {
  maxIterations: number;
  maxRepairs: number;
  maxFileChanges: number;
  maxShellCommands: number;
  maxRuntimeMs: number;
};

export type RunCounters = {
  iterations: number;
  repairs: number;
  fileChanges: number;
  shellCommands: number;
  runtimeMs: number;
};

export type RunResult = {
  success: boolean;
  reason: string;
  state: AgentState;
  counters: RunCounters;
};

type TransitionGuard = (ctx: TransitionContext) => { allowed: boolean; reason?: string };

type TransitionContext = {
  state: AgentState;
  counters: RunCounters;
  scopeExpanded: boolean;
  verificationPassed: boolean;
  modelSignaledDone: boolean;
  pendingScopeFile: string | null;
};

/**
 * Hard limits for the agent run. Enforces all limits at each transition.
 */
export class RunLimiter {
  constructor(private limits: RunLimits) {}

  canTransition(from: AgentState, to: AgentState, ctx: TransitionContext): { allowed: boolean; reason?: string } {
    if (this.limits.maxIterations > 0 && ctx.counters.iterations >= this.limits.maxIterations) {
      return { allowed: false, reason: `Max iterations reached (${this.limits.maxIterations})` };
    }
    if (this.limits.maxRepairs > 0 && ctx.counters.repairs >= this.limits.maxRepairs) {
      return { allowed: false, reason: `Max repairs reached (${this.limits.maxRepairs})` };
    }
    if (this.limits.maxRuntimeMs > 0 && ctx.counters.runtimeMs > this.limits.maxRuntimeMs) {
      return { allowed: false, reason: `Max runtime exceeded (${this.limits.maxRuntimeMs}ms)` };
    }
    return { allowed: true };
  }

  checkCounter(limit: keyof RunLimits, value: number): boolean {
    const max = this.limits[limit] as number;
    return max > 0 && value >= max;
  }
}

/**
 * State machine for the agent run lifecycle.
 * Transitions are driven by agent actions, not model signaling.
 */
export class TaskStateMachine {
  private state: AgentState = "planning";
  private counters: RunCounters = {
    iterations: 0,
    repairs: 0,
    fileChanges: 0,
    shellCommands: 0,
    runtimeMs: 0,
  };

  constructor(
    private limiter: RunLimiter,
    private onTransition?: (from: AgentState, to: AgentState, reason?: string) => void
  ) {}

  get currentState(): AgentState {
    return this.state;
  }

  get snapshot(): RunCounters {
    return { ...this.counters };
  }

  /**
   * Called at the start of each iteration.
   */
  tick(runtimeMs: number) {
    this.counters.iterations++;
    this.counters.runtimeMs += runtimeMs;
  }

  /**
   * Increment file change counter.
   */
  recordFileChange() {
    this.counters.fileChanges++;
  }

  /**
   * Increment shell command counter.
   */
  recordShellCommand() {
    this.counters.shellCommands++;
  }

  /**
   * Record a repair attempt (verification failed and model is re-attempting).
   */
  recordRepair() {
    this.counters.repairs++;
  }

  /**
   * Transition to executing when model first requests a mutation (write/delete/shell).
   */
  toExecuting(scopeExpanded: boolean): { allowed: boolean; reason?: string } {
    if (scopeExpanded) {
      // Scope expansion detected — don't transition yet, user must approve
      return { allowed: false, reason: "scope_expansion_pending" };
    }
    const ctx = this.buildContext(false, false, false);
    const result = this.limiter.canTransition(this.state, "executing", ctx);
    if (result.allowed && this.state === "planning") {
      this._transition("executing");
    }
    return result;
  }

  /**
   * Transition to verifying when model signals done.
   */
  toVerifying(verificationPassed: boolean): { allowed: boolean; reason?: string } {
    const ctx = this.buildContext(false, verificationPassed, true);
    const result = this.limiter.canTransition(this.state, "verifying", ctx);
    if (result.allowed) {
      if (this.state === "executing" || this.state === "repairing") {
        this._transition("verifying");
      }
    }
    return result;
  }

  /**
   * Transition to repairing when verification fails.
   */
  toRepairing(): { allowed: boolean; reason?: string } {
    const ctx = this.buildContext(false, false, false);
    const result = this.limiter.canTransition(this.state, "repairing", ctx);
    if (result.allowed) {
      if (this.state === "verifying") {
        this._transition("repairing");
        this.recordRepair();
      }
    }
    return result;
  }

  /**
   * Transition to summarizing when verification passed and model signaled done.
   */
  toSummarizing(): { allowed: boolean; reason?: string } {
    const ctx = this.buildContext(false, true, true);
    const result = this.limiter.canTransition(this.state, "summarizing", ctx);
    if (result.allowed) {
      this._transition("summarizing");
    }
    return result;
  }

  /**
   * Hard stop — reached a limit.
   */
  stop(reason: string): RunResult {
    this.state = "stopped";
    return {
      success: false,
      reason,
      state: this.state,
      counters: this.snapshot,
    };
  }

  /**
   * Normal completion — verification passed and model signaled done.
   */
  complete(): RunResult {
    this.state = "stopped";
    return {
      success: true,
      reason: "completed",
      state: this.state,
      counters: this.snapshot,
    };
  }

  private buildContext(scopeExpanded: boolean, verificationPassed: boolean, modelSignaledDone: boolean): TransitionContext {
    return {
      state: this.state,
      counters: this.snapshot,
      scopeExpanded: scopeExpanded,
      verificationPassed,
      modelSignaledDone,
      pendingScopeFile: null,
    };
  }

  private _transition(to: AgentState, reason?: string) {
    const from = this.state;
    this.state = to;
    this.onTransition?.(from, to, reason);
  }

  /** @internal - for testing only */
  _setState(to: AgentState) { this.state = to; }
}

/**
 * Delegate tool handler — parent agent calls this to spawn subagents.
 * Returns findings as structured output.
 */
import { randomUUID } from "crypto";
import type { SubagentRole, SubagentTask, SubagentResult } from "../config/schema.js";
import type { SubagentManager } from "./subagent-manager.js";
import type { ToolResult } from "../tools/types.js";
import { classifyTask } from "../task-classifier.js";
import { recommendRole } from "./role-mapper.js";

type AutoRole = SubagentRole | "auto";

export function createDelegateHandler(
  subagentManager: SubagentManager,
  buildTask: (opts: { role: SubagentRole; prompt: string; ownedPaths?: string[]; mode?: "read_only" | "write" }) => SubagentTask,
  onResult?: (result: SubagentResult) => void,
  log?: (msg: string) => void,
): (args: Record<string, unknown>) => Promise<ToolResult> {
  return async (args: Record<string, unknown>): Promise<ToolResult> => {
    const roleArg = args.role as AutoRole | undefined;
    const prompt = args.prompt as string;
    const ownedPaths = (args.ownedPaths as string[] | undefined) ?? [];

    // Resolve role: "auto" or missing → infer from task content
    let role: SubagentRole;
    if (!roleArg || roleArg === "auto") {
      const taskType = classifyTask(prompt);
      const rec = recommendRole(taskType, prompt);
      role = rec.role;
      log?.(`[delegate] auto-selected role=${role} (${rec.confidence}) for taskType=${taskType}: ${rec.reason}`);
    } else {
      role = roleArg;
    }

    if (role === "worker" && ownedPaths.length === 0) {
      return { kind: "error", message: "Worker subagent requires ownedPaths", retryable: false };
    }

    const mode = role === "worker" ? "write" : "read_only";
    const task = buildTask({ role, prompt, ownedPaths, mode });

    try {
      const result = await subagentManager.spawn(task);

      if (result.status === "success") {
        if (onResult) onResult(result);
        return {
          kind: "success",
          output: result.findings.map(f => `[${f.type}] ${f.content}`).join("\n") || "(no findings)",
        };
      } else {
        if (onResult) onResult(result);
        return {
          kind: "error",
          message: `Subagent failed: ${result.error ?? "unknown error"}`,
          retryable: false,
        };
      }
    } catch (err) {
      const errorResult: SubagentResult = {
        id: crypto.randomUUID(), role, status: "failed", findings: [], events: [],
        error: err instanceof Error ? err.message : String(err),
      };
      if (onResult) onResult(errorResult);
      return {
        kind: "error",
        message: err instanceof Error ? err.message : String(err),
        retryable: false,
      };
    }
  };
}

/**
 * Coordinates results from multiple concurrent subagents.
 * Detects conflicts, summarizes findings, and feeds into parent decision loop.
 */
import type { SubagentResult, SubagentFinding } from "../config/schema.js";

export type Conflict = {
  path: string;
  findings: SubagentFinding[];
};

export class MergeCoordinator {
  private pending: SubagentResult[] = [];

  /** Queue a subagent result for processing. */
  enqueue(result: SubagentResult): void {
    this.pending.push(result);
  }

  /** Get all pending results and clear the queue. */
  drain(): SubagentResult[] {
    const results = [...this.pending];
    this.pending = [];
    return results;
  }

  /** Number of pending results. */
  size(): number { return this.pending.length; }

  /**
   * Identify potential conflicts — file paths where multiple subagents
   * found different things (e.g., two explorers mapped the same file differently).
   */
  detectConflicts(results: SubagentResult[]): Conflict[] {
    const byRef = new Map<string, SubagentFinding[]>();

    for (const result of results) {
      for (const finding of result.findings) {
        if (finding.refs) {
          for (const ref of finding.refs) {
            if (!byRef.has(ref)) byRef.set(ref, []);
            byRef.get(ref)!.push(finding);
          }
        }
      }
    }

    const conflicts: Conflict[] = [];
    for (const [path, findings] of byRef) {
      if (findings.length > 1) {
        conflicts.push({ path, findings });
      }
    }
    return conflicts;
  }

  /**
   * Merge findings into a summary string for the parent agent.
   * Parent incorporates this into its message stream.
   */
  summarize(results: SubagentResult[]): string {
    const lines: string[] = [];
    for (const result of results) {
      lines.push(`## ${result.role} (${result.id.slice(0, 8)})`);
      if (result.error) {
        lines.push(`**Error:** ${result.error}`);
        continue;
      }
      if (result.findings.length === 0) {
        lines.push("(no findings)");
        continue;
      }
      for (const finding of result.findings) {
        lines.push(`- [${finding.type}] ${finding.content}`);
      }
    }
    return lines.join("\n");
  }
}

/**
 * Tracks which worker subagent owns which file paths.
 * Prevents overlapping write ownership across subagents.
 */
export class OwnershipRegistry {
  private owned = new Map<string, string>(); // path -> subagentId

  claim(subagentId: string, paths: string[]): void {
    for (const path of paths) {
      const existing = this.owned.get(path);
      if (existing && existing !== subagentId) {
        throw new Error(`Overlapping ownership: '${path}' already owned by '${existing}'`);
      }
      this.owned.set(path, subagentId);
    }
  }

  release(subagentId: string): void {
    for (const [path, id] of this.owned) {
      if (id === subagentId) this.owned.delete(path);
    }
  }

  isOwner(subagentId: string, path: string): boolean {
    return this.owned.get(path) === subagentId;
  }

  ownedBy(subagentId: string): string[] {
    return [...this.owned.entries()]
      .filter(([, id]) => id === subagentId)
      .map(([path]) => path);
  }

  count(): number { return this.owned.size; }
}

/**
 * Validates subagent results against expected output contract.
 */
import type { SubagentResult } from "../config/schema.js";

export type ValidationResult = {
  valid: boolean;
  warnings: string[];
};

export function validateResult(result: SubagentResult, expected?: string): ValidationResult {
  const warnings: string[] = [];

  if (expected && result.status === "success") {
    const hasExpected = result.findings.some(f => f.content.includes(expected));
    if (!hasExpected) {
      warnings.push(`Expected output "${expected}" not found in findings`);
    }
  }

  if (result.findings.length === 0 && result.status === "success") {
    warnings.push("Subagent returned success but no findings were recorded");
  }

  return { valid: warnings.length === 0, warnings };
}

import type { TaskType } from "../task-classifier.js";
import type { SubagentRole } from "../config/schema.js";

export type RoleRecommendation = {
  role: SubagentRole;
  confidence: "high" | "medium" | "low";
  reason: string;
};

/**
 * Map task type and prompt to recommended subagent role.
 */
export function recommendRole(taskType: TaskType, prompt: string): RoleRecommendation {
  // Bugfix → worker (can apply fixes)
  if (taskType === "bugfix") {
    return { role: "worker", confidence: "high", reason: "bugfix tasks require write capability" };
  }

  // Feature → check if it mentions files (could be worker)
  if (taskType === "feature") {
    const mentionsFiles = /[\/\w]+\.(ts|js|py|go|rs)/i.test(prompt);
    if (mentionsFiles) {
      return { role: "worker", confidence: "medium", reason: "feature mentions existing files" };
    }
    return { role: "explorer", confidence: "medium", reason: "feature without file references" };
  }

  // Refactor → reviewer (analyze code quality)
  if (taskType === "refactor") {
    return { role: "reviewer", confidence: "high", reason: "refactor tasks benefit from code review" };
  }

  // Docs → docs_researcher
  if (taskType === "docs") {
    return { role: "docs_researcher", confidence: "high", reason: "documentation tasks" };
  }

  // Default → explorer (read-only exploration)
  return { role: "explorer", confidence: "low", reason: "no specific role match" };
}

