import { spawn, type ChildProcess } from "child_process";
import { resolve } from "path";
import { fileURLToPath } from "url";
import type { SubagentRole, SubagentTask, SubagentResult, SubagentRoleConfig, AlixConfig, ModelTierConfig } from "../config/schema.js";

// Re-export types for consumers
export type { SubagentTask, SubagentResult };

export type SubagentManagerOptions = {
  sessionId: string;
  config?: AlixConfig;
  /** Override the spawned command for testing. Defaults to the alix CLI. */
  spawnOverride?: { command: string; args?: string[] };
};

type RunningSubagent = {
  task: SubagentTask;
  process: ChildProcess;
  resolve: (result: SubagentResult) => void;
  reject: (err: Error) => void;
};

export type SubagentResultCallback = (result: SubagentResult) => void;

export class SubagentManager {
  private running = new Map<string, RunningSubagent>();
  private ownershipRegistry = new Map<string, string>(); // path -> subagentId
  private callbacks: SubagentResultCallback[] = [];

  constructor(private options: SubagentManagerOptions) {}

  onResult(cb: SubagentResultCallback): void {
    this.callbacks.push(cb);
  }

  /**
   * Spawn a subagent process. Throws if owned paths overlap with an active worker.
   */
  spawn(task: SubagentTask): Promise<SubagentResult> {
    return new Promise((resolvePromise, reject) => {
      if (task.mode === "write" && task.ownedPaths?.length) {
        for (const path of task.ownedPaths) {
          const owner = this.ownershipRegistry.get(path);
          if (owner && owner !== task.id) {
            reject(new Error(`Overlapping ownership: '${path}' is already owned by '${owner}'`));
            return;
          }
        }
        for (const path of task.ownedPaths) {
          this.ownershipRegistry.set(path, task.id);
        }
      }

      // model selection via getRoleModel (resolves style → provider+model)
      const { provider, name } = this.getRoleModel(task.role);
      // Build CLI args array
      const cliArgs = [
        "--subagent", task.role,
        "--task-id", task.id,
        "--prompt", task.prompt,
        "--mode", task.mode,
        "--session-id", task.contextBundle ?? `sub-${Date.now()}`,
        "--provider", provider,
        "--model", name,
        ...(task.ownedPaths?.length ? ["--owned-paths", task.ownedPaths.join(",")] : []),
      ];

      // Use spawnOverride for testing, otherwise use alix CLI
      const spawnOverride = this.options.spawnOverride;
      let command: string;
      let commandArgs: string[];
      if (spawnOverride) {
        command = spawnOverride.command;
        commandArgs = spawnOverride.args ?? cliArgs;
      } else {
        // Resolve to the alix CLI entry point
        const { fileURLToPath } = require("url");
        const thisFile = fileURLToPath(import.meta.url);
        const repoRoot = resolve(thisFile, "..", "..", "..", "..");
        command = String(process.execPath);
        commandArgs = [resolve(repoRoot, "dist", "src", "cli.js"), ...cliArgs];
      }

      const child = spawn(command, commandArgs, {
        stdio: ["pipe", "pipe", "pipe"] as const,
        env: { ...process.env, ALIX_NO_BANNER: "1" },
      }) as ChildProcess;

      this.running.set(task.id, { task, process: child, resolve: resolvePromise, reject });

      let stdoutData = "";
      if (child.stdout) {
        child.stdout.on("data", (chunk: Buffer) => { stdoutData += chunk.toString(); });
      }
      let stderr = "";

      if (child.stderr) {
        child.stderr.on("data", (data: Buffer) => { stderr += data.toString(); });
      }

      child.on("exit", (code: number | null) => {
        this.running.delete(task.id);
        this.releaseOwnership(task);

        const exitCode = code ?? 1;
        const parsed = stdoutData.trim() ? JSON.parse(stdoutData) as Partial<SubagentResult> : null;
        const result: SubagentResult = {
          id: task.id,
          role: task.role,
          status: exitCode === 0 ? "success" : "failed",
          findings: parsed?.findings ?? [],
          events: parsed?.events ?? [],
          error: exitCode !== 0 ? (stderr || parsed?.error || `Exit code ${exitCode}`) : undefined,
        };

        for (const cb of this.callbacks) cb(result);

        if (exitCode === 0) {
          resolvePromise(result);
        } else {
          reject(new Error(stderr || `Subagent exited with code ${exitCode}`));
        }
      });

      child.on("error", (err: Error) => {
        this.running.delete(task.id);
        this.releaseOwnership(task);
        reject(err);
      });
    });
  }

  shutdown(): void {
    for (const [, running] of this.running) {
      running.process.kill();
    }
    this.running.clear();
    this.ownershipRegistry.clear();
  }

  private releaseOwnership(task: SubagentTask): void {
    if (task.mode === "write" && task.ownedPaths?.length) {
      for (const path of task.ownedPaths) {
        this.ownershipRegistry.delete(path);
      }
    }
  }

  getRoleConfig(role: SubagentRole): SubagentRoleConfig | undefined {
    return this.options.config?.subagents?.roles.find((r: SubagentRoleConfig) => r.role === role);
  }

  getRoleModel(role: SubagentRole): { provider: string; name: string } {
    const roleConfig = this.getRoleConfig(role);
    const style = roleConfig?.style ?? "fast";
    const tier = this.options.config?.subagents?.[style] as ModelTierConfig | undefined;
    if (!tier) return { provider: "ollama", name: "llama3.2:3b" }; // safe fallback
    return { provider: tier.provider, name: tier.name };
  }
}

// Maps model tool names (alix_file_read) to executor names (file.read)
// Shared between main agent (run.ts) and subagents (SubagentCLI)

export type ToolNameMap = Record<string, string>;

export const TOOL_NAME_MAP: ToolNameMap = {
  alix_file_read:    "file.read",
  alix_file_write:   "file.write",
  alix_file_create:  "file.create",
  alix_file_delete:  "file.delete",
  alix_file_exists:  "file.exists",
  alix_dir_search:   "dir.search",
  alix_shell_run:    "shell.run",
  alix_patch_apply:  "patch.apply",
  alix_done:         "done",
  alix_delegate:     "delegate",
  mcp_search_tools: "mcp_search_tools",
};

import type { SubagentRole } from "../config/schema.js";

export type ToolCategory = "read" | "write" | "mcp";

export type ToolPolicy = {
  allowedCategories: ToolCategory[];
  maxIterations: number;
  maxShellCommandsPerIteration: number;
  allowMcpTools: boolean;
};

// Policies keyed by role or style
const READ_ONLY_ROLES: SubagentRole[] = [
  "explorer",
  "reviewer",
  "test_investigator",
  "docs_researcher",
];

const WRITE_ROLES: SubagentRole[] = ["worker"];

export function getToolPolicy(role: SubagentRole): ToolPolicy {
  if (READ_ONLY_ROLES.includes(role)) {
    return {
      allowedCategories: ["read"],
      maxIterations: 5,
      maxShellCommandsPerIteration: 3,
      allowMcpTools: false,
    };
  }
  if (WRITE_ROLES.includes(role)) {
    return {
      allowedCategories: ["read", "write", "mcp"],
      maxIterations: 5,
      maxShellCommandsPerIteration: 5,
      allowMcpTools: true,
    };
  }
  // Default: read-only fallback
  return {
    allowedCategories: ["read"],
    maxIterations: 3,
    maxShellCommandsPerIteration: 2,
    allowMcpTools: false,
  };
}

// Built-in read-only tool names (alix_* model names)
const READ_ONLY_TOOLS = new Set([
  "alix_file_read",
  "alix_file_list",
  "alix_file_search",
  "alix_file_view",
  "alix_file_view_tree",
  "alix_git_status",
  "alix_git_diff",
  "alix_git_log",
  "alix_git_search",
  "alix_mcp_list",
  "alix_done",
  "mcp_search_tools",
]);

// Built-in write tool names
const WRITE_TOOLS = new Set([
  "alix_file_write",
  "alix_file_create",
  "alix_file_delete",
  "alix_file_exists",
  "alix_patch_preview",
  "alix_patch_apply",
]);

export function filterTools(tools: Array<{ name: string; description?: string }>, policy: ToolPolicy): Array<{ name: string; description?: string }> {
  return tools.filter((tool) => {
    // done is always allowed
    if (tool.name === "alix_done") return true;

    // mcp_search_tools only allowed when MCP tools are permitted
    if (tool.name === "mcp_search_tools") return policy.allowMcpTools;

    // MCP tools
    if (tool.name.startsWith("mcp_") || tool.name.startsWith("mcp.")) {
      if (!policy.allowMcpTools) return false;
      return true;
    }

    // Built-in tools
    if (READ_ONLY_TOOLS.has(tool.name)) {
      return policy.allowedCategories.includes("read");
    }
    if (WRITE_TOOLS.has(tool.name)) {
      return policy.allowedCategories.includes("write");
    }
    // Unknown tool: default to allowed (don't block)
    return true;
  });
}

